// --- Helper Components ---
interface Option { id: string; label: string; subLabel?: string; }

const SearchableSelect = ({ options, value, onChange, placeholder, disabled = false }: { options: Option[], value: string, onChange: (val: string) => void, placeholder: string, disabled?: boolean }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const selectedOption = options.find(o => o.id === value);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) setIsOpen(false);
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => { if (!isOpen) setSearch(''); }, [isOpen]);

  const filteredOptions = options.filter(option => 
    option.label.toLowerCase().includes(search.toLowerCase()) || 
    (option.subLabel && option.subLabel.toLowerCase().includes(search.toLowerCase()))
  );

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      if (!disabled) setIsOpen(!isOpen);
    }
    if (e.key === 'Escape') setIsOpen(false);
  };

  const handleClear = (e: React.MouseEvent) => {
    e.stopPropagation();
    onChange('');
    setIsOpen(false);
  };

  return (
    <div className="relative w-full" ref={wrapperRef}>
      <div 
        tabIndex={0} 
        onKeyDown={handleKeyDown}
        className={`w-full border border-gray-200 rounded-lg px-4 py-3 bg-white flex items-center justify-between cursor-pointer shadow-sm focus:ring-2 focus:ring-blue-500 outline-none ${disabled ? 'bg-gray-50 text-gray-400 cursor-not-allowed' : 'hover:border-blue-300'}`} 
        onClick={() => !disabled && setIsOpen(!isOpen)}
      >
        <span className={`block truncate ${!selectedOption ? 'text-gray-400' : 'text-gray-700'}`}>{selectedOption ? selectedOption.label : placeholder}</span>

        <div className="flex items-center gap-2">
            {selectedOption && !disabled && (
                <div onClick={handleClear} className="p-1 hover:bg-gray-100 rounded-full text-gray-400 hover:text-gray-600 transition-colors z-10" title="Limpar seleção">
                    <X size={14} />
                </div>
            )}
            <ChevronDown size={16} className="text-gray-400" />
        </div>
      </div>
      {isOpen && (
        <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-xl max-h-60 overflow-hidden flex flex-col animate-fade-in">
          <div className="p-2 border-b border-gray-100 bg-gray-50">
            <div className="flex items-center bg-white border border-gray-200 rounded px-2">
              <Search size={14} className="text-gray-400" />
              <input type="text" className="w-full p-2 text-sm outline-none text-gray-700" placeholder="Buscar..." value={search} onChange={(e) => setSearch(e.target.value)} autoFocus />
            </div>
          </div>
          <div className="overflow-y-auto flex-1">
            {filteredOptions.length > 0 ? (
              filteredOptions.map((option) => (
                <div key={option.id} className={`px-4 py-2 text-sm cursor-pointer hover:bg-blue-50 text-gray-700 flex flex-col ${value === option.id ? 'bg-blue-50 font-medium' : ''}`} onClick={() => { onChange(option.id); setIsOpen(false); setSearch(''); }}>
                  <span>{option.label}</span>
                  {option.subLabel && <span className="text-xs text-gray-400">{option.subLabel}</span>}
                </div>
              ))
            ) : <div className="px-4 py-3 text-sm text-gray-400 text-center">Nenhum resultado</div>}
          </div>
        </div>
      )}
    </div>
  );
};

const CurrencyInput = ({ value, onChange, disabled = false, placeholder = "R$ 0,00", className = "" }: { value: number | undefined, onChange: (val: number) => void, disabled?: boolean, placeholder?: string, className?: string }) => {
  const format = (val: number) => val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    onChange(Number(rawValue) / 100);
  };
  return (
    <input 
      type="text" 
      className={`w-full border border-gray-200 rounded-lg px-4 py-3 text-gray-700 bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all shadow-sm placeholder-gray-400 font-bold text-lg ${disabled ? 'bg-gray-50 text-gray-400' : ''} ${className}`} 
      value={value !== undefined ? format(value) : ''} 
      onChange={handleChange} 
      placeholder={placeholder} 
      disabled={disabled} 
    />
  );
};

const StatCard = ({ title, value, type }: { title: string; value: string; type?: 'neutral' | 'positive' | 'negative' }) => {
  let colorClass = 'text-gray-900';
  if (type === 'positive') colorClass = 'text-emerald-600';
  if (type === 'negative') colorClass = 'text-rose-600';
  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <p className="text-sm font-medium text-gray-500 mb-1">{title}</p>
      <h3 className={`text-2xl font-bold ${colorClass}`}>{value}</h3>
    </div>
  );
};

// --- Transaction Table Component ---
interface TransactionTableProps {
  transactions: Transaction[];
  appData: AppData;
  showBalance: boolean;
  viewType: 'PENDING' | 'PAID';
  isSelectable: boolean;
  selectedIds: Set<string>;
  onToggleSelectAll: (ids: string[]) => void;
  onToggleSelectOne: (id: string) => void;
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string, e: React.MouseEvent) => void;
  onPay: (tx: Transaction) => void;
  calculateRunningBalances: {[key: string]: number};
}

const TransactionTable = ({ 
  transactions, appData, showBalance, viewType, isSelectable, 
  selectedIds, onToggleSelectAll, onToggleSelectOne, onEdit, onDelete, onPay, calculateRunningBalances 
}: TransactionTableProps) => {

  const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' }>({ key: 'date', direction: 'desc' });
  const [filters, setFilters] = useState({
    documentNumber: '',
    category: '',
    costCenter: '',
    participant: '',
    description: '',
  });

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(25);

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const processedTransactions = useMemo(() => {
    let filtered = [...transactions];

    // Filter Logic
    if (filters.documentNumber) filtered = filtered.filter(t => t.documentNumber?.toLowerCase().includes(filters.documentNumber.toLowerCase()));
    if (filters.description) filtered = filtered.filter(t => t.description.toLowerCase().includes(filters.description.toLowerCase()));

    if (filters.category) {
       filtered = filtered.filter(t => {
         const name = appData.categories.find(c => c.id === t.categoryId)?.name || '';
         return name.toLowerCase().includes(filters.category.toLowerCase());
       });
    }
    if (filters.costCenter) {
       filtered = filtered.filter(t => {
         const name = appData.costCenters.find(c => c.id === t.costCenterId)?.name || '';
         return name.toLowerCase().includes(filters.costCenter.toLowerCase());
       });
    }
    if (filters.participant) {
       filtered = filtered.filter(t => {
         const name = appData.participants.find(c => c.id === t.participantId)?.name || '';
         return name.toLowerCase().includes(filters.participant.toLowerCase());
       });
    }

    // Sort Logic
    filtered.sort((a, b) => {
      let valA: any = a[sortConfig.key as keyof Transaction];
      let valB: any = b[sortConfig.key as keyof Transaction];

      // Handle relational sorting (by name instead of ID)
      if (sortConfig.key === 'categoryId') {
        valA = appData.categories.find(c => c.id === a.categoryId)?.name || '';
        valB = appData.categories.find(c => c.id === b.categoryId)?.name || '';
      }
      if (sortConfig.key === 'costCenterId') {
        valA = appData.costCenters.find(c => c.id === a.costCenterId)?.name || '';
        valB = appData.costCenters.find(c => c.id === b.costCenterId)?.name || '';
      }
      if (sortConfig.key === 'participantId') {
        valA = appData.participants.find(c => c.id === a.participantId)?.name || '';
        valB = appData.participants.find(c => c.id === b.participantId)?.name || '';
      }
      if (sortConfig.key === 'bankId') {
        valA = appData.banks.find(c => c.id === a.bankId)?.name || '';
        valB = appData.banks.find(c => c.id === b.bankId)?.name || '';
      }

      // Handle nulls
      if (valA === undefined || valA === null) valA = '';
      if (valB === undefined || valB === null) valB = '';

      if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });

    return filtered;
  }, [transactions, filters, sortConfig, appData]);

  // Reset page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filters, transactions.length, sortConfig]);

  // Pagination Calculations
  const totalPages = Math.ceil(processedTransactions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const paginatedTransactions = processedTransactions.slice(startIndex, startIndex + itemsPerPage);

  const SortIcon = ({ colKey }: { colKey: string }) => {
    if (sortConfig.key !== colKey) return <ArrowUpDown size={12} className="text-gray-300 ml-1" />;
    return sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-blue-500 ml-1" /> : <ArrowDown size={12} className="text-blue-500 ml-1" />;
  };

  const FilterInput = ({ value, onChange, placeholder }: { value: string, onChange: (val: string) => void, placeholder: string }) => (
    <div className="relative">
      <input 
        type="text" 
        value={value} 
        onChange={e => onChange(e.target.value)} 
        placeholder={placeholder}
        className="w-full text-[10px] p-1 border border-gray-200 rounded focus:ring-1 focus:ring-blue-500 outline-none bg-gray-50"
      />
      {value && <button onClick={() => onChange('')} className="absolute right-1 top-1.5 text-gray-400 hover:text-gray-600"><X size={10}/></button>}
    </div>
  );

  return (
    <div className="flex flex-col gap-2">
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-x-auto">
        <table className="w-full text-left text-gray-600 text-xs">
          <thead className="bg-gray-50 text-gray-900 font-semibold">
              {/* Header Row with Sort */}
              <tr>
                {isSelectable && (
                  <th className="p-2 w-8" rowSpan={2}>
                    <input 
                      type="checkbox" 
                      checked={processedTransactions.length > 0 && selectedIds.size === processedTransactions.length} 
                      onChange={() => onToggleSelectAll(processedTransactions.map(t => t.id))} 
                      className="rounded border-gray-300" 
                    />
                  </th>
                )}
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('date')}>
                  <div className="flex items-center">Data <SortIcon colKey="date" /></div>
                </th>
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('documentNumber')}>
                  <div className="flex items-center">Nº Doc <SortIcon colKey="documentNumber" /></div>
                </th>
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('bankId')}>
                  <div className="flex items-center">Banco <SortIcon colKey="bankId" /></div>
                </th>
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('categoryId')}>
                  <div className="flex items-center">Categoria <SortIcon colKey="categoryId" /></div>
                </th>
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('costCenterId')}>
                  <div className="flex items-center">C. Custo <SortIcon colKey="costCenterId" /></div>
                </th>
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('participantId')}>
                  <div className="flex items-center">Participante <SortIcon colKey="participantId" /></div>
                </th>
                <th className="p-2 whitespace-nowrap cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => handleSort('description')}>
                  <div className="flex items-center">Descrição <SortIcon colKey="description" /></div>
                </th>
                <th className="p-2 text-center whitespace-nowrap">Parc.</th>
                <th className="p-2 text-right whitespace-nowrap cursor-pointer hover:bg-gray-100" onClick={() => handleSort('amount')}>
                  <div className="flex items-center justify-end">Débito <SortIcon colKey="amount" /></div>
                </th>
                <th className="p-2 text-right whitespace-nowrap cursor-pointer hover:bg-gray-100" onClick={() => handleSort('amount')}>
                  <div className="flex items-center justify-end">Crédito <SortIcon colKey="amount" /></div>
                </th>
                {showBalance && <th className="p-2 text-right whitespace-nowrap">Saldo</th>}
                <th className="p-2 text-center whitespace-nowrap">Status</th>
                <th className="p-2 text-right whitespace-nowrap">Ações</th>
              </tr>
              {/* Filter Row */}
              <tr className="border-b border-gray-200">
                 <th className="p-1"></th> 
                 <th className="p-1"><FilterInput value={filters.documentNumber} onChange={v => setFilters({...filters, documentNumber: v})} placeholder="Filtrar Doc..." /></th>
                 <th className="p-1"></th> {/* Banco filter is global usually, or could be here */}
                 <th className="p-1"><FilterInput value={filters.category} onChange={v => setFilters({...filters, category: v})} placeholder="Filtrar Categoria..." /></th>
                 <th className="p-1"><FilterInput value={filters.costCenter} onChange={v => setFilters({...filters, costCenter: v})} placeholder="Filtrar Centro..." /></th>
                 <th className="p-1"><FilterInput value={filters.participant} onChange={v => setFilters({...filters, participant: v})} placeholder="Filtrar Part..." /></th>
                 <th className="p-1"><FilterInput value={filters.description} onChange={v => setFilters({...filters, description: v})} placeholder="Filtrar Desc..." /></th>
                 <th colSpan={showBalance ? 6 : 5} className="p-1"></th>
              </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
              {paginatedTransactions.map(tx => (
                <tr key={tx.id} className={`hover:bg-gray-50 cursor-pointer ${selectedIds.has(tx.id) ? 'bg-blue-50' : ''}`} onClick={() => { onEdit(tx); }}>
                    {isSelectable && <td className="p-2" onClick={e => e.stopPropagation()}><input type="checkbox" checked={selectedIds.has(tx.id)} onChange={() => onToggleSelectOne(tx.id)} className="rounded border-gray-300" /></td>}
                    {/* FIXED: Display date directly from string to avoid timezone shifts */}
                    <td className="p-2 whitespace-nowrap">{tx.date ? tx.date.split('-').reverse().join('/') : '-'}</td>
                    <td className="p-2 whitespace-nowrap text-gray-500 text-xs">{tx.documentNumber || '-'}</td>
                    <td className="p-2 whitespace-nowrap">{appData.banks.find(b => b.id === tx.bankId)?.name}</td>
                    <td className="p-2 whitespace-nowrap text-gray-500">{appData.categories.find(c => c.id === tx.categoryId)?.name || '-'}</td>
                    <td className="p-2 whitespace-nowrap text-gray-500">{appData.costCenters.find(c => c.id === tx.costCenterId)?.name || '-'}</td>
                    <td className="p-2 whitespace-nowrap text-gray-500">{appData.participants.find(p => p.id === tx.participantId)?.name || '-'}</td>
                    <td className="p-2 font-medium text-gray-900">{tx.description}</td>
                    <td className="p-2 text-center">{tx.installmentNumber ? `${tx.installmentNumber}/${tx.installmentTotal}` : '-'}</td>
                    <td className="p-2 text-right text-red-600">{tx.type === 'EXPENSE' ? `${tx.amount.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : '-'}</td>
                    <td className="p-2 text-right text-green-600">{tx.type === 'INCOME' ? `${tx.amount.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : '-'}</td>
                    {showBalance && <td className="p-2 text-right font-medium text-gray-700">{calculateRunningBalances[tx.id]?.toLocaleString('pt-BR', {minimumFractionDigits: 2})}</td>}
                    <td className="p-2 text-center"><span className={`px-2 py-0.5 rounded-full text-[10px] ${tx.status === 'PAID' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>{tx.status === 'PAID' ? 'Pago' : 'Pendente'}</span></td>
                    <td className="p-2 text-right whitespace-nowrap">
                      {viewType === 'PENDING' && <button onClick={(e) => { e.stopPropagation(); onPay(tx); }} className="text-green-600 hover:text-green-800 p-1 mr-2" title="Baixar"><CheckCircle size={14}/></button>}
                      <button onClick={(e) => { e.stopPropagation(); onEdit(tx); }} className="text-blue-500 hover:text-blue-700 p-1 mr-2"><Pencil size={14}/></button>
                      <button onClick={(e) => onDelete(tx.id, e)} className="text-red-500 hover:text-red-700 p-1"><Trash2 size={14}/></button>
                    </td>
                </tr>
              ))}
          </tbody>
        </table>
        {processedTransactions.length === 0 && <div className="p-8 text-center text-gray-400 text-sm">Nenhuma transação encontrada.</div>}
      </div>

      {/* Pagination Controls */}
      {processedTransactions.length > 0 && (
        <div className="flex justify-between items-center bg-white p-2 rounded-lg shadow-sm border border-gray-100 text-xs text-gray-600">
          <div className="flex items-center gap-2">
            <span>Itens por página:</span>
            <select 
              value={itemsPerPage} 
              onChange={(e) => setItemsPerPage(Number(e.target.value))}
              className="border border-gray-200 rounded p-1 bg-gray-50 focus:ring-1 focus:ring-blue-500 outline-none"
            >
              <option value={10}>10</option>
              <option value={25}>25</option>
              <option value={50}>50</option>
              <option value={100}>100</option>
            </select>
          </div>

          <div className="flex items-center gap-2">
            <span>{startIndex + 1}-{Math.min(startIndex + itemsPerPage, processedTransactions.length)} de {processedTransactions.length}</span>
            <div className="flex items-center border border-gray-200 rounded overflow-hidden">
               <button onClick={() => setCurrentPage(1)} disabled={currentPage === 1} className="p-1 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"><ChevronsLeft size={16} /></button>
               <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="p-1 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"><ChevronLeft size={16} /></button>
               <span className="px-3 py-1 font-medium bg-gray-50">{currentPage}</span>
               <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="p-1 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"><ChevronRight size={16} /></button>
               <button onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages} className="p-1 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"><ChevronsRight size={16} /></button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

