  const [selectedWalletFilter, setSelectedWalletFilter] = useState<string>(''); // Wallet Selection
  const [selectedBankFilter, setSelectedBankFilter] = useState<string>(''); // View specific filter
  const [dateFilter, setDateFilter] = useState({ start: '', end: '' }); // Date Filter

  const [showNotifications, setShowNotifications] = useState(false);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [configForm, setConfigForm] = useState({ url: localStorage.getItem(LS_KEYS.URL) || '', key: localStorage.getItem(LS_KEYS.KEY) || '' });
  const [copiedSql, setCopiedSql] = useState(false);

  // Forms
  const [txForm, setTxForm] = useState<Partial<Transaction>>({ type: 'EXPENSE', status: 'PENDING', date: new Date().toISOString().split('T')[0] });
  const [isRecurring, setIsRecurring] = useState(false);
  const [installmentsCount, setInstallmentsCount] = useState(2);
  const [transferForm, setTransferForm] = useState({ amount: 0, fromBankId: '', toBankId: '', date: new Date().toISOString().split('T')[0], description: 'Transferência', participantId: '', categoryId: '' });
  const [genericForm, setGenericForm] = useState<any>({});

  const loadData = async () => {
    try {
      setLoading(true);
      if (!isSupabaseConfigured()) { setIsDemoMode(true); setDbError(false); } 
      else { setIsDemoMode(false); const isHealthy = await dataService.checkDatabaseHealth(); setDbError(!isHealthy); }
      const appData = await dataService.getInitialData();
      setData(appData);
    } catch (error) { console.error(error); setIsDemoMode(true); } finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  // Força seleção da primeira carteira se nenhuma estiver selecionada
  useEffect(() => {
    if (data.wallets.length > 0 && !selectedWalletFilter) {
      setSelectedWalletFilter(data.wallets[0].id);
    }
  }, [data.wallets, selectedWalletFilter]);

  // Limpa seleção ao mudar de view
  useEffect(() => {
    setSelectedTxIds(new Set());
  }, [currentView]);

  // --- Derived Data (Global Filtering by Wallet) ---
  const filteredBanks = useMemo(() => {
    if (!selectedWalletFilter) return data.banks;
    return data.banks.filter(b => b.walletId === selectedWalletFilter);
  }, [data.banks, selectedWalletFilter]);

  const filteredTransactionsGlobal = useMemo(() => {
    // Only show transactions belonging to the visible banks
    return data.transactions.filter(t => filteredBanks.some(b => b.id === t.bankId));
  }, [data.transactions, filteredBanks]);

  const transactionsByDateRange = useMemo(() => {
    return filteredTransactionsGlobal.filter(t => {
      if (dateFilter.start && t.date < dateFilter.start) return false;
      if (dateFilter.end && t.date > dateFilter.end) return false;
      return true;
    });
  }, [filteredTransactionsGlobal, dateFilter]);

  // Derived for Views
  const totalBalance = useMemo(() => filteredBanks.reduce((acc, b) => acc + b.balance, 0), [filteredBanks]);

  const pendingPayables = useMemo(() => filteredTransactionsGlobal
      .filter(t => t.type === 'EXPENSE' && t.status === 'PENDING')
      .reduce((acc, t) => acc + t.amount, 0), [filteredTransactionsGlobal]);

  const pendingReceivables = useMemo(() => filteredTransactionsGlobal
      .filter(t => t.type === 'INCOME' && t.status === 'PENDING')
      .reduce((acc, t) => acc + t.amount, 0), [filteredTransactionsGlobal]);

  const notifications = useMemo(() => {
    const today = new Date(); today.setHours(0,0,0,0);
    const threeDays = new Date(today); threeDays.setDate(today.getDate() + 3);
    return filteredTransactionsGlobal.filter(t => t.type === 'EXPENSE' && t.status !== 'PAID' && new Date(t.date) <= threeDays).sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [filteredTransactionsGlobal]);

  const calculateRunningBalances = useMemo(() => {
    if (!selectedBankFilter) return {};

    // Considera apenas transações pagas para o saldo
    const bankTxs = filteredTransactionsGlobal
      .filter(t => t.bankId === selectedBankFilter && t.status === 'PAID')
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    const currentBalance = filteredBanks.find(b => b.id === selectedBankFilter)?.balance || 0;

    const balances: {[key: string]: number} = {};
    let running = currentBalance;

    const sortedDesc = [...bankTxs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    for (const tx of sortedDesc) {
      balances[tx.id] = running;
      if (tx.type === 'INCOME' && tx.status === 'PAID') running -= tx.amount;
      else if (tx.type === 'EXPENSE' && tx.status === 'PAID') running += tx.amount;
    }
    return balances;
  }, [filteredTransactionsGlobal, selectedBankFilter, filteredBanks]);

  // --- Handlers ---
  const handleCreateTransaction = async () => {
    // Campos Obrigatórios
    if (!txForm.amount || txForm.amount <= 0) { alert('Informe o Valor.'); return; }
    if (!txForm.bankId) { alert('Selecione um Banco.'); return; }
    if (!txForm.categoryId) { alert('Selecione uma Categoria.'); return; }
    if (!txForm.participantId) { alert('Selecione um Participante.'); return; }
    if (!txForm.status) { alert('Selecione o Status (Pendente/Pago).'); return; }
    if (!txForm.date) { alert('Selecione a Data.'); return; }

    // Se a descrição estiver vazia, vai como string vazia (opcional)
    const descriptionToSend = txForm.description?.trim() || '';

    try {
      setLoading(true);
      const txPayload = { ...txForm, description: descriptionToSend, amount: Number(txForm.amount), bankId: txForm.bankId!, type: txForm.type as any };

      if (editingId) {
        let appliedToAll = false;
        if (txForm.installmentTotal && txForm.installmentTotal > 1) {
           if (window.confirm("Deseja aplicar as alterações para TODAS as parcelas PENDENTES desta série?")) {
              await dataService.updateInstallmentBatch(editingId, {
                  amount: Number(txForm.amount), bankId: txForm.bankId!, categoryId: txForm.categoryId,
                  participantId: txForm.participantId, costCenterId: txForm.costCenterId, type: txForm.type as TransactionType
              });
              appliedToAll = true;
           }
        }
        if (!appliedToAll) await dataService.updateTransaction(editingId, txPayload as any);
      } else {
        if (isRecurring && installmentsCount > 1) {
          await dataService.createInstallments({ ...txPayload, history: [] } as any, Number(installmentsCount));
        } else {
          await dataService.createTransaction({ ...txPayload, installmentNumber: 1, installmentTotal: 1, history: [] } as any);
        }
      }
      await loadData(); setIsTxModalOpen(false); setEditingId(null);
      setTxForm({ type: 'EXPENSE', status: 'PENDING', date: new Date().toISOString().split('T')[0], description: '', amount: 0, bankId: '', categoryId: '', participantId: '', costCenterId: '', documentNumber: '' });
      setIsRecurring(false); setInstallmentsCount(2);
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const confirmDelete = (type: string, id: string, e?: React.MouseEvent) => {
      if (e) {
          e.stopPropagation();
          e.preventDefault();
      }
      setConfirmModal({
          isOpen: true,
          title: 'Excluir Item',
          message: 'Tem certeza que deseja excluir este item? Esta ação não pode ser desfeita.',
          onConfirm: () => performDelete(type, id)
      });
  };

  const performDelete = async (type: string, id: string) => {
    try {
      setLoading(true);
      setConfirmModal(prev => ({ ...prev, isOpen: false })); // Close confirm modal

      let table: any = '';
      if (type === 'WALLET') table = 'wallets';
      if (type === 'BANK') table = 'banks';
      if (type === 'CATEGORY') table = 'categories';
      if (type === 'COST') table = 'cost_centers';
      if (type === 'PARTICIPANT') table = 'participants';
      if (type === 'TRANSACTION') table = 'transactions';

      await dataService.deleteItem(table, id);

      if (editingId === id) {
        setIsTxModalOpen(false);
        setGenericModalOpen(false);
        setEditingId(null);
      }

      await loadData();
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const handleBulkDelete = async () => {
    if (selectedTxIds.size === 0) return;

    setConfirmModal({
      isOpen: true,
      title: 'Excluir Transações',
      message: `Tem certeza que deseja excluir ${selectedTxIds.size} transações selecionadas?`,
      onConfirm: async () => {
        try {
          setLoading(true);
          setConfirmModal(prev => ({...prev, isOpen: false}));
          await dataService.deleteTransactionsBatch(Array.from(selectedTxIds));
          setSelectedTxIds(new Set());
          await loadData();
        } catch(e: any) { alert(e.message); } finally { setLoading(false); }
      }
    });
  };

  const handleTransfer = async () => {
    if (!transferForm.fromBankId || !transferForm.toBankId || !transferForm.amount || !transferForm.participantId || !transferForm.categoryId) {
      alert("Preencha todos os campos obrigatórios (Origem, Destino, Valor, Participante e Categoria).");
      return;
    }
    if (transferForm.fromBankId === transferForm.toBankId) {
      alert("A conta de origem e destino não podem ser a mesma.");
      return;
    }

    try {
      setLoading(true);
      await dataService.createTransfer(Number(transferForm.amount), transferForm.date, transferForm.fromBankId, transferForm.toBankId, transferForm.description, transferForm.participantId || undefined, transferForm.categoryId);
      await loadData(); setIsTransferModalOpen(false);
      setTransferForm({ ...transferForm, amount: 0, fromBankId: '', toBankId: '', description: 'Transferência', participantId: '', categoryId: '' });
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const markAsPaid = async (tx: Transaction) => {
    try { setLoading(true); await dataService.markAsPaid(tx); await loadData(); } 
    catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const openGenericModal = (type: 'WALLET'|'BANK'|'CATEGORY'|'COST'|'PARTICIPANT', item?: any) => {
    setGenericModalType(type);
    if (item) { setEditingId(item.id); setGenericForm(item); } 
    else { setEditingId(null); setGenericForm(type === 'BANK' && selectedWalletFilter ? {walletId: selectedWalletFilter} : {}); }
    setGenericModalOpen(true);
  };

  const handleGenericSave = async () => {
    if (!genericModalType) return;
    try {
      setLoading(true);
      if (editingId) {
        if (genericModalType === 'WALLET') await dataService.updateWallet(editingId, genericForm);
        if (genericModalType === 'BANK') await dataService.updateBank(editingId, genericForm);
        if (genericModalType === 'CATEGORY') await dataService.updateCategory(editingId, { ...genericForm, type: 'EXPENSE' }); // Default type
        if (genericModalType === 'COST') await dataService.updateCostCenter(editingId, { ...genericForm, code: '' }); // No code
        if (genericModalType === 'PARTICIPANT') await dataService.updateParticipant(editingId, { ...genericForm, type: 'OTHER' }); // Default type
      } else {
        if (genericModalType === 'WALLET') await dataService.createWallet(genericForm);
        if (genericModalType === 'BANK') await dataService.createBank({ ...genericForm, balance: Number(genericForm.balance || 0), color: BANK_COLORS[Math.floor(Math.random() * BANK_COLORS.length)] });
        if (genericModalType === 'CATEGORY') await dataService.createCategory({ ...genericForm, type: 'EXPENSE' });
        if (genericModalType === 'COST') await dataService.createCostCenter({ ...genericForm, code: '' });
        if (genericModalType === 'PARTICIPANT') await dataService.createParticipant({ ...genericForm, type: 'OTHER' });
      }
      await loadData(); setGenericModalOpen(false); setGenericForm({}); setEditingId(null);
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const handleBulkImport = async () => {
    if (!importText.trim()) return;
    const lines: string[] = importText.split('\n').map(l => l.trim()).filter(l => l.length > 0);

    try {
      setLoading(true);

      if (importType === 'TRANSACTION') {
         await processTransactionImport(lines);
         await loadData();
         setIsImportModalOpen(false);
         alert("Transações importadas com sucesso!");
         return;
      }

      // Simple Import (Name only)
      const uniqueLines = Array.from(new Set(lines));
      for (const name of uniqueLines) {
        const targetWalletId = importWalletId || selectedWalletFilter;
        if (importType === 'BANK') {
           const existsInWallet = data.banks.some(b => b.name.toLowerCase() === name.toLowerCase() && (b.walletId === targetWalletId || (!b.walletId && !targetWalletId)));
           if (!existsInWallet) await dataService.createBank({ name, balance: 0, color: BANK_COLORS[Math.floor(Math.random() * BANK_COLORS.length)], walletId: targetWalletId });
        } else if (importType === 'CATEGORY' && !data.categories.some(c => c.name.toLowerCase() === name.toLowerCase())) {
           await dataService.createCategory({ name, type: 'EXPENSE' });
        } else if (importType === 'PARTICIPANT' && !data.participants.some(p => p.name.toLowerCase() === name.toLowerCase())) {
           await dataService.createParticipant({ name, type: 'OTHER' });
        }
      }
      await loadData(); setIsImportModalOpen(false); alert(`${uniqueLines.length} linhas processadas!`);
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const processTransactionImport = async (lines: string[]) => {
      // 1. Ensure "Renzo Braz" wallet exists
      let targetWalletId = '';
      const targetWalletName = "Renzo Braz";
      let wallet = data.wallets.find(w => w.name.toLowerCase() === targetWalletName.toLowerCase());

      if (!wallet) {
          // Create Renzo Braz wallet
          wallet = await dataService.createWallet({ name: targetWalletName });
      }
      targetWalletId = wallet.id;

      // Caches for ID lookups
      const bankCache = new Map<string, string>(data.banks.filter(b => b.walletId === targetWalletId).map(b => [b.name.toLowerCase(), b.id]) as [string, string][]);
      const catCache = new Map<string, string>(data.categories.map(c => [c.name.toLowerCase(), c.id]) as [string, string][]);
      const costCache = new Map<string, string>(data.costCenters.map(c => [c.name.toLowerCase(), c.id]) as [string, string][]);
      const partCache = new Map<string, string>(data.participants.map(p => [p.name.toLowerCase(), p.id]) as [string, string][]);

      for (const line of lines) {
         if (!line.trim()) continue;
         const cols = line.split('\t').map(c => c.trim());

         // Headers skip check
         if (cols[0].toLowerCase().includes('data') && cols[2].toLowerCase().includes('origem')) continue;

         const dateStr = cols[0] || '';
         const docStr = cols[1] || '';
         const bankName = cols[2] || '';
         const catName = cols[3] || '';
         const ccName = cols[4] || '';
         const partName = cols[5] || '';
         const descStr = cols[6] || '';
         const instNumStr = cols[7] || '';
         const instTotalStr = cols[8] || '';
         const debitStr = cols[9] || '';
         const creditStr = cols[10] || '';
         const statusStr = cols[11] || '';

         // Validate Date
         if (!dateStr || dateStr.length < 8) continue;
         const [d, m, y] = dateStr.split('/');
         const fullYear = y.length === 2 ? `20${y}` : y;
         const isoDate = `${fullYear}-${m}-${d}`;
         if (isoDate.length !== 10) continue;

         // Resolve Bank
         if (bankName) {
             if (!bankCache.has(bankName.toLowerCase())) {
                 const newBank = await dataService.createBank({ name: bankName, balance: 0, color: 'bg-gray-500', walletId: targetWalletId });
                 bankCache.set(bankName.toLowerCase(), newBank.id);
             }
         }

         const bankId = bankCache.get(bankName.toLowerCase());
         if (!bankId) continue;

         // Resolve Category
         if (catName && !catCache.has(catName.toLowerCase())) {
             const newCat = await dataService.createCategory({ name: catName, type: 'EXPENSE' });
             catCache.set(catName.toLowerCase(), newCat.id);
         }
         const categoryId = catName ? catCache.get(catName.toLowerCase()) : undefined;

         // Resolve Cost Center
         if (ccName && !costCache.has(ccName.toLowerCase())) {
             const newCC = await dataService.createCostCenter({ name: ccName, code: '' });
             costCache.set(ccName.toLowerCase(), newCC.id);
         }
         const costCenterId = ccName ? costCache.get(ccName.toLowerCase()) : undefined;

         // Resolve Participant
         if (partName && !partCache.has(partName.toLowerCase())) {
             const newPart = await dataService.createParticipant({ name: partName, type: 'OTHER' });
             partCache.set(partName.toLowerCase(), newPart.id);
         }
         const participantId = partName ? partCache.get(partName.toLowerCase()) : undefined;

         // Amount & Type
         const debitVal = debitStr ? parseFloat(debitStr.replace(/\./g, '').replace(',', '.')) : 0;
         const creditVal = creditStr ? parseFloat(creditStr.replace(/\./g, '').replace(',', '.')) : 0;

         let amount = 0;
         let type: TransactionType = 'EXPENSE';

         if (debitVal > 0) {
             amount = debitVal;
             type = 'EXPENSE';
         } else if (creditVal > 0) {
             amount = creditVal;
             type = 'INCOME';
         } else {
            // Skip rows with no value
            continue;
         }

         let status: TransactionStatus = 'PENDING';
         if (statusStr) {
            status = (statusStr.toLowerCase().includes('pago')) ? 'PAID' : 'PENDING';
         } else {
            // Se a data é passada (anterior a hoje), assume que já foi pago (Movimentação Histórica)
            const today = new Date().toISOString().split('T')[0];
            status = isoDate < today ? 'PAID' : 'PENDING';
         }

         // Installment logic
         const installmentNumber = instNumStr ? parseInt(instNumStr) : undefined;
         const installmentTotal = instTotalStr ? parseInt(instTotalStr) : undefined;

         // Description (Default to empty if missing)
         const description = descStr || '';

         await dataService.createTransaction({
             description,
             amount,
             date: isoDate,
             type,
             status,
             bankId,
             categoryId,
             costCenterId,
             participantId,
             documentNumber: docStr,
             history: [],
             installmentNumber: installmentNumber || 1,
             installmentTotal: installmentTotal || 1
         });
      }
  };

  const openImportModal = (type: 'BANK' | 'CATEGORY' | 'PARTICIPANT' | 'TRANSACTION') => {
    setImportType(type);
    if (type === 'BANK') { setImportText(DEFAULT_BANK_IMPORT_LIST); setImportWalletId(selectedWalletFilter); } 
    else { setImportText(''); setImportWalletId(''); }
    setIsImportModalOpen(true);
  };

  const handleAskAI = async () => { setAiLoading(true); const response = await analyzeFinancials(data, aiQuery); setAiResponse(response); setAiLoading(false); };
  const handleSaveConfig = async () => { if (!configForm.url || !configForm.key) return alert("Preencha URL e Key"); saveSupabaseConfig(configForm.url, configForm.key); await new Promise(r => setTimeout(r, 500)); await loadData(); };
  const handleDisconnect = async () => { disconnectSupabase(); setIsDemoMode(true); await loadData(); };
  const copySqlToClipboard = () => { navigator.clipboard.writeText(DB_SCHEMA_SQL); setCopiedSql(true); setTimeout(() => setCopiedSql(false), 2000); };
  const goToTransactionMovement = (tx: Transaction) => { setSelectedBankFilter(tx.bankId); setCurrentView('PAYABLES'); };

  const openTransferModal = () => {
      // Logic to find "Transferência Mesma Titularidade"
      const transferCat = data.categories.find(c => 
          c.name.toLowerCase().includes("transferência mesma titularidade") || 
          c.name.toLowerCase().includes("transferencia mesma titularidade")
      );

      setTransferForm({ 
          amount: 0, 
          fromBankId: '', 
          toBankId: '', 
          date: new Date().toISOString().split('T')[0], 
          description: 'Transferência', 
          participantId: '',
          categoryId: transferCat ? transferCat.id : ''
      }); 
      setIsTransferModalOpen(true);
  };

  // --- Handlers for Table Selections ---
  const toggleSelectAll = (ids: string[]) => {
      if (selectedTxIds.size === ids.length) {
         setSelectedTxIds(new Set());
      } else {
         setSelectedTxIds(new Set(ids));
      }
   };

  const toggleSelectOne = (id: string) => {
      const newSet = new Set(selectedTxIds);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setSelectedTxIds(newSet);
   };

  // --- Renderers ---
  const renderDashboard = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard title="Saldo Total" value={`R$ ${totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} type={totalBalance >= 0 ? 'positive' : 'negative'} />
        <StatCard title="A Pagar (Pendente)" value={`R$ ${pendingPayables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} type="negative" />
        <StatCard title="A Receber (Pendente)" value={`R$ ${pendingReceivables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} type="positive" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-96">
          <h3 className="text-lg font-bold text-gray-800 mb-4">Receitas vs Despesas (Por Categoria)</h3>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data.categories.map(c => ({ name: c.name, value: filteredTransactionsGlobal.filter(t => t.categoryId === c.id && t.status === 'PAID').reduce((a, t) => a + t.amount, 0), type: c.type })).filter(d => d.value > 0)}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
