                      <div><p className="font-medium text-gray-800">{tx.description}</p><p className="text-xs text-gray-500">{new Date(tx.date).toLocaleDateString('pt-BR')}</p></div>
                   </div>
                   <div className="text-right"><p className={`font-bold ${tx.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>{tx.type === 'EXPENSE' ? '-' : '+'} R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p><span className={`text-[10px] px-2 py-0.5 rounded-full ${tx.status === 'PAID' ? 'bg-gray-100 text-gray-600' : 'bg-yellow-100 text-yellow-700'}`}>{tx.status === 'PAID' ? 'Pago' : 'Pendente'}</span></div>
                </div>
              ))}
           </div>
