  );

  const renderGenericList = (title: string, items: any[], type: 'WALLET'|'BANK'|'CATEGORY'|'COST'|'PARTICIPANT', cols: {key: string, label: string}[]) => (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100">
      <div className="p-6 border-b border-gray-100 flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">{title}</h2>
        <div className="flex gap-2">
          {['BANK', 'CATEGORY', 'PARTICIPANT'].includes(type) && <button onClick={() => openImportModal(type as any)} className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 rounded-lg hover:bg-gray-50 text-sm font-medium"><Upload size={16} /> Importar</button>}
          <button onClick={() => openGenericModal(type)} className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-white rounded-lg hover:bg-gray-800 text-sm font-medium"><Plus size={16} /> Adicionar</button>
        </div>
      </div>
      <table className="w-full text-left text-sm text-gray-600">
         <thead className="bg-gray-50 text-gray-900 font-semibold border-b border-gray-200"><tr>{cols.map(c => <th key={c.key} className="px-6 py-4">{c.label}</th>)}<th className="px-6 py-4 text-right">Ações</th></tr></thead>
         <tbody className="divide-y divide-gray-100">
            {items.map(item => (
              <tr key={item.id} className="hover:bg-gray-50 group">
                {cols.map(c => <td key={c.key} className="px-6 py-4">{c.key === 'balance' ? `R$ ${item[c.key]?.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : c.key === 'initialDate' ? (item[c.key] ? new Date(item[c.key]).toLocaleDateString('pt-BR') : '-') : item[c.key]}</td>)}
                <td className="px-6 py-4 text-right">
                   <div className="flex justify-end gap-2">
                      <button onClick={() => openGenericModal(type, item)} className="text-blue-400 hover:text-blue-600"><Pencil size={16} /></button>
                      <button onClick={(e) => confirmDelete(type, item.id, e)} className="text-red-400 hover:text-red-600"><Trash2 size={16} /></button>
                   </div>
                </td>
              </tr>
            ))}
         </tbody>
      </table>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-[#f3f4f6]">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 fixed inset-y-0 z-20 hidden md:flex flex-col">
         <div className="p-6 border-b border-gray-100">
            <div className="flex items-center gap-2 mb-4">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">F</div>
              <span className="text-xl font-bold text-gray-900">FinControl Pro</span>
            </div>

            {/* Wallet Selector */}
            <div className="relative">
               <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1 block">Carteira (Contexto)</label>
               <select 
                 className="w-full bg-gray-50 border border-gray-200 text-gray-800 text-sm rounded-lg p-2.5 focus:ring-blue-500 focus:border-blue-500 outline-none cursor-pointer font-medium"
                 value={selectedWalletFilter}
                 onChange={(e) => { setSelectedWalletFilter(e.target.value); setCurrentView('DASHBOARD'); }}
               >
                 {data.wallets.length === 0 && <option value="">Criar Carteira...</option>}
                 {data.wallets.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
               </select>
            </div>
         </div>

         <nav className="p-4 space-y-1 flex-1 overflow-y-auto">
            {MENU_ITEMS.map(item => (
              <button key={item.id} onClick={() => setCurrentView(item.id as ViewName)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${currentView === item.id ? 'bg-blue-50 text-blue-700' : 'text-gray-600 hover:bg-gray-50'}`}>
                 {item.icon} {item.label}
              </button>
            ))}
         </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-2 md:p-4 overflow-x-hidden bg-[#f3f4f6]">
         <div className="flex justify-between items-center mb-6">
            <div>
               <h1 className="text-2xl font-bold text-gray-900">{MENU_ITEMS.find(m => m.id === currentView)?.label}</h1>
               <p className="text-gray-500 text-sm">{selectedWalletFilter ? `Contexto: ${data.wallets.find(w => w.id === selectedWalletFilter)?.name}` : 'Visualizando todas as carteiras'}</p>
            </div>
            <div className="flex items-center gap-4">
                <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium border shadow-sm ${!isDemoMode ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-gray-50 text-gray-500 border-gray-200'}`}>
                   {!isDemoMode ? <Cloud size={16} /> : <CloudOff size={16} />} <span className="hidden sm:inline">{!isDemoMode ? 'Cloud' : 'Local'}</span>
                </div>
                <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 bg-white rounded-full border border-gray-200 relative"><Bell size={20} />{notifications.length > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full text-[10px] text-white flex items-center justify-center translate-x-1 -translate-y-1">{notifications.length}</span>}</button>
            </div>
         </div>

         {/* Notifications Dropdown */}
         {showNotifications && (
            <div className="absolute right-8 mt-[-10px] w-80 bg-white rounded-xl shadow-2xl border border-gray-100 z-50 overflow-hidden">
              <div className="p-3 bg-gray-50 flex justify-between"><h4 className="font-semibold text-gray-700 text-sm">Contas Próximas</h4><button onClick={() => setShowNotifications(false)}><X size={14}/></button></div>
              <div className="max-h-64 overflow-y-auto">
                {notifications.length > 0 ? notifications.map(tx => (
                   <div key={tx.id} className="p-3 border-b border-gray-50 hover:bg-gray-50 flex gap-3 cursor-pointer" onClick={() => goToTransactionMovement(tx)}>
                      <AlertTriangle size={14} className="text-orange-500 mt-1"/>
                      <div><p className="text-sm font-medium">{tx.description}</p><p className="text-xs text-gray-500">{new Date(tx.date).toLocaleDateString('pt-BR')}</p></div>
                   </div>
                )) : <div className="p-4 text-center text-gray-400 text-sm">Tudo em dia!</div>}
              </div>
            </div>
         )}

         {dbError && !isDemoMode && currentView !== 'SETTINGS' && <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl text-red-800 font-medium cursor-pointer" onClick={() => setCurrentView('SETTINGS')}>Banco de Dados Desatualizado. Clique para corrigir.</div>}

         {currentView === 'DASHBOARD' && renderDashboard()}

         {currentView === 'ACCOUNTS_PAYABLE' && 
            <div className="space-y-6">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="bg-red-50 p-6 rounded-xl border border-red-100"><h2 className="text-lg font-bold text-red-800">Total a Pagar</h2><h3 className="text-2xl font-bold text-red-700">R$ {pendingPayables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3></div>
                  <div className="bg-green-50 p-6 rounded-xl border border-green-100"><h2 className="text-lg font-bold text-green-800">Total a Receber</h2><h3 className="text-2xl font-bold text-green-700">R$ {pendingReceivables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3></div>
               </div>

               {/* Controles para Contas a Pagar/Receber */}
               <div className="flex gap-4 mb-4 bg-white p-4 rounded-xl shadow-sm items-center">
                  <div className="w-64"><SearchableSelect options={[{id: '', label: 'Todos os Bancos'}, ...filteredBanks.map(b => ({id: b.id, label: b.name}))]} value={selectedBankFilter} onChange={setSelectedBankFilter} placeholder="Filtrar Banco" /></div>

                  {/* Bulk Actions Info */}
                  {selectedTxIds.size > 0 && (
                     <div className="flex items-center gap-4 bg-blue-50 px-4 py-2 rounded-lg border border-blue-100 animate-fade-in">
                        <span className="text-sm font-semibold text-blue-800">{selectedTxIds.size} selecionado(s)</span>
                        <button onClick={handleBulkDelete} className="text-red-600 hover:text-red-800 text-sm font-bold flex items-center gap-1"><Trash2 size={14}/> Excluir Selecionados</button>
                     </div>
                  )}

                  <div className="flex-1 flex justify-end gap-2">
                     <button onClick={() => openImportModal('TRANSACTION')} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-gray-50"><Upload size={16}/> Importar</button>
                     <button onClick={openTransferModal} className="bg-purple-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-purple-700"><ArrowRightLeft size={16}/> Transferência</button>
                     <button onClick={() => { setEditingId(null); setTxForm({ type: 'EXPENSE', status: 'PENDING', date: new Date().toISOString().split('T')[0] }); setIsTxModalOpen(true); }} className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-blue-700"><Plus size={16}/> Nova Transação</button>
                  </div>
               </div>

               <TransactionTable 
                  transactions={transactionsByDateRange.filter(t => t.status === 'PENDING' && (selectedBankFilter ? t.bankId === selectedBankFilter : true))}
                  appData={data}
                  showBalance={false}
                  viewType="PENDING"
                  isSelectable={true}
                  selectedIds={selectedTxIds}
                  onToggleSelectAll={toggleSelectAll}
                  onToggleSelectOne={toggleSelectOne}
                  onEdit={(tx) => { setTxForm(tx); setEditingId(tx.id); setIsTxModalOpen(true); }}
                  onDelete={confirmDelete.bind(null, 'TRANSACTION')}
                  onPay={markAsPaid}
                  calculateRunningBalances={{}}
               />
            </div>
         }

         {currentView === 'PAYABLES' && 
            <div className="space-y-4">
               <div className="flex flex-col md:flex-row gap-4 mb-4 bg-white p-4 rounded-xl shadow-sm items-end">
                  <div className="w-full md:w-64"><SearchableSelect options={[{id: '', label: 'Todos os Bancos'}, ...filteredBanks.map(b => ({id: b.id, label: b.name}))]} value={selectedBankFilter} onChange={setSelectedBankFilter} placeholder="Filtrar Banco" /></div>

                  {/* Date Filter */}
                  <div className="flex gap-2 items-center">
                    <div>
                        <label className="text-xs font-semibold text-gray-500 mb-1 block">Início</label>
                        <input type="date" className="border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-700 outline-none focus:ring-2 focus:ring-blue-500 bg-white" value={dateFilter.start} onChange={e => setDateFilter(prev => ({...prev, start: e.target.value}))} />
                    </div>
                    <div>
                        <label className="text-xs font-semibold text-gray-500 mb-1 block">Fim</label>
                        <input type="date" className="border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-700 outline-none focus:ring-2 focus:ring-blue-500 bg-white" value={dateFilter.end} onChange={e => setDateFilter(prev => ({...prev, end: e.target.value}))} />
                    </div>
                    {(dateFilter.start || dateFilter.end) && <button onClick={() => setDateFilter({start:'', end:''})} className="text-xs text-red-500 hover:underline mt-6">Limpar</button>}
                  </div>

                  {/* Bulk Actions Info */}
                  {selectedTxIds.size > 0 && (
                     <div className="flex items-center gap-4 bg-blue-50 px-4 py-2 rounded-lg border border-blue-100 animate-fade-in mb-1 md:mb-0">
                        <span className="text-sm font-semibold text-blue-800">{selectedTxIds.size} selecionado(s)</span>
                        <button onClick={handleBulkDelete} className="text-red-600 hover:text-red-800 text-sm font-bold flex items-center gap-1"><Trash2 size={14}/> Excluir Selecionados</button>
                     </div>
                  )}

                  <div className="flex-1 flex justify-end gap-2">
                     <button onClick={() => openImportModal('TRANSACTION')} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-gray-50"><Upload size={16}/> Importar</button>
                     <button onClick={openTransferModal} className="bg-purple-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-purple-700"><ArrowRightLeft size={16}/> Transferência</button>
                     <button onClick={() => { setEditingId(null); setTxForm({ type: 'EXPENSE', status: 'PAID', date: new Date().toISOString().split('T')[0] }); setIsTxModalOpen(true); }} className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-blue-700"><Plus size={16}/> Nova Transação</button>
                  </div>
               </div>

               <TransactionTable 
                  transactions={transactionsByDateRange.filter(t => (selectedBankFilter ? t.bankId === selectedBankFilter : true) && t.status === 'PAID')}
                  appData={data}
                  showBalance={!!selectedBankFilter}
                  viewType="PAID"
                  isSelectable={true}
                  selectedIds={selectedTxIds}
                  onToggleSelectAll={toggleSelectAll}
                  onToggleSelectOne={toggleSelectOne}
                  onEdit={(tx) => { setTxForm(tx); setEditingId(tx.id); setIsTxModalOpen(true); }}
                  onDelete={confirmDelete.bind(null, 'TRANSACTION')}
                  onPay={markAsPaid}
                  calculateRunningBalances={calculateRunningBalances}
               />
            </div>
         }

         {currentView === 'WALLETS' && renderGenericList('Gerenciar Carteiras', data.wallets, 'WALLET', [{key:'name', label:'Nome'}])}
         {currentView === 'BANKS' && renderGenericList('Bancos', filteredBanks, 'BANK', [{key:'name', label:'Nome'}, {key:'balance', label:'Saldo Inicial'}, {key:'initialDate', label:'Data Inicial'}])}
         {currentView === 'CATEGORIES' && renderGenericList('Categorias', data.categories, 'CATEGORY', [{key:'name', label:'Nome'}])}
         {currentView === 'COST_CENTERS' && renderGenericList('Centros de Custo', data.costCenters, 'COST', [{key:'name', label:'Nome'}])}
         {currentView === 'PARTICIPANTS' && renderGenericList('Participantes', data.participants, 'PARTICIPANT', [{key:'name', label:'Nome'}])}
         {currentView === 'SETTINGS' && (
             <div className="space-y-6">
                 {dbError && <div className="p-4 bg-red-100 text-red-800 rounded-lg">Atenção: Banco de dados desatualizado. Copie o SQL abaixo e execute no Supabase.</div>}
                 <div className="bg-white p-6 rounded-xl border border-gray-100">
                     <h3 className="font-bold mb-4">Conexão Supabase</h3>
                     <input className={INPUT_STYLE} placeholder="URL" value={configForm.url} onChange={e => setConfigForm({...configForm, url: e.target.value})} />
                     <input className={`${INPUT_STYLE} mt-2`} type="password" placeholder="Key" value={configForm.key} onChange={e => setConfigForm({...configForm, key: e.target.value})} />
                     <div className="mt-4 flex gap-2"><button onClick={handleSaveConfig} className="bg-emerald-600 text-white px-4 py-2 rounded">Salvar</button>{!isDemoMode && <button onClick={handleDisconnect} className="text-red-600">Desconectar</button>}</div>
                 </div>
                 <div className="bg-gray-900 text-gray-300 p-4 rounded-xl"><div className="flex justify-between mb-2"><span className="font-bold">SQL Schema</span><button onClick={copySqlToClipboard} className="text-xs bg-gray-700 px-2 py-1 rounded">{copiedSql ? 'Copiado!' : 'Copiar'}</button></div><pre className="text-xs overflow-x-auto">{DB_SCHEMA_SQL}</pre></div>
             </div>
         )}
      </main>

      {/* --- MODALS --- */}

      {/* Confirmation Modal */}
      <Modal isOpen={confirmModal.isOpen} onClose={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))} title={confirmModal.title} maxWidth="sm">
          <div className="space-y-6">
              <p className="text-gray-600">{confirmModal.message}</p>
              <div className="flex gap-4 justify-end">
                  <button onClick={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))} className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 font-medium">Não</button>
                  <button onClick={confirmModal.onConfirm} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-medium">Sim, excluir</button>
              </div>
          </div>
      </Modal>

      <Modal isOpen={genericModalOpen} onClose={() => { setGenericModalOpen(false); setEditingId(null); }} title={editingId ? "Editar" : "Novo"} maxWidth="md">
         <div className="space-y-4">
            <div><label className={LABEL_STYLE}>Nome</label><input type="text" className={INPUT_STYLE} value={genericForm.name || ''} onChange={e => setGenericForm({...genericForm, name: e.target.value})} /></div>

            {/* Campo Carteira no Banco */}
            {genericModalType === 'BANK' && (
              <div className="space-y-4">
                 <div>
                    <label className={LABEL_STYLE}>Carteira (Vínculo)</label>
                    <select className={INPUT_STYLE} value={genericForm.walletId || ''} onChange={e => setGenericForm({...genericForm, walletId: e.target.value})}>
                        <option value="">Nenhuma (Global)</option>
                        {data.wallets.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
                    </select>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className={LABEL_STYLE}>Saldo Atual (Inicial)</label>
                        <div className="flex">
                            <button
                                onClick={() => {
                                    const currentVal = genericForm.balance || 0;
                                    setGenericForm({ ...genericForm, balance: currentVal * -1 });
                                }}
                                className={`px-3 py-3 border border-r-0 rounded-l-lg font-bold transition-colors ${
                                    (genericForm.balance || 0) < 0 
                                    ? 'bg-red-50 text-red-600 border-red-200' 
                                    : 'bg-green-50 text-green-600 border-green-200'
                                }`}
                                title="Alternar entre Positivo e Negativo"
                            >
                                {(genericForm.balance || 0) < 0 ? '-' : '+'}
                            </button>
                            <div className="flex-1">
                                 <CurrencyInput 
                                    value={Math.abs(genericForm.balance || 0)} 
                                    onChange={(v) => {
                                         const isNegative = (genericForm.balance || 0) < 0;
                                         setGenericForm({ ...genericForm, balance: isNegative ? -v : v });
                                    }}
                                    className="rounded-l-none" 
                                 />
                            </div>
                        </div>
                        <p className="text-[10px] text-gray-400 mt-1">Defina manualmente o saldo atual da conta.</p>
                    </div>
                    <div><label className={LABEL_STYLE}>Data de Referência</label><input type="date" className={INPUT_STYLE} value={genericForm.initialDate || ''} onChange={e => setGenericForm({...genericForm, initialDate: e.target.value})} /></div>
                 </div>
              </div>
            )}

            <button onClick={handleGenericSave} className="w-full bg-blue-600 text-white py-3 rounded-lg font-medium hover:bg-blue-700">{editingId ? 'Salvar' : 'Criar'}</button>
         </div>
      </Modal>

      <Modal isOpen={isTxModalOpen} onClose={() => { setIsTxModalOpen(false); setEditingId(null); }} title={editingId ? "Editar Transação" : "Nova Transação"} maxWidth="4xl">
          <div className="space-y-4 pb-10">

             {/* Tipo de Transação (Débito/Crédito) */}
             <div className="flex gap-4 mb-4">
                <button 
                  className={`flex-1 py-3 rounded-lg font-bold border transition-colors ${txForm.type === 'EXPENSE' ? 'bg-red-50 border-red-200 text-red-700 ring-2 ring-red-100' : 'bg-white border-gray-200 text-gray-400 hover:bg-gray-50'}`}
                  onClick={() => setTxForm({...txForm, type: 'EXPENSE'})}
                >
                  <div className="flex items-center justify-center gap-2">
                    <TrendingDown size={20}/> Débito (Saída)
                  </div>
                </button>
                <button 
                  className={`flex-1 py-3 rounded-lg font-bold border transition-colors ${txForm.type === 'INCOME' ? 'bg-green-50 border-green-200 text-green-700 ring-2 ring-green-100' : 'bg-white border-gray-200 text-gray-400 hover:bg-gray-50'}`}
                  onClick={() => setTxForm({...txForm, type: 'INCOME'})}
                >
                  <div className="flex items-center justify-center gap-2">
                    <TrendingUp size={20}/> Crédito (Entrada)
                  </div>
                </button>
             </div>

             <div className="grid grid-cols-2 gap-4">
                <div><label className={LABEL_STYLE}>Data</label><input type="date" className={INPUT_STYLE} value={txForm.date} onChange={e => setTxForm({...txForm, date: e.target.value})} /></div>
                <div><label className={LABEL_STYLE}>Status</label><select className={INPUT_STYLE} value={txForm.status} onChange={e => setTxForm({...txForm, status: e.target.value as any})} disabled={!!editingId && txForm.status === 'PAID'}><option value="PENDING">Pendente</option><option value="PAID">Pago</option></select></div>
             </div>

             <div className="grid grid-cols-2 gap-4">
                <div><label className={LABEL_STYLE}>Nº Documento</label><input className={INPUT_STYLE} value={txForm.documentNumber || ''} onChange={e => setTxForm({...txForm, documentNumber: e.target.value})} placeholder="Opcional" /></div>
                <div><label className={LABEL_STYLE}>Banco</label><SearchableSelect options={filteredBanks.map(b => ({id: b.id, label: b.name}))} value={txForm.bankId || ''} onChange={(v) => setTxForm({...txForm, bankId: v})} placeholder="Selecione..." disabled={!!editingId && txForm.status === 'PAID'} /></div>
             </div>

             <div className="grid grid-cols-3 gap-4">
                <div><label className={LABEL_STYLE}>Categoria</label><SearchableSelect options={data.categories.map(c => ({id: c.id, label: c.name}))} value={txForm.categoryId || ''} onChange={(v) => setTxForm({...txForm, categoryId: v})} placeholder="Selecione..." /></div>
                <div><label className={LABEL_STYLE}>Centro de Custo</label><SearchableSelect options={data.costCenters.map(c => ({id: c.id, label: c.name}))} value={txForm.costCenterId || ''} onChange={(v) => setTxForm({...txForm, costCenterId: v})} placeholder="Selecione... (Opcional)" /></div>
                <div><label className={LABEL_STYLE}>Participante</label><SearchableSelect options={data.participants.map(p => ({id: p.id, label: p.name}))} value={txForm.participantId || ''} onChange={(v) => setTxForm({...txForm, participantId: v})} placeholder="Selecione..." /></div>
             </div>

             <div><label className={LABEL_STYLE}>Descrição (Opcional)</label><input className={INPUT_STYLE} value={txForm.description || ''} onChange={e => setTxForm({...txForm, description: e.target.value})} /></div>

             {/* Parcelamento Lógica */}
             {!editingId && <div className="bg-blue-50 p-3 rounded flex items-center gap-2"><input type="checkbox" checked={isRecurring} onChange={e => setIsRecurring(e.target.checked)} className="w-5 h-5"/> <label>Gerar Parcelamento Automático</label></div>}
             {isRecurring && <div><label className={LABEL_STYLE}>Qtd Parcelas</label><input type="number" className={INPUT_STYLE} value={installmentsCount} onChange={e => setInstallmentsCount(Number(e.target.value))} /></div>}

             <div><label className={LABEL_STYLE}>Valor</label><CurrencyInput value={txForm.amount} onChange={(v) => setTxForm({...txForm, amount: v})} /></div>

             <div className="flex gap-2 mt-6">
               {editingId && (
                 <button onClick={() => confirmDelete('TRANSACTION', editingId)} className="bg-red-100 text-red-700 py-3 px-4 rounded-lg font-medium hover:bg-red-200 transition-colors">Excluir</button>
               )}
               <button onClick={handleCreateTransaction} className="flex-1 bg-blue-600 text-white py-3 rounded-lg font-medium">{loading ? 'Salvando...' : 'Salvar'}</button>
             </div>
          </div>
      </Modal>

      <Modal isOpen={isTransferModalOpen} onClose={() => setIsTransferModalOpen(false)} title="Nova Transferência" maxWidth="full">
         <div className="space-y-6">
             {/* Linha 1: Data e Valor (Compacto) */}
             <div className="grid grid-cols-2 gap-4">
                 <div><label className={LABEL_STYLE}>Data</label><input type="date" className={INPUT_STYLE} value={transferForm.date} onChange={e => setTransferForm({...transferForm, date: e.target.value})} /></div>
                 <div><label className={LABEL_STYLE}>Valor</label><CurrencyInput value={transferForm.amount} onChange={v => setTransferForm({...transferForm, amount: v})} /></div>
             </div>

             {/* Linha 2: Origem e Destino */}
             <div className="grid grid-cols-2 gap-4">
                 <div><label className={LABEL_STYLE}>Origem</label><SearchableSelect options={filteredBanks.map(b => ({id: b.id, label: b.name}))} value={transferForm.fromBankId} onChange={v => setTransferForm({...transferForm, fromBankId: v})} placeholder="De..." /></div>
                 <div><label className={LABEL_STYLE}>Destino</label><SearchableSelect options={filteredBanks.map(b => ({id: b.id, label: b.name}))} value={transferForm.toBankId} onChange={v => setTransferForm({...transferForm, toBankId: v})} placeholder="Para..." /></div>
             </div>

             {/* Linha 3: Participante (Linha inteira, obrigatório) */}
             <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={LABEL_STYLE}>Participante</label>
                    <SearchableSelect options={data.participants.map(p => ({id: p.id, label: p.name}))} value={transferForm.participantId} onChange={v => setTransferForm({...transferForm, participantId: v})} placeholder="Selecione..." />
                 </div>
                 <div>
                    <label className={LABEL_STYLE}>Categoria</label>
                    <SearchableSelect options={data.categories.map(c => ({id: c.id, label: c.name}))} value={transferForm.categoryId} onChange={v => setTransferForm({...transferForm, categoryId: v})} placeholder="Selecione..." />
                 </div>
             </div>

             <button onClick={handleTransfer} className="w-full bg-purple-600 text-white py-3 rounded-lg font-medium hover:bg-purple-700 mt-4">{loading ? 'Processando...' : 'Confirmar Transferência'}</button>
         </div>
      </Modal>

      <Modal isOpen={isImportModalOpen} onClose={() => setIsImportModalOpen(false)} title="Importação em Massa" maxWidth="lg">
         <div className="space-y-4">
             <div className="p-3 bg-blue-50 text-blue-700 rounded-lg text-sm">
                 Importando para: <strong>{importType === 'BANK' ? 'Bancos' : importType === 'CATEGORY' ? 'Categorias' : importType === 'TRANSACTION' ? 'Transações (Planilha)' : 'Participantes'}</strong>
             </div>

             {/* Wallet Selector for Import */}
             {importType === 'BANK' && (
               <div>
                  <label className={LABEL_STYLE}>Carteira de Destino</label>
                  <select className={INPUT_STYLE} value={importWalletId} onChange={e => setImportWalletId(e.target.value)}>
                     <option value="">Carteira Atual (Filtro)</option>
                     {data.wallets.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
                  </select>
               </div>
             )}

             <div>
                <label className={LABEL_STYLE}>{importType === 'TRANSACTION' ? 'Cole os dados da planilha (Tab separated)' : 'Lista de Itens (Um por linha)'}</label>
                <textarea 
                   className={`${INPUT_STYLE} h-40 font-mono text-sm whitespace-pre`} 
                   placeholder={importType === 'TRANSACTION' ? "Data | Banco | Categoria..." : "Item 1\nItem 2\nItem 3"} 
                   value={importText} 
                   onChange={e => setImportText(e.target.value)}
                />
             </div>
             <button onClick={handleBulkImport} className="w-full bg-emerald-600 text-white py-3 rounded-lg font-medium hover:bg-emerald-700">
                {loading ? 'Processando...' : 'Importar Itens'}
             </button>
         </div>
      </Modal>
    </div>
  );
}

