export default function App() {
  const [data, setData] = useState<AppData>({ wallets: [], banks: [], categories: [], costCenters: [], participants: [], transactions: [] });
  const [loading, setLoading] = useState(true);
  const [currentView, setCurrentView] = useState<ViewName>('DASHBOARD');
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [dbError, setDbError] = useState(false);

  // States
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [isTransferModalOpen, setIsTransferModalOpen] = useState(false);
  const [genericModalOpen, setGenericModalOpen] = useState(false);
  const [genericModalType, setGenericModalType] = useState<'WALLET'|'BANK'|'CATEGORY'|'COST'|'PARTICIPANT'|null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [importType, setImportType] = useState<'BANK' | 'CATEGORY' | 'PARTICIPANT' | 'TRANSACTION'>('BANK');
  const [importText, setImportText] = useState('');
  const [importWalletId, setImportWalletId] = useState(''); // Specific wallet for import

  // Bulk selection state for Payables
  const [selectedTxIds, setSelectedTxIds] = useState<Set<string>>(new Set());

  // Confirmation Modal State
  const [confirmModal, setConfirmModal] = useState<{isOpen: boolean, title: string, message: string, onConfirm: () => void}>({
    isOpen: false, title: '', message: '', onConfirm: () => {}
  });

  // Global Filters
  const [selectedWalletFilter, setSelectedWalletFilter] = useState<string>(''); // Wallet Selection
  const [selectedBankFilter, setSelectedBankFilter] = useState<string>(''); // View specific filter
  const [dateFilter, setDateFilter] = useState({ start: '', end: '' }); // Date Filter

  const [showNotifications, setShowNotifications] = useState(false);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [configForm, setConfigForm] = useState({ url: localStorage.getItem(LS_KEYS.URL) || '', key: localStorage.getItem(LS_KEYS.KEY) || '' });
  const [copiedSql, setCopiedSql] = useState(false);

  // Forms
  const [txForm, setTxForm] = useState<Partial<Transaction>>({ type: 'EXPENSE', status: 'PENDING', date: new Date().toISOString().split('T')[0] });
  const [isRecurring, setIsRecurring] = useState(false);
  const [installmentsCount, setInstallmentsCount] = useState(2);
  const [transferForm, setTransferForm] = useState({ amount: 0, fromBankId: '', toBankId: '', date: new Date().toISOString().split('T')[0], description: 'Transferência', participantId: '', categoryId: '' });
  const [genericForm, setGenericForm] = useState<any>({});

  const loadData = async () => {
    try {
      setLoading(true);
      if (!isSupabaseConfigured()) { setIsDemoMode(true); setDbError(false); } 
      else { setIsDemoMode(false); const isHealthy = await dataService.checkDatabaseHealth(); setDbError(!isHealthy); }
      const appData = await dataService.getInitialData();
      setData(appData);
    } catch (error) { console.error(error); setIsDemoMode(true); } finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  // Força seleção da primeira carteira se nenhuma estiver selecionada
  useEffect(() => {
    if (data.wallets.length > 0 && !selectedWalletFilter) {
      setSelectedWalletFilter(data.wallets[0].id);
    }
  }, [data.wallets, selectedWalletFilter]);

  // Limpa seleção ao mudar de view
  useEffect(() => {
    setSelectedTxIds(new Set());
  }, [currentView]);

  // --- Derived Data (Global Filtering by Wallet) ---
  const filteredBanks = useMemo(() => {
    if (!selectedWalletFilter) return data.banks;
    return data.banks.filter(b => b.walletId === selectedWalletFilter);
  }, [data.banks, selectedWalletFilter]);

  const filteredTransactionsGlobal = useMemo(() => {
    // Only show transactions belonging to the visible banks
    return data.transactions.filter(t => filteredBanks.some(b => b.id === t.bankId));
  }, [data.transactions, filteredBanks]);

  const transactionsByDateRange = useMemo(() => {
    return filteredTransactionsGlobal.filter(t => {
      if (dateFilter.start && t.date < dateFilter.start) return false;
      if (dateFilter.end && t.date > dateFilter.end) return false;
      return true;
    });
  }, [filteredTransactionsGlobal, dateFilter]);

  // Derived for Views
  const totalBalance = useMemo(() => filteredBanks.reduce((acc, b) => acc + b.balance, 0), [filteredBanks]);

  const pendingPayables = useMemo(() => filteredTransactionsGlobal
      .filter(t => t.type === 'EXPENSE' && t.status === 'PENDING')
      .reduce((acc, t) => acc + t.amount, 0), [filteredTransactionsGlobal]);

  const pendingReceivables = useMemo(() => filteredTransactionsGlobal
      .filter(t => t.type === 'INCOME' && t.status === 'PENDING')
      .reduce((acc, t) => acc + t.amount, 0), [filteredTransactionsGlobal]);

  const notifications = useMemo(() => {
    const today = new Date(); today.setHours(0,0,0,0);
    const threeDays = new Date(today); threeDays.setDate(today.getDate() + 3);
    return filteredTransactionsGlobal.filter(t => t.type === 'EXPENSE' && t.status !== 'PAID' && new Date(t.date) <= threeDays).sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [filteredTransactionsGlobal]);

  const calculateRunningBalances = useMemo(() => {
    if (!selectedBankFilter) return {};

    // Considera apenas transações pagas para o saldo
    const bankTxs = filteredTransactionsGlobal
      .filter(t => t.bankId === selectedBankFilter && t.status === 'PAID')
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    const currentBalance = filteredBanks.find(b => b.id === selectedBankFilter)?.balance || 0;

    const balances: {[key: string]: number} = {};
    let running = currentBalance;

    const sortedDesc = [...bankTxs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    for (const tx of sortedDesc) {
      balances[tx.id] = running;
      if (tx.type === 'INCOME' && tx.status === 'PAID') running -= tx.amount;
      else if (tx.type === 'EXPENSE' && tx.status === 'PAID') running += tx.amount;
    }
    return balances;
  }, [filteredTransactionsGlobal, selectedBankFilter, filteredBanks]);

  // --- Handlers ---
  const handleCreateTransaction = async () => {
    // Campos Obrigatórios
    if (!txForm.amount || txForm.amount <= 0) { alert('Informe o Valor.'); return; }
    if (!txForm.bankId) { alert('Selecione um Banco.'); return; }
    if (!txForm.categoryId) { alert('Selecione uma Categoria.'); return; }
    if (!txForm.participantId) { alert('Selecione um Participante.'); return; }
    if (!txForm.status) { alert('Selecione o Status (Pendente/Pago).'); return; }
    if (!txForm.date) { alert('Selecione a Data.'); return; }

    // Se a descrição estiver vazia, vai como string vazia (opcional)
    const descriptionToSend = txForm.description?.trim() || '';

    try {
      setLoading(true);
      const txPayload = { ...txForm, description: descriptionToSend, amount: Number(txForm.amount), bankId: txForm.bankId!, type: txForm.type as any };

      if (editingId) {
        let appliedToAll = false;
        if (txForm.installmentTotal && txForm.installmentTotal > 1) {
           if (window.confirm("Deseja aplicar as alterações para TODAS as parcelas PENDENTES desta série?")) {
              await dataService.updateInstallmentBatch(editingId, {
                  amount: Number(txForm.amount), bankId: txForm.bankId!, categoryId: txForm.categoryId,
                  participantId: txForm.participantId, costCenterId: txForm.costCenterId, type: txForm.type as TransactionType
              });
              appliedToAll = true;
           }
        }
        if (!appliedToAll) await dataService.updateTransaction(editingId, txPayload as any);
      } else {
        if (isRecurring && installmentsCount > 1) {
          await dataService.createInstallments({ ...txPayload, history: [] } as any, Number(installmentsCount));
        } else {
          await dataService.createTransaction({ ...txPayload, installmentNumber: 1, installmentTotal: 1, history: [] } as any);
        }
      }
      await loadData(); setIsTxModalOpen(false); setEditingId(null);
      setTxForm({ type: 'EXPENSE', status: 'PENDING', date: new Date().toISOString().split('T')[0], description: '', amount: 0, bankId: '', categoryId: '', participantId: '', costCenterId: '', documentNumber: '' });
      setIsRecurring(false); setInstallmentsCount(2);
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const confirmDelete = (type: string, id: string, e?: React.MouseEvent) => {
      if (e) {
          e.stopPropagation();
          e.preventDefault();
      }
      setConfirmModal({
          isOpen: true,
          title: 'Excluir Item',
          message: 'Tem certeza que deseja excluir este item? Esta ação não pode ser desfeita.',
          onConfirm: () => performDelete(type, id)
      });
  };

  const performDelete = async (type: string, id: string) => {
    try {
      setLoading(true);
      setConfirmModal(prev => ({ ...prev, isOpen: false })); // Close confirm modal

      let table: any = '';
      if (type === 'WALLET') table = 'wallets';
      if (type === 'BANK') table = 'banks';
      if (type === 'CATEGORY') table = 'categories';
      if (type === 'COST') table = 'cost_centers';
      if (type === 'PARTICIPANT') table = 'participants';
      if (type === 'TRANSACTION') table = 'transactions';

      await dataService.deleteItem(table, id);

      if (editingId === id) {
        setIsTxModalOpen(false);
        setGenericModalOpen(false);
        setEditingId(null);
      }

      await loadData();
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const handleBulkDelete = async () => {
    if (selectedTxIds.size === 0) return;

    setConfirmModal({
      isOpen: true,
      title: 'Excluir Transações',
      message: `Tem certeza que deseja excluir ${selectedTxIds.size} transações selecionadas?`,
      onConfirm: async () => {
        try {
          setLoading(true);
          setConfirmModal(prev => ({...prev, isOpen: false}));
          await dataService.deleteTransactionsBatch(Array.from(selectedTxIds));
          setSelectedTxIds(new Set());
          await loadData();
        } catch(e: any) { alert(e.message); } finally { setLoading(false); }
      }
    });
  };

  const handleTransfer = async () => {
    if (!transferForm.fromBankId || !transferForm.toBankId || !transferForm.amount || !transferForm.participantId || !transferForm.categoryId) {
      alert("Preencha todos os campos obrigatórios (Origem, Destino, Valor, Participante e Categoria).");
      return;
    }
    if (transferForm.fromBankId === transferForm.toBankId) {
      alert("A conta de origem e destino não podem ser a mesma.");
      return;
    }

    try {
      setLoading(true);
      await dataService.createTransfer(Number(transferForm.amount), transferForm.date, transferForm.fromBankId, transferForm.toBankId, transferForm.description, transferForm.participantId || undefined, transferForm.categoryId);
      await loadData(); setIsTransferModalOpen(false);
      setTransferForm({ ...transferForm, amount: 0, fromBankId: '', toBankId: '', description: 'Transferência', participantId: '', categoryId: '' });
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const markAsPaid = async (tx: Transaction) => {
    try { setLoading(true); await dataService.markAsPaid(tx); await loadData(); } 
    catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const openGenericModal = (type: 'WALLET'|'BANK'|'CATEGORY'|'COST'|'PARTICIPANT', item?: any) => {
    setGenericModalType(type);
    if (item) { setEditingId(item.id); setGenericForm(item); } 
    else { setEditingId(null); setGenericForm(type === 'BANK' && selectedWalletFilter ? {walletId: selectedWalletFilter} : {}); }
    setGenericModalOpen(true);
  };

  const handleGenericSave = async () => {
    if (!genericModalType) return;
    try {
      setLoading(true);
      if (editingId) {
        if (genericModalType === 'WALLET') await dataService.updateWallet(editingId, genericForm);
        if (genericModalType === 'BANK') await dataService.updateBank(editingId, genericForm);
        if (genericModalType === 'CATEGORY') await dataService.updateCategory(editingId, { ...genericForm, type: 'EXPENSE' }); // Default type
        if (genericModalType === 'COST') await dataService.updateCostCenter(editingId, { ...genericForm, code: '' }); // No code
        if (genericModalType === 'PARTICIPANT') await dataService.updateParticipant(editingId, { ...genericForm, type: 'OTHER' }); // Default type
      } else {
        if (genericModalType === 'WALLET') await dataService.createWallet(genericForm);
        if (genericModalType === 'BANK') await dataService.createBank({ ...genericForm, balance: Number(genericForm.balance || 0), color: BANK_COLORS[Math.floor(Math.random() * BANK_COLORS.length)] });
        if (genericModalType === 'CATEGORY') await dataService.createCategory({ ...genericForm, type: 'EXPENSE' });
        if (genericModalType === 'COST') await dataService.createCostCenter({ ...genericForm, code: '' });
        if (genericModalType === 'PARTICIPANT') await dataService.createParticipant({ ...genericForm, type: 'OTHER' });
      }
      await loadData(); setGenericModalOpen(false); setGenericForm({}); setEditingId(null);
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const handleBulkImport = async () => {
    if (!importText.trim()) return;
    const lines: string[] = importText.split('\n').map(l => l.trim()).filter(l => l.length > 0);

    try {
      setLoading(true);

      if (importType === 'TRANSACTION') {
         await processTransactionImport(lines);
         await loadData();
         setIsImportModalOpen(false);
         alert("Transações importadas com sucesso!");
         return;
      }

      // Simple Import (Name only)
      const uniqueLines = Array.from(new Set(lines));
      for (const name of uniqueLines) {
        const targetWalletId = importWalletId || selectedWalletFilter;
        if (importType === 'BANK') {
           const existsInWallet = data.banks.some(b => b.name.toLowerCase() === name.toLowerCase() && (b.walletId === targetWalletId || (!b.walletId && !targetWalletId)));
           if (!existsInWallet) await dataService.createBank({ name, balance: 0, color: BANK_COLORS[Math.floor(Math.random() * BANK_COLORS.length)], walletId: targetWalletId });
        } else if (importType === 'CATEGORY' && !data.categories.some(c => c.name.toLowerCase() === name.toLowerCase())) {
           await dataService.createCategory({ name, type: 'EXPENSE' });
        } else if (importType === 'PARTICIPANT' && !data.participants.some(p => p.name.toLowerCase() === name.toLowerCase())) {
           await dataService.createParticipant({ name, type: 'OTHER' });
        }
      }
      await loadData(); setIsImportModalOpen(false); alert(`${uniqueLines.length} linhas processadas!`);
    } catch (e: any) { alert(e.message); } finally { setLoading(false); }
  };

  const processTransactionImport = async (lines: string[]) => {
      // 1. Ensure "Renzo Braz" wallet exists
      let targetWalletId = '';
      const targetWalletName = "Renzo Braz";
      let wallet = data.wallets.find(w => w.name.toLowerCase() === targetWalletName.toLowerCase());

      if (!wallet) {
          // Create Renzo Braz wallet
          wallet = await dataService.createWallet({ name: targetWalletName });
      }
      targetWalletId = wallet.id;

      // Caches for ID lookups
      const bankCache = new Map<string, string>(data.banks.filter(b => b.walletId === targetWalletId).map(b => [b.name.toLowerCase(), b.id]) as [string, string][]);
      const catCache = new Map<string, string>(data.categories.map(c => [c.name.toLowerCase(), c.id]) as [string, string][]);
      const costCache = new Map<string, string>(data.costCenters.map(c => [c.name.toLowerCase(), c.id]) as [string, string][]);
      const partCache = new Map<string, string>(data.participants.map(p => [p.name.toLowerCase(), p.id]) as [string, string][]);

      for (const line of lines) {
         if (!line.trim()) continue;
         const cols = line.split('\t').map(c => c.trim());

         // Headers skip check
         if (cols[0].toLowerCase().includes('data') && cols[2].toLowerCase().includes('origem')) continue;

         const dateStr = cols[0] || '';
         const docStr = cols[1] || '';
         const bankName = cols[2] || '';
         const catName = cols[3] || '';
         const ccName = cols[4] || '';
         const partName = cols[5] || '';
         const descStr = cols[6] || '';
         const instNumStr = cols[7] || '';
         const instTotalStr = cols[8] || '';
         const debitStr = cols[9] || '';
         const creditStr = cols[10] || '';
         const statusStr = cols[11] || '';

         // Validate Date
         if (!dateStr || dateStr.length < 8) continue;
         const [d, m, y] = dateStr.split('/');
         const fullYear = y.length === 2 ? `20${y}` : y;
         const isoDate = `${fullYear}-${m}-${d}`;
         if (isoDate.length !== 10) continue;

         // Resolve Bank
         if (bankName) {
             if (!bankCache.has(bankName.toLowerCase())) {
                 const newBank = await dataService.createBank({ name: bankName, balance: 0, color: 'bg-gray-500', walletId: targetWalletId });
                 bankCache.set(bankName.toLowerCase(), newBank.id);
             }
         }

         const bankId = bankCache.get(bankName.toLowerCase());
         if (!bankId) continue;

         // Resolve Category
         if (catName && !catCache.has(catName.toLowerCase())) {
             const newCat = await dataService.createCategory({ name: catName, type: 'EXPENSE' });
             catCache.set(catName.toLowerCase(), newCat.id);
         }
         const categoryId = catName ? catCache.get(catName.toLowerCase()) : undefined;

         // Resolve Cost Center
         if (ccName && !costCache.has(ccName.toLowerCase())) {
             const newCC = await dataService.createCostCenter({ name: ccName, code: '' });
             costCache.set(ccName.toLowerCase(), newCC.id);
         }
         const costCenterId = ccName ? costCache.get(ccName.toLowerCase()) : undefined;

         // Resolve Participant
         if (partName && !partCache.has(partName.toLowerCase())) {
             const newPart = await dataService.createParticipant({ name: partName, type: 'OTHER' });
             partCache.set(partName.toLowerCase(), newPart.id);
         }
         const participantId = partName ? partCache.get(partName.toLowerCase()) : undefined;

         // Amount & Type
         const debitVal = debitStr ? parseFloat(debitStr.replace(/\./g, '').replace(',', '.')) : 0;
         const creditVal = creditStr ? parseFloat(creditStr.replace(/\./g, '').replace(',', '.')) : 0;

         let amount = 0;
         let type: TransactionType = 'EXPENSE';

         if (debitVal > 0) {
             amount = debitVal;
             type = 'EXPENSE';
         } else if (creditVal > 0) {
             amount = creditVal;
             type = 'INCOME';
         } else {
            // Skip rows with no value
            continue;
         }

         let status: TransactionStatus = 'PENDING';
         if (statusStr) {
            status = (statusStr.toLowerCase().includes('pago')) ? 'PAID' : 'PENDING';
         } else {
            // Se a data é passada (anterior a hoje), assume que já foi pago (Movimentação Histórica)
            const today = new Date().toISOString().split('T')[0];
            status = isoDate < today ? 'PAID' : 'PENDING';
         }

         // Installment logic
         const installmentNumber = instNumStr ? parseInt(instNumStr) : undefined;
         const installmentTotal = instTotalStr ? parseInt(instTotalStr) : undefined;

         // Description (Default to empty if missing)
         const description = descStr || '';

         await dataService.createTransaction({
             description,
             amount,
             date: isoDate,
             type,
             status,
             bankId,
             categoryId,
             costCenterId,
             participantId,
             documentNumber: docStr,
             history: [],
             installmentNumber: installmentNumber || 1,
             installmentTotal: installmentTotal || 1
         });
      }
  };

  const openImportModal = (type: 'BANK' | 'CATEGORY' | 'PARTICIPANT' | 'TRANSACTION') => {
    setImportType(type);
    if (type === 'BANK') { setImportText(DEFAULT_BANK_IMPORT_LIST); setImportWalletId(selectedWalletFilter); } 
    else { setImportText(''); setImportWalletId(''); }
    setIsImportModalOpen(true);
  };

  const handleAskAI = async () => { setAiLoading(true); const response = await analyzeFinancials(data, aiQuery); setAiResponse(response); setAiLoading(false); };
  const handleSaveConfig = async () => { if (!configForm.url || !configForm.key) return alert("Preencha URL e Key"); saveSupabaseConfig(configForm.url, configForm.key); await new Promise(r => setTimeout(r, 500)); await loadData(); };
  const handleDisconnect = async () => { disconnectSupabase(); setIsDemoMode(true); await loadData(); };
  const copySqlToClipboard = () => { navigator.clipboard.writeText(DB_SCHEMA_SQL); setCopiedSql(true); setTimeout(() => setCopiedSql(false), 2000); };
  const goToTransactionMovement = (tx: Transaction) => { setSelectedBankFilter(tx.bankId); setCurrentView('PAYABLES'); };

  const openTransferModal = () => {
      // Logic to find "Transferência Mesma Titularidade"
      const transferCat = data.categories.find(c => 
          c.name.toLowerCase().includes("transferência mesma titularidade") || 
          c.name.toLowerCase().includes("transferencia mesma titularidade")
      );

      setTransferForm({ 
          amount: 0, 
          fromBankId: '', 
          toBankId: '', 
          date: new Date().toISOString().split('T')[0], 
          description: 'Transferência', 
          participantId: '',
          categoryId: transferCat ? transferCat.id : ''
      }); 
      setIsTransferModalOpen(true);
  };

  // --- Handlers for Table Selections ---
  const toggleSelectAll = (ids: string[]) => {
      if (selectedTxIds.size === ids.length) {
         setSelectedTxIds(new Set());
      } else {
         setSelectedTxIds(new Set(ids));
      }
   };

  const toggleSelectOne = (id: string) => {
      const newSet = new Set(selectedTxIds);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setSelectedTxIds(newSet);
   };

  // --- Renderers ---
  const renderDashboard = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard title="Saldo Total" value={`R$ ${totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} type={totalBalance >= 0 ? 'positive' : 'negative'} />
        <StatCard title="A Pagar (Pendente)" value={`R$ ${pendingPayables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} type="negative" />
        <StatCard title="A Receber (Pendente)" value={`R$ ${pendingReceivables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} type="positive" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-96">
          <h3 className="text-lg font-bold text-gray-800 mb-4">Receitas vs Despesas (Por Categoria)</h3>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data.categories.map(c => ({ name: c.name, value: filteredTransactionsGlobal.filter(t => t.categoryId === c.id && t.status === 'PAID').reduce((a, t) => a + t.amount, 0), type: c.type })).filter(d => d.value > 0)}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
              <YAxis fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `R$${val}`} />
              <RechartsTooltip formatter={(val: number) => `R$ ${val.toLocaleString('pt-BR')}`} cursor={{fill: 'transparent'}} />
              <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                {data.categories.map((entry, i) => <Cell key={i} fill={entry.type === 'INCOME' ? '#10b981' : '#f43f5e'} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
           <div className="flex justify-between items-center mb-4"><h3 className="text-lg font-bold text-gray-800">Últimas Transações</h3><button onClick={() => setCurrentView('PAYABLES')} className="text-sm text-blue-600 hover:underline">Ver todas</button></div>
           <div className="space-y-3">
              {filteredTransactionsGlobal.slice(0, 5).map(tx => (
                <div key={tx.id} className="flex justify-between items-center p-3 hover:bg-gray-50 rounded-lg transition-colors border-b border-gray-50 last:border-0">
                   <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-full ${tx.type === 'INCOME' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>{tx.type === 'INCOME' ? <TrendingUp size={16} /> : <TrendingDown size={16} />}</div>
                      <div><p className="font-medium text-gray-800">{tx.description}</p><p className="text-xs text-gray-500">{new Date(tx.date).toLocaleDateString('pt-BR')}</p></div>
                   </div>
                   <div className="text-right"><p className={`font-bold ${tx.type === 'INCOME' ? 'text-green-600' : 'text-red-600'}`}>{tx.type === 'EXPENSE' ? '-' : '+'} R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p><span className={`text-[10px] px-2 py-0.5 rounded-full ${tx.status === 'PAID' ? 'bg-gray-100 text-gray-600' : 'bg-yellow-100 text-yellow-700'}`}>{tx.status === 'PAID' ? 'Pago' : 'Pendente'}</span></div>
                </div>
              ))}
           </div>
        </div>
      </div>
    </div>
  );

  const renderGenericList = (title: string, items: any[], type: 'WALLET'|'BANK'|'CATEGORY'|'COST'|'PARTICIPANT', cols: {key: string, label: string}[]) => (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100">
      <div className="p-6 border-b border-gray-100 flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">{title}</h2>
        <div className="flex gap-2">
          {['BANK', 'CATEGORY', 'PARTICIPANT'].includes(type) && <button onClick={() => openImportModal(type as any)} className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 rounded-lg hover:bg-gray-50 text-sm font-medium"><Upload size={16} /> Importar</button>}
          <button onClick={() => openGenericModal(type)} className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-white rounded-lg hover:bg-gray-800 text-sm font-medium"><Plus size={16} /> Adicionar</button>
        </div>
      </div>
      <table className="w-full text-left text-sm text-gray-600">
         <thead className="bg-gray-50 text-gray-900 font-semibold border-b border-gray-200"><tr>{cols.map(c => <th key={c.key} className="px-6 py-4">{c.label}</th>)}<th className="px-6 py-4 text-right">Ações</th></tr></thead>
         <tbody className="divide-y divide-gray-100">
            {items.map(item => (
              <tr key={item.id} className="hover:bg-gray-50 group">
                {cols.map(c => <td key={c.key} className="px-6 py-4">{c.key === 'balance' ? `R$ ${item[c.key]?.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : c.key === 'initialDate' ? (item[c.key] ? new Date(item[c.key]).toLocaleDateString('pt-BR') : '-') : item[c.key]}</td>)}
                <td className="px-6 py-4 text-right">
                   <div className="flex justify-end gap-2">
                      <button onClick={() => openGenericModal(type, item)} className="text-blue-400 hover:text-blue-600"><Pencil size={16} /></button>
                      <button onClick={(e) => confirmDelete(type, item.id, e)} className="text-red-400 hover:text-red-600"><Trash2 size={16} /></button>
                   </div>
                </td>
              </tr>
            ))}
         </tbody>
      </table>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-[#f3f4f6]">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 fixed inset-y-0 z-20 hidden md:flex flex-col">
         <div className="p-6 border-b border-gray-100">
            <div className="flex items-center gap-2 mb-4">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">F</div>
              <span className="text-xl font-bold text-gray-900">FinControl Pro</span>
            </div>

            {/* Wallet Selector */}
            <div className="relative">
               <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1 block">Carteira (Contexto)</label>
               <select 
                 className="w-full bg-gray-50 border border-gray-200 text-gray-800 text-sm rounded-lg p-2.5 focus:ring-blue-500 focus:border-blue-500 outline-none cursor-pointer font-medium"
                 value={selectedWalletFilter}
                 onChange={(e) => { setSelectedWalletFilter(e.target.value); setCurrentView('DASHBOARD'); }}
               >
                 {data.wallets.length === 0 && <option value="">Criar Carteira...</option>}
                 {data.wallets.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
               </select>
            </div>
         </div>

         <nav className="p-4 space-y-1 flex-1 overflow-y-auto">
            {MENU_ITEMS.map(item => (
              <button key={item.id} onClick={() => setCurrentView(item.id as ViewName)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${currentView === item.id ? 'bg-blue-50 text-blue-700' : 'text-gray-600 hover:bg-gray-50'}`}>
                 {item.icon} {item.label}
              </button>
            ))}
         </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-2 md:p-4 overflow-x-hidden bg-[#f3f4f6]">
         <div className="flex justify-between items-center mb-6">
            <div>
               <h1 className="text-2xl font-bold text-gray-900">{MENU_ITEMS.find(m => m.id === currentView)?.label}</h1>
               <p className="text-gray-500 text-sm">{selectedWalletFilter ? `Contexto: ${data.wallets.find(w => w.id === selectedWalletFilter)?.name}` : 'Visualizando todas as carteiras'}</p>
            </div>
            <div className="flex items-center gap-4">
                <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium border shadow-sm ${!isDemoMode ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-gray-50 text-gray-500 border-gray-200'}`}>
                   {!isDemoMode ? <Cloud size={16} /> : <CloudOff size={16} />} <span className="hidden sm:inline">{!isDemoMode ? 'Cloud' : 'Local'}</span>
                </div>
                <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 bg-white rounded-full border border-gray-200 relative"><Bell size={20} />{notifications.length > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full text-[10px] text-white flex items-center justify-center translate-x-1 -translate-y-1">{notifications.length}</span>}</button>
            </div>
         </div>

         {/* Notifications Dropdown */}
         {showNotifications && (
            <div className="absolute right-8 mt-[-10px] w-80 bg-white rounded-xl shadow-2xl border border-gray-100 z-50 overflow-hidden">
              <div className="p-3 bg-gray-50 flex justify-between"><h4 className="font-semibold text-gray-700 text-sm">Contas Próximas</h4><button onClick={() => setShowNotifications(false)}><X size={14}/></button></div>
              <div className="max-h-64 overflow-y-auto">
                {notifications.length > 0 ? notifications.map(tx => (
                   <div key={tx.id} className="p-3 border-b border-gray-50 hover:bg-gray-50 flex gap-3 cursor-pointer" onClick={() => goToTransactionMovement(tx)}>
                      <AlertTriangle size={14} className="text-orange-500 mt-1"/>
                      <div><p className="text-sm font-medium">{tx.description}</p><p className="text-xs text-gray-500">{new Date(tx.date).toLocaleDateString('pt-BR')}</p></div>
                   </div>
                )) : <div className="p-4 text-center text-gray-400 text-sm">Tudo em dia!</div>}
              </div>
            </div>
         )}

         {dbError && !isDemoMode && currentView !== 'SETTINGS' && <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl text-red-800 font-medium cursor-pointer" onClick={() => setCurrentView('SETTINGS')}>Banco de Dados Desatualizado. Clique para corrigir.</div>}

         {currentView === 'DASHBOARD' && renderDashboard()}

         {currentView === 'ACCOUNTS_PAYABLE' && 
            <div className="space-y-6">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="bg-red-50 p-6 rounded-xl border border-red-100"><h2 className="text-lg font-bold text-red-800">Total a Pagar</h2><h3 className="text-2xl font-bold text-red-700">R$ {pendingPayables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3></div>
                  <div className="bg-green-50 p-6 rounded-xl border border-green-100"><h2 className="text-lg font-bold text-green-800">Total a Receber</h2><h3 className="text-2xl font-bold text-green-700">R$ {pendingReceivables.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3></div>
               </div>

               {/* Controles para Contas a Pagar/Receber */}
               <div className="flex gap-4 mb-4 bg-white p-4 rounded-xl shadow-sm items-center">
                  <div className="w-64"><SearchableSelect options={[{id: '', label: 'Todos os Bancos'}, ...filteredBanks.map(b => ({id: b.id, label: b.name}))]} value={selectedBankFilter} onChange={setSelectedBankFilter} placeholder="Filtrar Banco" /></div>

                  {/* Bulk Actions Info */}
                  {selectedTxIds.size > 0 && (
                     <div className="flex items-center gap-4 bg-blue-50 px-4 py-2 rounded-lg border border-blue-100 animate-fade-in">
                        <span className="text-sm font-semibold text-blue-800">{selectedTxIds.size} selecionado(s)</span>
                        <button onClick={handleBulkDelete} className="text-red-600 hover:text-red-800 text-sm font-bold flex items-center gap-1"><Trash2 size={14}/> Excluir Selecionados</button>
                     </div>
                  )}

                  <div className="flex-1 flex justify-end gap-2">
                     <button onClick={() => openImportModal('TRANSACTION')} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-gray-50"><Upload size={16}/> Importar</button>
                     <button onClick={openTransferModal} className="bg-purple-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-purple-700"><ArrowRightLeft size={16}/> Transferência</button>
                     <button onClick={() => { setEditingId(null); setTxForm({ type: 'EXPENSE', status: 'PENDING', date: new Date().toISOString().split('T')[0] }); setIsTxModalOpen(true); }} className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-blue-700"><Plus size={16}/> Nova Transação</button>
                  </div>
               </div>

               <TransactionTable 
                  transactions={transactionsByDateRange.filter(t => t.status === 'PENDING' && (selectedBankFilter ? t.bankId === selectedBankFilter : true))}
                  appData={data}
                  showBalance={false}
                  viewType="PENDING"
                  isSelectable={true}
                  selectedIds={selectedTxIds}
                  onToggleSelectAll={toggleSelectAll}
                  onToggleSelectOne={toggleSelectOne}
                  onEdit={(tx) => { setTxForm(tx); setEditingId(tx.id); setIsTxModalOpen(true); }}
                  onDelete={confirmDelete.bind(null, 'TRANSACTION')}
                  onPay={markAsPaid}
                  calculateRunningBalances={{}}
               />
            </div>
         }

         {currentView === 'PAYABLES' && 
            <div className="space-y-4">
               <div className="flex flex-col md:flex-row gap-4 mb-4 bg-white p-4 rounded-xl shadow-sm items-end">
                  <div className="w-full md:w-64"><SearchableSelect options={[{id: '', label: 'Todos os Bancos'}, ...filteredBanks.map(b => ({id: b.id, label: b.name}))]} value={selectedBankFilter} onChange={setSelectedBankFilter} placeholder="Filtrar Banco" /></div>

                  {/* Date Filter */}
                  <div className="flex gap-2 items-center">
                    <div>
                        <label className="text-xs font-semibold text-gray-500 mb-1 block">Início</label>
                        <input type="date" className="border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-700 outline-none focus:ring-2 focus:ring-blue-500 bg-white" value={dateFilter.start} onChange={e => setDateFilter(prev => ({...prev, start: e.target.value}))} />
                    </div>
                    <div>
                        <label className="text-xs font-semibold text-gray-500 mb-1 block">Fim</label>
                        <input type="date" className="border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-700 outline-none focus:ring-2 focus:ring-blue-500 bg-white" value={dateFilter.end} onChange={e => setDateFilter(prev => ({...prev, end: e.target.value}))} />
                    </div>
                    {(dateFilter.start || dateFilter.end) && <button onClick={() => setDateFilter({start:'', end:''})} className="text-xs text-red-500 hover:underline mt-6">Limpar</button>}
                  </div>

                  {/* Bulk Actions Info */}
                  {selectedTxIds.size > 0 && (
                     <div className="flex items-center gap-4 bg-blue-50 px-4 py-2 rounded-lg border border-blue-100 animate-fade-in mb-1 md:mb-0">
                        <span className="text-sm font-semibold text-blue-800">{selectedTxIds.size} selecionado(s)</span>
                        <button onClick={handleBulkDelete} className="text-red-600 hover:text-red-800 text-sm font-bold flex items-center gap-1"><Trash2 size={14}/> Excluir Selecionados</button>
                     </div>
                  )}

                  <div className="flex-1 flex justify-end gap-2">
                     <button onClick={() => openImportModal('TRANSACTION')} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-gray-50"><Upload size={16}/> Importar</button>
                     <button onClick={openTransferModal} className="bg-purple-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-purple-700"><ArrowRightLeft size={16}/> Transferência</button>
                     <button onClick={() => { setEditingId(null); setTxForm({ type: 'EXPENSE', status: 'PAID', date: new Date().toISOString().split('T')[0] }); setIsTxModalOpen(true); }} className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-blue-700"><Plus size={16}/> Nova Transação</button>
                  </div>
               </div>

               <TransactionTable 
                  transactions={transactionsByDateRange.filter(t => (selectedBankFilter ? t.bankId === selectedBankFilter : true) && t.status === 'PAID')}
                  appData={data}
                  showBalance={!!selectedBankFilter}
                  viewType="PAID"
                  isSelectable={true}
                  selectedIds={selectedTxIds}
                  onToggleSelectAll={toggleSelectAll}
                  onToggleSelectOne={toggleSelectOne}
                  onEdit={(tx) => { setTxForm(tx); setEditingId(tx.id); setIsTxModalOpen(true); }}
                  onDelete={confirmDelete.bind(null, 'TRANSACTION')}
                  onPay={markAsPaid}
                  calculateRunningBalances={calculateRunningBalances}
               />
            </div>
         }

         {currentView === 'WALLETS' && renderGenericList('Gerenciar Carteiras', data.wallets, 'WALLET', [{key:'name', label:'Nome'}])}
         {currentView === 'BANKS' && renderGenericList('Bancos', filteredBanks, 'BANK', [{key:'name', label:'Nome'}, {key:'balance', label:'Saldo Inicial'}, {key:'initialDate', label:'Data Inicial'}])}
         {currentView === 'CATEGORIES' && renderGenericList('Categorias', data.categories, 'CATEGORY', [{key:'name', label:'Nome'}])}
         {currentView === 'COST_CENTERS' && renderGenericList('Centros de Custo', data.costCenters, 'COST', [{key:'name', label:'Nome'}])}
         {currentView === 'PARTICIPANTS' && renderGenericList('Participantes', data.participants, 'PARTICIPANT', [{key:'name', label:'Nome'}])}
         {currentView === 'SETTINGS' && (
             <div className="space-y-6">
                 {dbError && <div className="p-4 bg-red-100 text-red-800 rounded-lg">Atenção: Banco de dados desatualizado. Copie o SQL abaixo e execute no Supabase.</div>}
                 <div className="bg-white p-6 rounded-xl border border-gray-100">
                     <h3 className="font-bold mb-4">Conexão Supabase</h3>
                     <input className={INPUT_STYLE} placeholder="URL" value={configForm.url} onChange={e => setConfigForm({...configForm, url: e.target.value})} />
                     <input className={`${INPUT_STYLE} mt-2`} type="password" placeholder="Key" value={configForm.key} onChange={e => setConfigForm({...configForm, key: e.target.value})} />
                     <div className="mt-4 flex gap-2"><button onClick={handleSaveConfig} className="bg-emerald-600 text-white px-4 py-2 rounded">Salvar</button>{!isDemoMode && <button onClick={handleDisconnect} className="text-red-600">Desconectar</button>}</div>
                 </div>
                 <div className="bg-gray-900 text-gray-300 p-4 rounded-xl"><div className="flex justify-between mb-2"><span className="font-bold">SQL Schema</span><button onClick={copySqlToClipboard} className="text-xs bg-gray-700 px-2 py-1 rounded">{copiedSql ? 'Copiado!' : 'Copiar'}</button></div><pre className="text-xs overflow-x-auto">{DB_SCHEMA_SQL}</pre></div>
             </div>
         )}
      </main>

      {/* --- MODALS --- */}

      {/* Confirmation Modal */}
      <Modal isOpen={confirmModal.isOpen} onClose={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))} title={confirmModal.title} maxWidth="sm">
          <div className="space-y-6">
              <p className="text-gray-600">{confirmModal.message}</p>
              <div className="flex gap-4 justify-end">
                  <button onClick={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))} className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 font-medium">Não</button>
                  <button onClick={confirmModal.onConfirm} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-medium">Sim, excluir</button>
              </div>
          </div>
      </Modal>

      <Modal isOpen={genericModalOpen} onClose={() => { setGenericModalOpen(false); setEditingId(null); }} title={editingId ? "Editar" : "Novo"} maxWidth="md">
         <div className="space-y-4">
            <div><label className={LABEL_STYLE}>Nome</label><input type="text" className={INPUT_STYLE} value={genericForm.name || ''} onChange={e => setGenericForm({...genericForm, name: e.target.value})} /></div>

            {/* Campo Carteira no Banco */}
            {genericModalType === 'BANK' && (
              <div className="space-y-4">
                 <div>
                    <label className={LABEL_STYLE}>Carteira (Vínculo)</label>
                    <select className={INPUT_STYLE} value={genericForm.walletId || ''} onChange={e => setGenericForm({...genericForm, walletId: e.target.value})}>
                        <option value="">Nenhuma (Global)</option>
                        {data.wallets.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
                    </select>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className={LABEL_STYLE}>Saldo Atual (Inicial)</label>
                        <div className="flex">
                            <button
                                onClick={() => {
                                    const currentVal = genericForm.balance || 0;
                                    setGenericForm({ ...genericForm, balance: currentVal * -1 });
                                }}
                                className={`px-3 py-3 border border-r-0 rounded-l-lg font-bold transition-colors ${
                                    (genericForm.balance || 0) < 0 
                                    ? 'bg-red-50 text-red-600 border-red-200' 
                                    : 'bg-green-50 text-green-600 border-green-200'
                                }`}
                                title="Alternar entre Positivo e Negativo"
                            >
                                {(genericForm.balance || 0) < 0 ? '-' : '+'}
                            </button>
                            <div className="flex-1">
                                 <CurrencyInput 
                                    value={Math.abs(genericForm.balance || 0)} 
                                    onChange={(v) => {
                                         const isNegative = (genericForm.balance || 0) < 0;
                                         setGenericForm({ ...genericForm, balance: isNegative ? -v : v });
                                    }}
                                    className="rounded-l-none" 
                                 />
                            </div>
                        </div>
                        <p className="text-[10px] text-gray-400 mt-1">Defina manualmente o saldo atual da conta.</p>
                    </div>
                    <div><label className={LABEL_STYLE}>Data de Referência</label><input type="date" className={INPUT_STYLE} value={genericForm.initialDate || ''} onChange={e => setGenericForm({...genericForm, initialDate: e.target.value})} /></div>
                 </div>
              </div>
            )}

            <button onClick={handleGenericSave} className="w-full bg-blue-600 text-white py-3 rounded-lg font-medium hover:bg-blue-700">{editingId ? 'Salvar' : 'Criar'}</button>
         </div>
      </Modal>

      <Modal isOpen={isTxModalOpen} onClose={() => { setIsTxModalOpen(false); setEditingId(null); }} title={editingId ? "Editar Transação" : "Nova Transação"} maxWidth="4xl">
          <div className="space-y-4 pb-10">

             {/* Tipo de Transação (Débito/Crédito) */}
             <div className="flex gap-4 mb-4">
                <button 
                  className={`flex-1 py-3 rounded-lg font-bold border transition-colors ${txForm.type === 'EXPENSE' ? 'bg-red-50 border-red-200 text-red-700 ring-2 ring-red-100' : 'bg-white border-gray-200 text-gray-400 hover:bg-gray-50'}`}
                  onClick={() => setTxForm({...txForm, type: 'EXPENSE'})}
                >
                  <div className="flex items-center justify-center gap-2">
                    <TrendingDown size={20}/> Débito (Saída)
                  </div>
                </button>
                <button 
                  className={`flex-1 py-3 rounded-lg font-bold border transition-colors ${txForm.type === 'INCOME' ? 'bg-green-50 border-green-200 text-green-700 ring-2 ring-green-100' : 'bg-white border-gray-200 text-gray-400 hover:bg-gray-50'}`}
                  onClick={() => setTxForm({...txForm, type: 'INCOME'})}
                >
                  <div className="flex items-center justify-center gap-2">
                    <TrendingUp size={20}/> Crédito (Entrada)
                  </div>
                </button>
             </div>

             <div className="grid grid-cols-2 gap-4">
                <div><label className={LABEL_STYLE}>Data</label><input type="date" className={INPUT_STYLE} value={txForm.date} onChange={e => setTxForm({...txForm, date: e.target.value})} /></div>
                <div><label className={LABEL_STYLE}>Status</label><select className={INPUT_STYLE} value={txForm.status} onChange={e => setTxForm({...txForm, status: e.target.value as any})} disabled={!!editingId && txForm.status === 'PAID'}><option value="PENDING">Pendente</option><option value="PAID">Pago</option></select></div>
             </div>

             <div className="grid grid-cols-2 gap-4">
                <div><label className={LABEL_STYLE}>Nº Documento</label><input className={INPUT_STYLE} value={txForm.documentNumber || ''} onChange={e => setTxForm({...txForm, documentNumber: e.target.value})} placeholder="Opcional" /></div>
                <div><label className={LABEL_STYLE}>Banco</label><SearchableSelect options={filteredBanks.map(b => ({id: b.id, label: b.name}))} value={txForm.bankId || ''} onChange={(v) => setTxForm({...txForm, bankId: v})} placeholder="Selecione..." disabled={!!editingId && txForm.status === 'PAID'} /></div>
             </div>

             <div className="grid grid-cols-3 gap-4">
                <div><label className={LABEL_STYLE}>Categoria</label><SearchableSelect options={data.categories.map(c => ({id: c.id, label: c.name}))} value={txForm.categoryId || ''} onChange={(v) => setTxForm({...txForm, categoryId: v})} placeholder="Selecione..." /></div>
                <div><label className={LABEL_STYLE}>Centro de Custo</label><SearchableSelect options={data.costCenters.map(c => ({id: c.id, label: c.name}))} value={txForm.costCenterId || ''} onChange={(v) => setTxForm({...txForm, costCenterId: v})} placeholder="Selecione... (Opcional)" /></div>
                <div><label className={LABEL_STYLE}>Participante</label><SearchableSelect options={data.participants.map(p => ({id: p.id, label: p.name}))} value={txForm.participantId || ''} onChange={(v) => setTxForm({...txForm, participantId: v})} placeholder="Selecione..." /></div>
             </div>

             <div><label className={LABEL_STYLE}>Descrição (Opcional)</label><input className={INPUT_STYLE} value={txForm.description || ''} onChange={e => setTxForm({...txForm, description: e.target.value})} /></div>

             {/* Parcelamento Lógica */}
