// Helper para garantir que strings vazias virem NULL no banco de dados
const sanitizeUuid = (id: string | undefined | null) => {
  if (!id) return null;
  if (typeof id !== 'string') return null;
  const trimmed = id.trim();
  return trimmed === '' ? null : trimmed;
};

// Helper para strings opcionais (ex: Document Number)
const sanitizeString = (str: string | undefined | null) => {
  if (!str) return null;
  const trimmed = str.trim();
  return trimmed === '' ? null : trimmed;
};

// Helper para formatar erros do Supabase de forma legível
const handleSupabaseError = (error: any, context: string) => {
  console.error(`Erro em ${context}:`, error);

  if (error.code === '22P02') {
    throw new Error(`Erro de dados: Um dos itens selecionados possui um ID inválido. Recarregue a página.`);
  }

  const msg = error.message || error.details || error.hint || JSON.stringify(error);

  // Detecta erros de coluna ou tabela faltando
  if ((msg.includes("Could not find the") && (msg.includes("column") || msg.includes("table"))) || 
       msg.includes("relation \"public.wallets\" does not exist")) {
     throw new Error(`O banco de dados está desatualizado. Vá em 'Configurações', copie o SQL atualizado e execute no Supabase.`);
  }

  throw new Error(`Erro ao ${context}: ${msg}`);
};

export const dataService = {
  async checkDatabaseHealth(): Promise<boolean> {
    if (!isSupabaseConfigured()) return true; 

    // Check 1: Novas colunas na tabela transactions e banks
    const { error: txError } = await supabase
      .from('banks')
      .select('initial_date')
      .limit(1);

    if (txError && (txError.message.includes('column') || txError.code === '42703')) {
      return false;
    }

    // Check 2: Existência da tabela wallets
    const { error: walletError } = await supabase
      .from('wallets')
      .select('id')
      .limit(1);

    if (walletError) {
      return false;
    }

    return true;
  },

  async getInitialData(): Promise<AppData> {
    if (!isSupabaseConfigured()) {
      return INITIAL_DATA;
    }

    try {
      // Aumentado o range para garantir que histórico antigo seja carregado (padrão do supabase é 1000)
      const [walletsRes, banksRes, catsRes, costsRes, partsRes, transRes] = await Promise.all([
        supabase.from('wallets').select('*').order('name'),
        supabase.from('banks').select('*').order('name'),
        supabase.from('categories').select('*').order('name'),
        supabase.from('cost_centers').select('*').order('name'),
        supabase.from('participants').select('*').order('name'),
        supabase.from('transactions').select('*').order('date', { ascending: false }).range(0, 9999)
      ]);

      if (walletsRes.error) handleSupabaseError(walletsRes.error, 'buscar carteiras');
      if (banksRes.error) handleSupabaseError(banksRes.error, 'buscar bancos');
      if (catsRes.error) handleSupabaseError(catsRes.error, 'buscar categorias');
      if (costsRes.error) handleSupabaseError(costsRes.error, 'buscar centros de custo');
      if (partsRes.error) handleSupabaseError(partsRes.error, 'buscar participantes');
      if (transRes.error) handleSupabaseError(transRes.error, 'buscar transações');

      return {
        wallets: (walletsRes.data || []).map(mapWallet),
        banks: (banksRes.data || []).map(mapBank),
        categories: (catsRes.data || []).map(mapCategory),
        costCenters: (costsRes.data || []).map(mapCostCenter),
        participants: (partsRes.data || []).map(mapParticipant),
        transactions: (transRes.data || []).map(mapTransaction),
      };

    } catch (error) {
      console.error("Erro ao conectar ao Supabase.", error);
      // Retorna INITIAL_DATA apenas se falhar totalmente, mas geralmente queremos que o App.tsx mostre o erro de banco desatualizado
      return INITIAL_DATA;
    }
  },

