  async createTransaction(tx: Omit<Transaction, 'id' | 'createdAt'>) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo.");

    // Sanitização rigorosa para evitar erro de tipo do Supabase
    const payload = {
      description: tx.description,
      amount: tx.amount,
      date: tx.date,
      type: tx.type,
      status: tx.status,
      bank_id: sanitizeUuid(tx.bankId),
      category_id: sanitizeUuid(tx.categoryId),
      cost_center_id: sanitizeUuid(tx.costCenterId),
      participant_id: sanitizeUuid(tx.participantId),
      document_number: sanitizeString(tx.documentNumber),
      installment_number: tx.installmentNumber ?? null, // Garante NULL se undefined
      installment_total: tx.installmentTotal ?? null,   // Garante NULL se undefined
      history: tx.history,
      related_transaction_id: sanitizeUuid(tx.relatedTransactionId)
    };

    const { data, error } = await supabase.from('transactions').insert([payload]).select();

    if (error) handleSupabaseError(error, 'criar transação');

    if (tx.status === 'PAID' && tx.bankId) {
      try {
        await updateBankBalance(tx.bankId, tx.amount, tx.type === 'INCOME');
      } catch (err) {
        console.warn("Transação criada, mas erro ao atualizar saldo:", err);
      }
    }
    return mapTransaction(data[0]);
  },

  async createInstallments(baseTx: Omit<Transaction, 'id' | 'createdAt'>, count: number) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo.");

    const transactionsToInsert = [];

    // Lógica Robusta de Datas
    const [yearStr, monthStr, dayStr] = baseTx.date.split('-');
    const startYear = parseInt(yearStr);
    const startMonth = parseInt(monthStr) - 1; 
    const startDay = parseInt(dayStr);

    for (let i = 0; i < count; i++) {
       const targetDate = new Date(startYear, startMonth + i, 1);
       const daysInMonth = new Date(targetDate.getFullYear(), targetDate.getMonth() + 1, 0).getDate();
       const finalDay = Math.min(startDay, daysInMonth);
       targetDate.setDate(finalDay);

       const y = targetDate.getFullYear();
       const m = String(targetDate.getMonth() + 1).padStart(2, '0');
       const d = String(targetDate.getDate()).padStart(2, '0');
       const dateStr = `${y}-${m}-${d}`;

       const installmentNum = i + 1;
       const description = `${baseTx.description} (${installmentNum}/${count})`;

       transactionsToInsert.push({
          description: description,
          amount: baseTx.amount,
          date: dateStr,
          type: baseTx.type,
          status: 'PENDING',
          bank_id: sanitizeUuid(baseTx.bankId),
          category_id: sanitizeUuid(baseTx.categoryId),
          cost_center_id: sanitizeUuid(baseTx.costCenterId),
          participant_id: sanitizeUuid(baseTx.participantId),
          document_number: sanitizeString(baseTx.documentNumber),
          installment_number: installmentNum,
          installment_total: count,
          history: [{ date: new Date().toISOString(), message: 'Parcela criada automaticamente', user: 'System' }],
       });
    }

    const { error } = await supabase.from('transactions').insert(transactionsToInsert);
    if (error) handleSupabaseError(error, 'criar parcelas');
  },

  async updateTransaction(id: string, tx: Partial<Transaction>) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo");

    const payload: any = {
      description: tx.description,
      date: tx.date,
      document_number: sanitizeString(tx.documentNumber),
      amount: tx.amount,
      bank_id: sanitizeUuid(tx.bankId),
      type: tx.type,
      status: tx.status,
      category_id: sanitizeUuid(tx.categoryId),
      cost_center_id: sanitizeUuid(tx.costCenterId),
      participant_id: sanitizeUuid(tx.participantId),
      installment_number: tx.installmentNumber,
      installment_total: tx.installmentTotal,
    };

    const { error } = await supabase.from('transactions').update(payload).eq('id', id);
    if (error) handleSupabaseError(error, 'atualizar transação');
  },

  async updateInstallmentBatch(id: string, updates: Partial<Transaction>) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo");

    const { data: original, error: fetchError } = await supabase
      .from('transactions').select('description').eq('id', id).single();

    if (fetchError || !original) throw new Error("Transação original não encontrada.");

    const match = original.description.match(/^(.*) \(\d+\/\d+\)$/);
    if (!match) return this.updateTransaction(id, updates);

    const baseName = match[1];
    const payload: any = {};
    if (updates.amount) payload.amount = updates.amount;
    if (updates.bankId) payload.bank_id = sanitizeUuid(updates.bankId);
    if (updates.categoryId !== undefined) payload.category_id = sanitizeUuid(updates.categoryId);
    if (updates.participantId !== undefined) payload.participant_id = sanitizeUuid(updates.participantId);
    if (updates.costCenterId !== undefined) payload.cost_center_id = sanitizeUuid(updates.costCenterId);
    if (updates.type) payload.type = updates.type;

    const searchPattern = `${baseName} (%`;

    const { error } = await supabase
      .from('transactions')
      .update(payload)
      .ilike('description', searchPattern) 
      .eq('status', 'PENDING');

    if (error) handleSupabaseError(error, 'atualizar parcelas em lote');
  },

  async createTransfer(amount: number, date: string, fromBankId: string, toBankId: string, description: string, participantId?: string, categoryId?: string) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo.");

    const { data: txOutData, error: errOut } = await supabase.from('transactions').insert([{
      description: description || `Transferência enviada`,
      amount: amount,
      date: date,
      type: 'EXPENSE',
      status: 'PAID',
      bank_id: sanitizeUuid(fromBankId),
      participant_id: sanitizeUuid(participantId),
      category_id: sanitizeUuid(categoryId),
      history: [{ date: new Date().toISOString(), message: 'Transferência enviada', user: 'System' }]
    }]).select();

    if (errOut) handleSupabaseError(errOut, 'criar transferência (saída)');
    const txOutId = txOutData[0].id;

    const { data: txInData, error: errIn } = await supabase.from('transactions').insert([{
      description: description || `Transferência recebida`,
      amount: amount,
      date: date,
      type: 'INCOME',
      status: 'PAID',
      bank_id: sanitizeUuid(toBankId),
      related_transaction_id: txOutId,
      participant_id: sanitizeUuid(participantId),
      category_id: sanitizeUuid(categoryId),
      history: [{ date: new Date().toISOString(), message: 'Transferência recebida', user: 'System' }]
    }]).select();

    if (errIn) handleSupabaseError(errIn, 'criar transferência (entrada)');
    const txInId = txInData[0].id;

    await supabase.from('transactions').update({ related_transaction_id: txInId }).eq('id', txOutId);

    try {
      await updateBankBalance(fromBankId, amount, false);
      await updateBankBalance(toBankId, amount, true);
    } catch (err) {
      console.warn("Erro ao atualizar saldos na transferência:", err);
    }
  },

  async markAsPaid(tx: Transaction) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo.");

    const newHistory = [...(tx.history || []), { date: new Date().toISOString(), message: 'Marcado como pago', user: 'Usuario' }];
    const { error } = await supabase.from('transactions').update({ status: 'PAID', history: newHistory }).eq('id', tx.id);
    if (error) handleSupabaseError(error, 'marcar como pago');

    try {
      await updateBankBalance(tx.bankId, tx.amount, tx.type === 'INCOME');
    } catch (err) {
      console.warn("Erro ao atualizar saldo ao pagar:", err);
    }
  },

  async deleteItem(table: 'wallets'|'banks'|'categories'|'cost_centers'|'participants'|'transactions', id: string) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo.");

    // Se for transação, verifica se tem uma relacionada (transferência) e apaga ela também
    if (table === 'transactions') {
      try {
        const { data: tx } = await supabase
          .from('transactions')
          .select('related_transaction_id')
          .eq('id', id)
          .single();

        if (tx && tx.related_transaction_id) {
           await supabase.from('transactions').delete().eq('id', tx.related_transaction_id);
        } else {
            // Check if this transaction is referred to by another transaction (reverse link)
            const { data: reverseTx } = await supabase
                .from('transactions')
                .select('id')
                .eq('related_transaction_id', id)
                .single();

            if (reverseTx) {
                await supabase.from('transactions').delete().eq('id', reverseTx.id);
            }
        }
      } catch (e) {
        console.warn("Erro ao tentar remover transação relacionada (talvez não exista):", e);
      }
    }

    const { error } = await supabase.from(table).delete().eq('id', id);
    if (error) handleSupabaseError(error, 'excluir item');
  },

  async deleteTransactionsBatch(ids: string[]) {
    if (!isSupabaseConfigured()) throw new Error("Modo Demo.");
    if (ids.length === 0) return;
    const { error } = await supabase.from('transactions').delete().in('id', ids);
    if (error) handleSupabaseError(error, 'excluir transações em lote');
  }
};

async function updateBankBalance(bankId: string, amount: number, isIncome: boolean) {
  if (!isSupabaseConfigured()) return;
  const { data: bank, error } = await supabase.from('banks').select('balance').eq('id', bankId).single();
  if (error || !bank) return;

  const newBalance = isIncome ? Number(bank.balance) + Number(amount) : Number(bank.balance) - Number(amount);
  await supabase.from('banks').update({ balance: newBalance }).eq('id', bankId);
}

// Mappers
const mapWallet = (w: any): Wallet => ({ id: w.id, name: w.name });
const mapBank = (b: any): Bank => ({
  id: b.id, name: b.name, balance: Number(b.balance), initialDate: b.initial_date, color: b.color, accountNumber: b.account_number, walletId: b.wallet_id
});
const mapCategory = (c: any): Category => ({ id: c.id, name: c.name, type: c.type });
const mapCostCenter = (c: any): CostCenter => ({ id: c.id, name: c.name, code: c.code });
const mapParticipant = (p: any): Participant => ({ id: p.id, name: p.name, type: p.type, document: p.document });
const mapTransaction = (t: any): Transaction => ({
  id: t.id, description: t.description, amount: Number(t.amount), date: t.date, type: t.type, status: t.status,
  bankId: t.bank_id, categoryId: t.category_id, costCenterId: t.cost_center_id, participantId: t.participant_id,
  relatedTransactionId: t.related_transaction_id, documentNumber: t.document_number,
  installmentNumber: t.installment_number, installmentTotal: t.installment_total,
  history: typeof t.history === 'string' ? JSON.parse(t.history) : (t.history || []), createdAt: t.created_at
});

