                {cols.map(c => <td key={c.key} className="px-6 py-4">{c.key === 'balance' ? `R$ ${item[c.key]?.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : c.key === 'initialDate' ? (item[c.key] ? new Date(item[c.key]).toLocaleDateString('pt-BR') : '-') : item[c.key]}</td>)}
