import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, useLocation, Link } from 'react-router-dom';
import { LayoutDashboard, PlusCircle, Table, Calculator, Menu, X, PiggyBank, List, Settings as SettingsIcon, Cloud, CloudOff, TrendingUp, AlertCircle, FileBarChart, Building2, Briefcase, BookOpen, ShoppingBag, FileText } from 'lucide-react';

