        </button>
      </div>

      <nav className="mt-8 px-4 flex flex-col gap-2">
        <Link to="/" className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${isActive('/')}`}>
          <LayoutDashboard size={20} />
          <span className="font-medium">Dashboard</span>
