        <Link to="/quotas" className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${isActive('/quotas')}`}>
          <List size={20} />
          <span className="font-medium">Minhas Cotas</span>
        </Link>

        <Link to="/new" className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${isActive('/new')}`}>
          <PlusCircle size={20} />
          <span className="font-medium">Novo Cadastro</span>
