          </div>
        </header>

        <main className="p-4 md:p-8 flex-1 overflow-y-auto print:p-0 print:overflow-visible">
          {children}
        </main>
      </div>
    </div>
  );
};

const App = () => {
  return (
    <ConsortiumProvider>
      <HashRouter>
        <Layout>
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/quotas" element={<QuotaList />} />
            <Route path="/new" element={<NewQuota />} />
            <Route path="/edit/:id" element={<NewQuota />} />
