            <Route path="/calculator" element={<CalculatorTool />} />
            <Route path="/settings" element={<Settings />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </Layout>
      </HashRouter>
    </ConsortiumProvider>
  );
};

export default App;

import React, { useEffect, useState, useMemo } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { generateSchedule, calculateCDICorrection } from '../services/calculationService';
import { db } from '../services/database';
import { FileBarChart, Loader, AlertTriangle, Filter, CheckCircle2, Clock, Sheet, Calendar, ArrowUpDown, ArrowUp, ArrowDown } from 'lucide-react';

interface ReportRow {
  id: string;
  group: string;
  quotaNumber: string;
  creditValue: number;
  isContemplated: boolean;

  // Filtering relations
  administratorId?: string;
  companyId?: string;

  // Calculated Fields
  valoresAPagar: number; // Formerly Saldo Devedor (Future)
  percentAPagar: number;

  totalDevido: number; // Formerly Matured (Past + Bids) - Now displayed as "Total Pago"
  percentTotalDevido: number; // Now displayed as "% Pago"

  // Bid Fields
  bidTotal: number;
  percentBidTotal: number;
  bidFree: number;
  percentBidFree: number;
  bidEmbedded: number;
  percentBidEmbedded: number;

  // Manual & Finals
  valorRealCarta: number;
  creditManualAdjustment: number;
  creditoTotal: number;
  bidFreeCorrection: number; // Calculated, not manual anymore

  // NEW FIELDS
  creditoUtilizado: number;
  saldoDisponivel: number;
}

const Reports = () => {
  const { quotas, indices, updateQuota, administrators, companies, allCreditUsages } = useConsortium();
  const [reportData, setReportData] = useState<ReportRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<{ id: string, field: 'credit' } | null>(null);
  const [editValue, setEditValue] = useState('');
  const [saveError, setSaveError] = useState<string | null>(null);

  // Filters State
  const [filterAdmin, setFilterAdmin] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterStatus, setFilterStatus] = useState(''); // '' | 'CONTEMPLATED' | 'ACTIVE'

  // Date Reference Filter (Closing Date)
  const [referenceDate, setReferenceDate] = useState(new Date().toISOString().split('T')[0]);

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: keyof ReportRow, direction: 'asc' | 'desc' } | null>(null);

  // Helper for "Clean" formatting (No R$, No %, 2 Decimals)
  const formatNumber = (val: number) => {
    return val.toLocaleString('pt-BR', { 
      minimumFractionDigits: 2, 
      maximumFractionDigits: 2 
    });
  };

  useEffect(() => {
    const buildReport = async () => {
      setLoading(true);

      // Use the selected Reference Date instead of Today
      const refDateStr = referenceDate;

      try {
        // Fetch all payments details (including manual fields)
        const allPayments = await db.getAllPaymentsDictionary();

        const rows = quotas.map(quota => {
          // Generate schedule (Source of Truth)
          const schedule = generateSchedule(quota, indices);

          // 1. EXTRACT CORRECTED CREDIT VALUE DIRECTLY FROM SCHEDULE (Consistency with Simulator)
          // Uses referenceDate to find the credit value AT THAT TIME
          let currentCredit = quota.creditValue;
          if (schedule.length > 0) {
             const pastOrPresent = schedule.filter(i => i.dueDate.split('T')[0] <= refDateStr);
             if (pastOrPresent.length > 0) {
                 currentCredit = pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || quota.creditValue;
             } else {
                 // If reference date is before first due date, use base value
                 currentCredit = quota.creditValue;
             }
          }

          let sumMatured = 0;
          let sumFuture = 0;

          // Get payment data for this quota from the bulk fetch
          const paymentMap = allPayments[quota.id] || {};

          // Logic matched with Simulation Summary Statement
          schedule.forEach(inst => {
              const instDateStr = inst.dueDate.split('T')[0];
              // Determines maturity based on Reference Date
              const isMatured = instDateStr <= refDateStr;
              const paymentData = paymentMap[inst.installmentNumber];

              if (isMatured) {
                  // Matured: FC + FR + TA + Fines + Interest
                  // If manual values exist in DB, they override calculated ones in the "Total Devido" concept
                  // or rather, Total Devido reflects what WAS expected/charged.
                  // Simulator Summary "Paid" side includes Manual Fine/Interest if present.

                  const fine = paymentData?.manualFine || inst.manualFine || 0;
                  const interest = paymentData?.manualInterest || inst.manualInterest || 0;

                  sumMatured += inst.commonFund + inst.reserveFund + inst.adminFee + fine + interest;
              } else {
                  // Future: FC + FR + TA
                  sumFuture += inst.commonFund + inst.reserveFund + inst.adminFee;
              }

              // Bid Logic: In Summary Statement, Bid Abatements are added to the "Paid/Matured" side
              if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
                  sumMatured += (inst.bidAbatementFC || 0) + (inst.bidAbatementFR || 0) + (inst.bidAbatementTA || 0);
              }
          });

          const totalContractValue = sumMatured + sumFuture || 1; // Avoid division by zero

          const bidEmbedded = quota.bidEmbedded || 0;
          const manualAdj = quota.creditManualAdjustment || 0;

          // --- CALCULATE CDI CORRECTION AUTOMATICALLY ---
          // Based on Bid Free Amount + Contemplation Date + Registered CDI Indices
          const correction92CDI = calculateCDICorrection(
              quota.bidFree || 0,
              quota.contemplationDate,
              indices
          );

          // Valor Real (Net) = Corrected Credit - Embedded Bid
          const valorLiquido = currentCredit - bidEmbedded;
          const creditoTotal = valorLiquido + manualAdj;

          // Calculate Credit Usage (Filter usages by reference date as well)
          const quotaUsages = allCreditUsages.filter(u => u.quotaId === quota.id && u.date <= refDateStr);
          const creditoUtilizado = quotaUsages.reduce((sum, u) => sum + u.amount, 0);
          const saldoDisponivel = creditoTotal - creditoUtilizado;

          return {
            id: quota.id,
            group: quota.group,
            quotaNumber: quota.quotaNumber,
            creditValue: currentCredit, // Matches Simulator
            isContemplated: quota.isContemplated,
            administratorId: quota.administratorId,
            companyId: quota.companyId,

            // "Valores a Pagar" (formerly Saldo Devedor Future)
            valoresAPagar: sumFuture,
            percentAPagar: (sumFuture / totalContractValue) * 100,

            // "Total Devido" which is now rendered as "Total Pago"
            totalDevido: sumMatured, 
            percentTotalDevido: (sumMatured / totalContractValue) * 100,

            bidTotal: quota.bidTotal || 0,
            percentBidTotal: currentCredit > 0 ? ((quota.bidTotal || 0) / currentCredit) * 100 : 0,

            bidFree: quota.bidFree || 0,
            percentBidFree: currentCredit > 0 ? ((quota.bidFree || 0) / currentCredit) * 100 : 0,

            bidEmbedded: bidEmbedded,
            percentBidEmbedded: currentCredit > 0 ? (bidEmbedded / currentCredit) * 100 : 0,

            valorRealCarta: valorLiquido,
            creditManualAdjustment: manualAdj,
            creditoTotal: creditoTotal,
            bidFreeCorrection: correction92CDI,

            creditoUtilizado,
            saldoDisponivel
          };
        });
        setReportData(rows);
      } catch (err) {
        console.error("Failed to build report", err);
      } finally {
        setLoading(false);
      }
    };

    buildReport();
  }, [quotas, indices, allCreditUsages, referenceDate]); // Added referenceDate dependency

  const handleEditClick = (id: string, field: 'credit', currentVal: number) => {
    setEditingId({ id, field });
    setEditValue(currentVal.toFixed(2).replace('.', ','));
    setSaveError(null);
  };

  const handleSaveEdit = async () => {
    if (!editingId) return;

    // Replace comma with dot for parsing
    const normalizedValue = editValue.replace(/\./g, '').replace(',', '.');
    const newVal = parseFloat(normalizedValue);

    if (isNaN(newVal)) {
        setEditingId(null);
        return;
    }

    const quota = quotas.find(q => q.id === editingId.id);
    if (quota) {
      try {
        if (editingId.field === 'credit') {
            await updateQuota({ ...quota, creditManualAdjustment: newVal });
        }
        // Correction is now automatic, no saving needed for that field
        setEditingId(null);
      } catch (error: any) {
        console.error("Save failed", error);
        setSaveError("Erro ao salvar. Verifique se o Banco de Dados foi atualizado em Configurações.");
      }
    }
  };

  // --- FILTER LOGIC ---
  const filteredData = reportData.filter(row => {
    const matchAdmin = !filterAdmin || row.administratorId === filterAdmin;
    const matchComp = !filterCompany || row.companyId === filterCompany;

    let matchStatus = true;
    if (filterStatus === 'CONTEMPLATED') {
        matchStatus = row.isContemplated;
    } else if (filterStatus === 'ACTIVE') {
        matchStatus = !row.isContemplated;
    }

    return matchAdmin && matchComp && matchStatus;
  });

  // --- SORTING LOGIC ---
  const requestSort = (key: keyof ReportRow) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedData = useMemo(() => {
    let sortableItems = [...filteredData];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        // Special handling for quotaNumber (numeric sort even if string)
        if (sortConfig.key === 'quotaNumber') {
             const numA = parseInt(a.quotaNumber) || 0;
             const numB = parseInt(b.quotaNumber) || 0;
             if (numA < numB) return sortConfig.direction === 'asc' ? -1 : 1;
             if (numA > numB) return sortConfig.direction === 'asc' ? 1 : -1;
             return 0;
        }

        if (a[sortConfig.key] < b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (a[sortConfig.key] > b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
      });
    }
    return sortableItems;
  }, [filteredData, sortConfig]);


  // --- TOTALS CALCULATION ---
  const totals = sortedData.reduce((acc, row) => ({
    valoresAPagar: acc.valoresAPagar + row.valoresAPagar,
    totalDevido: acc.totalDevido + row.totalDevido,
    bidTotal: acc.bidTotal + row.bidTotal,
    bidFree: acc.bidFree + row.bidFree,
    bidEmbedded: acc.bidEmbedded + row.bidEmbedded,
    valorRealCarta: acc.valorRealCarta + row.valorRealCarta,
    creditManualAdjustment: acc.creditManualAdjustment + row.creditManualAdjustment,
    creditoTotal: acc.creditoTotal + row.creditoTotal,
    bidFreeCorrection: acc.bidFreeCorrection + row.bidFreeCorrection,
    creditoUtilizado: acc.creditoUtilizado + row.creditoUtilizado,
    saldoDisponivel: acc.saldoDisponivel + row.saldoDisponivel
  }), {
    valoresAPagar: 0,
    totalDevido: 0,
    bidTotal: 0,
    bidFree: 0,
    bidEmbedded: 0,
    valorRealCarta: 0,
    creditManualAdjustment: 0,
    creditoTotal: 0,
    bidFreeCorrection: 0,
    creditoUtilizado: 0,
    saldoDisponivel: 0
  });

  const handleExportExcel = () => {
    // Generate CSV content
    const header = [
        "Grupo",
        "Cota",
        "Empresa",
        "Valor Carta",
        "Valores a Pagar",
        "Total Pago",
        "Lance Total",
        "Lance Livre",
        "Lance Embutido",
        "Vlr Crédito Líquido",
        "Atualização",
        "Corr. 92% CDI",
        "Crédito Total",
        "Crédito Utilizado",
        "Saldo Disponível"
    ].join(";");

    const rows = sortedData.map(row => {
        const companyName = companies.find(c => c.id === row.companyId)?.name || '';

        // Helper to formatting number for CSV (using comma as decimal for PT-BR)
        const n = (val: number) => val.toFixed(2).replace('.', ',');

        return [
            row.group,
            `'${row.quotaNumber}`, // Prevent Excel from treating as number if it has leading zeros
            companyName,
            n(row.creditValue),
            n(row.valoresAPagar),
            n(row.totalDevido),
            n(row.bidTotal),
            n(row.bidFree),
            n(row.bidEmbedded),
            n(row.valorRealCarta),
            n(row.creditManualAdjustment),
            n(row.bidFreeCorrection),
            n(row.creditoTotal),
            n(row.creditoUtilizado),
            n(row.saldoDisponivel)
        ].join(";");
    }).join("\n");

    const csvContent = "\uFEFF" + header + "\n" + rows; // Add BOM for UTF-8 compatibility
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `relatorio_cotas_${referenceDate}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const SortHeader = ({ label, sortKey, align = 'right', className = '' }: { label: string, sortKey: keyof ReportRow, align?: 'left'|'right', className?: string }) => (
      <th 
        className={`px-2 py-1 cursor-pointer hover:bg-slate-800 transition-colors group select-none ${className} ${align === 'right' ? 'text-right' : 'text-left'}`}
        onClick={() => requestSort(sortKey)}
      >
        <div className={`flex items-center gap-1 ${align === 'right' ? 'justify-end' : 'justify-start'}`}>
            {label}
            <div className="flex flex-col opacity-50 group-hover:opacity-100">
                {sortConfig?.key === sortKey ? (
                    sortConfig.direction === 'asc' ? <ArrowUp size={10} /> : <ArrowDown size={10} />
                ) : (
                    <ArrowUpDown size={10} />
                )}
            </div>
        </div>
      </th>
  );

  return (
    // Negative margin to break out of parent padding for full width feel
    <div className="space-y-6 -mx-4 md:-mx-8 px-4 md:px-8 pb-10 print:m-0 print:p-0">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Relatório por Cota</h1>
           <p className="text-slate-500">Visão financeira detalhada de todas as cotas</p>
        </div>
        <div className="flex gap-2 self-start md:self-auto">
            <button 
                onClick={handleExportExcel} 
                className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition-colors font-medium flex items-center gap-2"
            >
                <Sheet size={18} /> Exportar Excel
            </button>
            <button 
                onClick={() => window.print()} 
                className="bg-slate-100 text-slate-600 px-4 py-2 rounded-lg hover:bg-slate-200 transition-colors font-medium print:hidden"
            >
                Imprimir
            </button>
        </div>
      </div>

      {saveError && (
        <div className="bg-red-50 text-red-700 p-3 rounded-lg flex items-center gap-2 border border-red-200">
           <AlertTriangle size={16} />
           {saveError}
        </div>
      )}

      {/* FILTERS */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 items-end print:hidden">
          <div className="flex-1 w-full md:w-auto">
             <label className="block text-xs font-semibold text-slate-500 mb-1 flex items-center gap-1">
                <Calendar size={12} /> Data de Referência (Fechamento)
             </label>
             <input 
                type="date"
                value={referenceDate}
                onChange={(e) => setReferenceDate(e.target.value)}
                className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
             />
          </div>
          <div className="flex-1 w-full md:w-auto">
             <label className="block text-xs font-semibold text-slate-500 mb-1 flex items-center gap-1">
                <Filter size={12}/> Administradora
             </label>
             <select 
                value={filterAdmin} 
                onChange={(e) => setFilterAdmin(e.target.value)}
                className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
             >
                <option value="">Todas</option>
                {administrators.map(a => (
                    <option key={a.id} value={a.id}>{a.name}</option>
                ))}
             </select>
          </div>
          <div className="flex-1 w-full md:w-auto">
             <label className="block text-xs font-semibold text-slate-500 mb-1 flex items-center gap-1">
                <Filter size={12}/> Empresa Compradora
             </label>
             <select 
                value={filterCompany} 
                onChange={(e) => setFilterCompany(e.target.value)}
                className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
             >
                <option value="">Todas</option>
                {companies.map(c => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                ))}
             </select>
          </div>
          <div className="flex-1 w-full md:w-auto">
             <label className="block text-xs font-semibold text-slate-500 mb-1 flex items-center gap-1">
                <Filter size={12}/> Status Cota
             </label>
             <select 
                value={filterStatus} 
                onChange={(e) => setFilterStatus(e.target.value)}
                className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
             >
                <option value="">Todas</option>
                <option value="CONTEMPLATED">Contempladas</option>
                <option value="ACTIVE">Em Andamento</option>
             </select>
          </div>

          {(filterAdmin || filterCompany || filterStatus || referenceDate !== new Date().toISOString().split('T')[0]) && (
              <button 
                onClick={() => { setFilterAdmin(''); setFilterCompany(''); setFilterStatus(''); setReferenceDate(new Date().toISOString().split('T')[0]); }}
                className="text-slate-500 hover:text-red-500 text-sm font-medium px-2 py-2"
              >
                Limpar Filtros
              </button>
          )}
      </div>

      {/* TOTALS SUMMARY */}
      {!loading && reportData.length > 0 && (
         <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-11 gap-2">
            {[
                { label: 'Valores a Pagar', value: totals.valoresAPagar, color: 'text-red-600', bg: 'bg-red-50' },
                { label: 'Total Pago', value: totals.totalDevido, color: 'text-emerald-600', bg: 'bg-emerald-50' },
                { label: 'Lance Total', value: totals.bidTotal, color: 'text-amber-600', bg: 'bg-amber-50' },
                { label: 'Lance Livre', value: totals.bidFree, color: 'text-slate-600', bg: 'bg-slate-50' },
                { label: 'Lance Embutido', value: totals.bidEmbedded, color: 'text-slate-600', bg: 'bg-slate-50' },
                { label: 'Vlr Crédito Líq.', value: totals.valorRealCarta, color: 'text-blue-600', bg: 'bg-blue-50' },
                { label: 'Atualização', value: totals.creditManualAdjustment, color: 'text-indigo-600', bg: 'bg-indigo-50' },
                { label: 'Corr. 92% CDI', value: totals.bidFreeCorrection, color: 'text-violet-600', bg: 'bg-violet-50' },
                { label: 'Crédito Total', value: totals.creditoTotal, color: 'text-emerald-700', bg: 'bg-emerald-100' },
                { label: 'Utilizado', value: totals.creditoUtilizado, color: 'text-amber-700', bg: 'bg-amber-100' },
                { label: 'Saldo Disp.', value: totals.saldoDisponivel, color: 'text-blue-700', bg: 'bg-blue-100' },
            ].map((item, idx) => (
                <div key={idx} className={`${item.bg} p-2 rounded-lg border border-slate-200/50 shadow-sm flex flex-col justify-between h-20`}>
                    <span className="text-[9px] uppercase font-bold text-slate-500 leading-tight">{item.label}</span>
                    <span className={`text-sm md:text-sm font-bold ${item.color} truncate`} title={formatNumber(item.value)}>
                        {formatNumber(item.value)}
                    </span>
                </div>
            ))}
         </div>
      )}

      {/* TABLE */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden print:overflow-visible print:border-none print:shadow-none">
        {loading ? (
          <div className="p-12 flex justify-center items-center text-slate-500 gap-3">
             <Loader className="animate-spin" /> Gerando relatório...
          </div>
        ) : filteredData.length === 0 ? (
          <div className="p-12 text-center text-slate-500">
             <FileBarChart size={48} className="mx-auto mb-4 opacity-20" />
             <p>Nenhuma cota encontrada para os filtros selecionados.</p>
          </div>
        ) : (
          <div className="overflow-x-auto print:overflow-visible">
            <table className="w-full text-[10px] md:text-xs text-left">
              <thead className="bg-slate-900 text-white font-medium uppercase tracking-wider h-10">
                <tr>
                  <SortHeader label="Cota" sortKey="quotaNumber" align="left" className="sticky left-0 bg-slate-900 z-20 border-r border-slate-700" />
                  <SortHeader label="Valor Carta" sortKey="creditValue" />
                  <SortHeader label="Valores a Pagar" sortKey="valoresAPagar" />
                  <th className="px-2 py-1 text-right">% a pagar</th>
                  <SortHeader label="Total Pago" sortKey="totalDevido" />
                  <th className="px-2 py-1 text-right">% Pago</th>
                  <SortHeader label="Lance Total" sortKey="bidTotal" />
                  <th className="px-2 py-1 text-right">% Tot</th>
                  <SortHeader label="Lance Livre" sortKey="bidFree" />
                  <th className="px-2 py-1 text-right">% Liv</th>
                  <SortHeader label="Lance Emb." sortKey="bidEmbedded" />
                  <th className="px-2 py-1 text-right">% Emb</th>
                  <SortHeader label="Vlr Crédito Líq." sortKey="valorRealCarta" className="border-l border-slate-700" />
                  <SortHeader label="Atualização" sortKey="creditManualAdjustment" />
                  <SortHeader label="Corr. 92% CDI" sortKey="bidFreeCorrection" />
                  <SortHeader label="Crédito Total" sortKey="creditoTotal" className="border-l border-slate-700 font-bold bg-slate-800" />
                  <SortHeader label="Utilizado" sortKey="creditoUtilizado" className="bg-amber-900/50" />
                  <SortHeader label="Saldo Disp." sortKey="saldoDisponivel" className="bg-emerald-900 border-l border-emerald-700 sticky right-0 z-20 shadow-[-5px_0_5px_-2px_rgba(0,0,0,0.3)]" />
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedData.map((row, idx) => (
                  <tr key={row.id} className={idx % 2 === 0 ? 'bg-white' : 'bg-slate-50'}>
                    <td className="p-2 font-medium text-slate-700 sticky left-0 bg-inherit z-10 border-r border-slate-200 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                       <div className="flex items-center gap-1.5 whitespace-nowrap">
                         {row.isContemplated ? (
                            <CheckCircle2 size={12} className="text-emerald-500" />
                         ) : (
                            <Clock size={12} className="text-slate-400" />
                         )}
                         {row.group} / {row.quotaNumber}
                       </div>
                    </td>
                    <td className="p-2 text-right font-medium text-slate-600">{formatNumber(row.creditValue)}</td>

                    {/* Valores a pagar (Future) */}
                    <td className="p-2 text-right text-red-600 font-medium bg-red-50/20">{formatNumber(row.valoresAPagar)}</td>
                    <td className="p-2 text-right text-slate-500">{formatNumber(row.percentAPagar)}</td>

                    {/* Total Devido -> Now "Total Pago" */}
                    <td className="p-2 text-right text-emerald-700 font-medium bg-emerald-50/20">{formatNumber(row.totalDevido)}</td>
                    <td className="p-2 text-right text-slate-500">{formatNumber(row.percentTotalDevido)}</td>

                    <td className="p-2 text-right font-medium text-amber-600 bg-amber-50/20">{formatNumber(row.bidTotal)}</td>
                    <td className="p-2 text-right text-slate-500">{formatNumber(row.percentBidTotal)}</td>

                    <td className="p-2 text-right text-slate-500">{formatNumber(row.bidFree)}</td>
                    <td className="p-2 text-right text-slate-400">{formatNumber(row.percentBidFree)}</td>

                    <td className="p-2 text-right text-slate-500">{formatNumber(row.bidEmbedded)}</td>
                    <td className="p-2 text-right text-slate-400">{formatNumber(row.percentBidEmbedded)}</td>

                    <td className="p-2 text-right font-bold text-slate-700 border-l border-slate-200">{formatNumber(row.valorRealCarta)}</td>

                    {/* Editable Cell: Credit Update */}
                    <td className="p-2 text-right">
                        {editingId?.id === row.id && editingId.field === 'credit' ? (
                           <div className="flex items-center justify-end gap-1">
                               <input 
                                 autoFocus
                                 type="text"
                                 className="w-16 p-1 text-right text-[10px] border border-blue-400 rounded outline-none"
                                 value={editValue}
                                 onChange={e => setEditValue(e.target.value)}
                                 onKeyDown={e => e.key === 'Enter' && handleSaveEdit()}
                                 onBlur={() => handleSaveEdit()}
                                 placeholder="0,00"
                               />
                           </div>
                        ) : (
                           <div 
                             onClick={() => handleEditClick(row.id, 'credit', row.creditManualAdjustment)}
                             className="cursor-pointer hover:bg-blue-50 px-1 py-0.5 rounded text-blue-600 font-medium transition-colors"
                           >
                              {formatNumber(row.creditManualAdjustment)}
                           </div>
                        )}
                    </td>

                    {/* Calculated Cell: 92% CDI (No longer editable) */}
                    <td className="p-2 text-right">
                        <div className="text-violet-600 font-medium">
                           {formatNumber(row.bidFreeCorrection)}
                        </div>
                    </td>

                    <td className="p-2 text-right font-bold text-slate-800 bg-slate-100 border-l border-slate-200">
                      {formatNumber(row.creditoTotal)}
                    </td>

                    <td className="p-2 text-right font-medium text-amber-700 bg-amber-50/50">
                        {formatNumber(row.creditoUtilizado)}
                    </td>

                    <td className="p-2 text-right font-bold text-emerald-800 bg-emerald-50 border-l border-emerald-100 sticky right-0 shadow-[-2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                        {formatNumber(row.saldoDisponivel)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
      <div className="text-xs text-slate-400 mt-2">
         * Clique na coluna "Atualização" para editar valores manualmente. A coluna "Corr. 92% CDI" é calculada automaticamente baseada nos índices cadastrados.
         <br/>
         * Os valores de "Valores a Pagar" e "Total Pago" são calculados com base na data de referência selecionada.
      </div>
    </div>
  );
};

export default Reports;

import React, { useState } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { formatCurrency, formatDate } from '../utils/formatters';
import { ShoppingBag, Printer, Filter, X } from 'lucide-react';

const CreditUsageReport = () => {
  const { allCreditUsages, quotas, companies, administrators } = useConsortium();

  // Filters State
  const [filterAdmin, setFilterAdmin] = useState('');
  const [filterCompany, setFilterCompany] = useState('');

  // Combine Usage Data with Quota Info & Filter
  const reportData = allCreditUsages.map(usage => {
      const quota = quotas.find(q => q.id === usage.quotaId);
      const company = quota ? companies.find(c => c.id === quota.companyId) : null;
      const admin = quota ? administrators.find(a => a.id === quota.administratorId) : null;
      return {
          ...usage,
          quota,
          company,
          admin
      };
  }).filter(item => {
      const matchAdmin = !filterAdmin || item.admin?.id === filterAdmin;
      const matchComp = !filterCompany || item.company?.id === filterCompany;
      return matchAdmin && matchComp;
  }).sort((a, b) => b.date.localeCompare(a.date)); // Newest first

  const totalUsed = reportData.reduce((acc, curr) => acc + curr.amount, 0);

  // Aggregations
  const byProvider = reportData.reduce((acc, curr) => {
      const key = curr.seller || 'Não Informado';
      acc[key] = (acc[key] || 0) + curr.amount;
      return acc;
  }, {} as Record<string, number>);

  const byDescription = reportData.reduce((acc, curr) => {
      const key = curr.description || 'Sem Descrição';
      acc[key] = (acc[key] || 0) + curr.amount;
      return acc;
  }, {} as Record<string, number>);

  // Sort aggregations for display
  const topProviders = (Object.entries(byProvider) as [string, number][]).sort((a, b) => b[1] - a[1]);
  const topDescriptions = (Object.entries(byDescription) as [string, number][]).sort((a, b) => b[1] - a[1]);

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-10 print:max-w-none print:w-full print:pb-0">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                    <ShoppingBag className="text-emerald-600" /> Relatório de Histórico de Utilização
                </h1>
                <p className="text-slate-500">Extrato completo de todas as utilizações de crédito.</p>
            </div>
            <button 
                onClick={() => window.print()} 
                className="bg-slate-100 text-slate-600 px-4 py-2 rounded-lg hover:bg-slate-200 transition-colors font-medium flex items-center gap-2 print:hidden self-start"
            >
                <Printer size={18} /> Imprimir
            </button>
        </div>

        {/* FILTERS */}
        <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 items-end print:hidden">
            <div className="flex-1 w-full md:w-auto">
                <label className="block text-xs font-semibold text-slate-500 mb-1">Empresa</label>
                <select 
                    value={filterCompany} 
                    onChange={(e) => setFilterCompany(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
                >
                    <option value="">Todas</option>
                    {companies.map(c => (
                        <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                </select>
            </div>
            <div className="flex-1 w-full md:w-auto">
                <label className="block text-xs font-semibold text-slate-500 mb-1">Administradora</label>
                <select 
                    value={filterAdmin} 
                    onChange={(e) => setFilterAdmin(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
                >
                    <option value="">Todas</option>
                    {administrators.map(a => (
                        <option key={a.id} value={a.id}>{a.name}</option>
                    ))}
                </select>
            </div>
            {(filterAdmin || filterCompany) && (
                <button 
                    onClick={() => { setFilterAdmin(''); setFilterCompany(''); }}
                    className="text-slate-500 hover:text-red-500 text-sm font-medium px-2 py-2 flex items-center gap-1"
                >
                    <X size={16}/> Limpar
                </button>
            )}
        </div>

        {/* SUMMARY */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="p-3 bg-amber-100 text-amber-600 rounded-full">
                    <ShoppingBag size={24} />
                </div>
                <div>
                    <p className="text-sm font-semibold text-slate-500 uppercase">Total Utilizado</p>
                    <p className="text-2xl font-bold text-slate-800">{formatCurrency(totalUsed)}</p>
                </div>
            </div>
            <div className="text-right">
                <p className="text-sm font-semibold text-slate-500 uppercase">Lançamentos</p>
                <p className="text-2xl font-bold text-slate-800">{reportData.length}</p>
            </div>
        </div>

        {/* TABLE */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden print:border-none print:shadow-none">
            {reportData.length > 0 ? (
                <div className="overflow-x-auto print:overflow-visible">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-900 text-white uppercase text-xs">
                            <tr>
                                <th className="px-6 py-3">Data</th>
                                <th className="px-6 py-3">Cota / Grupo</th>
                                <th className="px-6 py-3">Empresa</th>
                                <th className="px-6 py-3">Descrição</th>
                                <th className="px-6 py-3">Fornecedor</th>
                                <th className="px-6 py-3 text-right">Valor</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {reportData.map(item => (
                                <tr key={item.id} className="hover:bg-slate-50">
                                    <td className="px-6 py-4 font-medium text-slate-700 whitespace-nowrap">
                                        {formatDate(item.date)}
                                    </td>
                                    <td className="px-6 py-4 text-slate-600">
                                        {item.quota ? `${item.quota.group} / ${item.quota.quotaNumber}` : 'Cota Removida'}
                                    </td>
                                    <td className="px-6 py-4 text-slate-500 text-xs">
                                        {item.company?.name || '-'}
                                    </td>
                                    <td className="px-6 py-4 font-medium text-slate-800">
                                        {item.description}
                                    </td>
                                    <td className="px-6 py-4 text-slate-500">
                                        {item.seller || '-'}
                                    </td>
                                    <td className="px-6 py-4 text-right font-bold text-amber-600">
                                        {formatCurrency(item.amount)}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            ) : (
                <div className="p-12 text-center text-slate-400 border-2 border-dashed border-slate-100 rounded-xl m-4">
                    <Filter size={48} className="mx-auto mb-3 opacity-20" />
                    <p className="text-lg font-medium">Nenhum registro encontrado</p>
                </div>
            )}
        </div>

        {/* ANALYTICAL SUMMARY SECTION */}
        {reportData.length > 0 && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4 page-break-inside-avoid">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 border-b pb-2">Resumo por Fornecedor</h3>
                    <div className="space-y-3">
                        {topProviders.map(([provider, amount], idx) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                                <span className="text-slate-600 truncate flex-1 pr-4">{provider}</span>
                                <span className="font-bold text-slate-800">{formatCurrency(amount)}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 border-b pb-2">Resumo por Tipo/Descrição</h3>
                    <div className="space-y-3">
                        {topDescriptions.map(([desc, amount], idx) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                                <span className="text-slate-600 truncate flex-1 pr-4">{desc}</span>
                                <span className="font-bold text-slate-800">{formatCurrency(amount)}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default CreditUsageReport;

import React, { useState } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { CorrectionIndex, MonthlyIndex } from '../types';
import { Trash2, Plus, TrendingUp, Pencil, X, Filter, Calculator, Calendar } from 'lucide-react';

const CorrectionIndices = () => {
  const { indices, addIndex, updateIndex, deleteIndex } = useConsortium();

  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    month: new Date().toISOString().slice(0, 7), // YYYY-MM
    type: CorrectionIndex.INCC,
    rate: 0.5 // Default 0.5%
  });

  // Filter State
  const [filterStart, setFilterStart] = useState('');
  const [filterEnd, setFilterEnd] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Normalize date
    const dateStr = `${form.month}-01`;

    // 1. DUPLICATE CHECK
    const isDuplicate = indices.some(idx => 
      idx.type === form.type && 
      idx.date === dateStr && 
      idx.id !== editingId
    );

    if (isDuplicate) {
      alert(`Já existe um índice ${form.type} cadastrado para o mês ${form.month}. Não é permitido duplicidade.`);
      return;
    }

    const indexData: MonthlyIndex = {
      id: editingId || crypto.randomUUID(),
      type: form.type,
      date: dateStr, 
      rate: Number(form.rate)
    };

    if (editingId) {
      updateIndex(indexData);
      setEditingId(null); 
    } else {
      addIndex(indexData);
    }

    // Reset values for next entry
    setForm({
        month: new Date().toISOString().slice(0, 7),
        type: form.type, // Maintain type for faster sequence entry
        rate: 0.5
    });
  };

  const handleEdit = (idx: MonthlyIndex) => {
    setEditingId(idx.id);
    setForm({
      month: idx.date.slice(0, 7), 
      type: idx.type,
      rate: idx.rate
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setForm({
      month: new Date().toISOString().slice(0, 7),
      type: CorrectionIndex.INCC,
      rate: 0.5
    });
  };

  // --- FILTER & SORT LOGIC ---
  const sortedIndices = [...indices].sort((a, b) => 
    b.date.localeCompare(a.date)
  );

  const filteredIndices = sortedIndices.filter(idx => {
    const idxMonth = idx.date.slice(0, 7); // YYYY-MM

    if (filterStart && idxMonth < filterStart) return false;
    if (filterEnd && idxMonth > filterEnd) return false;

    return true;
  });

  // Comprehensive Calculation: Simple vs Compound
  const getIndexStats = (type: CorrectionIndex) => {
    const relevant = filteredIndices.filter(i => i.type === type);

    const simpleSum = relevant.reduce((acc, curr) => acc + curr.rate, 0);

    const totalFactor = relevant.reduce((acc, curr) => {
        return acc * (1 + (curr.rate / 100));
    }, 1.0);

    return {
        compound: (totalFactor - 1) * 100,
        simple: simpleSum,
        count: relevant.length
    };
  };

  const statsINCC = getIndexStats(CorrectionIndex.INCC);
  const statsIPCA = getIndexStats(CorrectionIndex.IPCA);
  const statsCDI = getIndexStats(CorrectionIndex.CDI);

  const SummaryCard = ({ title, stats, colorClass }: { title: string, stats: any, colorClass: string }) => (
    <div className={`bg-white p-4 rounded-xl border-t-4 shadow-sm min-w-[200px] flex-1 ${colorClass}`}>
        <div className="flex justify-between items-start mb-2">
            <h4 className="text-xs font-bold uppercase text-slate-500">{title}</h4>
            <span className="bg-slate-100 text-slate-500 text-[9px] px-1.5 py-0.5 rounded-full font-bold">
                {stats.count} MESES
            </span>
        </div>
        <div className="space-y-3">
            <div>
                <p className="text-[10px] text-slate-400 font-semibold uppercase">Acúmulo Composto</p>
                <p className="text-xl font-black text-slate-800">{stats.compound.toFixed(4)}%</p>
            </div>
            <div className="pt-2 border-t border-slate-50 flex justify-between items-end">
                <div>
                    <p className="text-[9px] text-slate-400 font-semibold uppercase">Soma Simples</p>
                    <p className="text-sm font-bold text-slate-600">{stats.simple.toFixed(2)}%</p>
                </div>
                <TrendingUp size={16} className="text-slate-200 mb-1" />
            </div>
        </div>
    </div>
  );

  return (
    <div className="space-y-6 max-w-5xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-800">Índices de Correção</h1>
            <p className="text-slate-500">Gestão de taxas mensais para reajuste automático de crédito e parcelas.</p>
        </div>
        <div className="flex bg-amber-50 border border-amber-200 p-3 rounded-lg text-amber-800 text-xs items-center gap-2 max-w-xs">
            <Calculator size={18} className="shrink-0" />
            <p>O sistema utiliza o <strong>Acúmulo Composto</strong> para cálculos financeiros oficiais.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          {/* FORM SECTION */}
          <div className="lg:col-span-4 space-y-6">
              <div className={`bg-white p-6 rounded-xl shadow-sm border ${editingId ? 'border-blue-400 ring-2 ring-blue-50' : 'border-slate-200'}`}>
                <h2 className={`text-sm font-bold uppercase tracking-wider mb-4 flex items-center gap-2 ${editingId ? 'text-blue-700' : 'text-slate-800'}`}>
                   {editingId ? <Pencil size={18} /> : <Plus size={18} className="text-emerald-600"/>} 
                   {editingId ? 'Editar Índice' : 'Novo Lançamento'}
                </h2>
                <form onSubmit={handleSubmit} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Mês/Ano</label>
                    <input 
                      type="month" 
                      required
                      value={form.month}
                      onChange={e => setForm({...form, month: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-emerald-500 outline-none text-sm"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipo de Índice</label>
                    <select 
                      value={form.type}
                      onChange={e => setForm({...form, type: e.target.value as CorrectionIndex})}
                      className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-emerald-500 outline-none text-sm"
                    >
                      <option value={CorrectionIndex.INCC}>INCC</option>
                      <option value={CorrectionIndex.IPCA}>IPCA</option>
                      <option value={CorrectionIndex.CDI}>CDI (para Lance Livre)</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Taxa Mensal (%)</label>
                    <div className="relative">
                        <input 
                        type="number" 
                        step="0.0001"
                        required
                        value={form.rate}
                        onChange={e => setForm({...form, rate: parseFloat(e.target.value)})}
                        className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2.5 pr-8 focus:ring-2 focus:ring-emerald-500 outline-none text-sm font-bold"
                        />
                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold">%</span>
                    </div>
                  </div>

                  <div className="flex gap-2 pt-2">
                    {editingId && (
                        <button 
                          type="button" 
                          onClick={handleCancelEdit}
                          className="flex-1 px-4 py-2.5 rounded-lg font-medium text-slate-600 bg-slate-100 hover:bg-slate-200 transition-colors flex items-center justify-center gap-1 text-sm"
                        >
                          <X size={16} />
                        </button>
                    )}
                    <button 
                      type="submit" 
                      className={`flex-1 px-6 py-2.5 rounded-lg font-bold text-white transition-colors shadow-sm ${editingId ? 'bg-blue-600 hover:bg-blue-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                    >
                      {editingId ? 'Salvar Alteração' : 'Adicionar Taxa'}
                    </button>
                  </div>
                </form>
              </div>

              {/* FILTER SECTION */}
              <div className="bg-slate-900 rounded-xl p-6 shadow-lg border border-slate-800 text-white">
                <h3 className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-4 flex items-center gap-2">
                    <Filter size={16} /> Filtragem & Acúmulo
                </h3>
                <div className="space-y-4">
                    <div>
                        <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Período Inicial</label>
                        <input 
                            type="month" 
                            value={filterStart}
                            onChange={e => setFilterStart(e.target.value)}
                            className="w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-sm outline-none focus:ring-2 focus:ring-blue-500"
                        />
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Período Final</label>
                        <input 
                            type="month" 
                            value={filterEnd}
                            onChange={e => setFilterEnd(e.target.value)}
                            className="w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-sm outline-none focus:ring-2 focus:ring-blue-500"
                        />
                    </div>
                    {(filterStart || filterEnd) && (
                        <button 
                            onClick={() => { setFilterStart(''); setFilterEnd(''); }}
                            className="w-full py-2 text-xs font-bold text-red-400 hover:text-red-300 border border-red-900/50 rounded-lg hover:bg-red-900/20 transition-colors flex items-center justify-center gap-2"
                        >
                            <X size={14} /> Limpar Filtros
                        </button>
                    )}
                </div>
              </div>
          </div>

          {/* SUMMARY AND LIST SECTION */}
          <div className="lg:col-span-8 space-y-6">
              {/* SUMMARY CARDS */}
              <div className="flex flex-col sm:flex-row gap-4">
                  <SummaryCard title="INCC Acumulado" stats={statsINCC} colorClass="border-blue-500" />
                  <SummaryCard title="IPCA Acumulado" stats={statsIPCA} colorClass="border-orange-500" />
                  <SummaryCard title="CDI Acumulado" stats={statsCDI} colorClass="border-violet-500" />
              </div>

              {/* LISTS GRID */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                    { type: CorrectionIndex.INCC, title: 'Histórico INCC', color: 'text-blue-600' },
                    { type: CorrectionIndex.IPCA, title: 'Histórico IPCA', color: 'text-orange-600' },
                    { type: CorrectionIndex.CDI, title: 'Histórico CDI', color: 'text-violet-600' }
                ].map((list) => (
                    <div key={list.type} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-[450px]">
                        <div className="bg-slate-50 p-4 border-b border-slate-200 font-bold text-slate-700 flex items-center justify-between sticky top-0 z-10">
                            <span className="text-xs uppercase tracking-tight">{list.title}</span>
                            <Calendar size={14} className="text-slate-300"/>
                        </div>
                        <div className="flex-1 overflow-y-auto">
                            <table className="w-full text-xs text-left">
                                <thead className="text-[10px] text-slate-400 uppercase bg-slate-50/50 sticky top-0">
                                    <tr>
                                        <th className="px-4 py-2">Mês</th>
                                        <th className="px-4 py-2 text-right">Taxa %</th>
                                        <th className="px-4 py-2 text-right">Ações</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {filteredIndices.filter(i => i.type === list.type).length > 0 ? (
                                        filteredIndices.filter(i => i.type === list.type).map(idx => (
                                            <tr key={idx.id} className={`hover:bg-slate-50 transition-colors ${editingId === idx.id ? 'bg-blue-50' : ''}`}>
                                                <td className="px-4 py-3 font-medium text-slate-600">
                                                    {new Date(idx.date + 'T12:00:00').toLocaleDateString('pt-BR', { month: '2-digit', year: '2-digit' })}
                                                </td>
                                                <td className="px-4 py-3 text-right font-bold text-slate-800">
                                                    {idx.rate.toFixed(2)}%
                                                </td>
                                                <td className="px-4 py-3 text-right">
                                                    <div className="flex items-center justify-end gap-1">
                                                        <button onClick={() => handleEdit(idx)} className="p-1 text-blue-400 hover:text-blue-600 transition-colors" title="Editar">
                                                            <Pencil size={14} />
                                                        </button>
                                                        <button onClick={() => deleteIndex(idx.id)} className="p-1 text-slate-300 hover:text-red-500 transition-colors" title="Excluir">
                                                            <Trash2 size={14} />
                                                        </button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr>
                                            <td colSpan={3} className="p-8 text-center text-slate-400 italic">
                                                Nenhum registro
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                ))}
              </div>
          </div>
      </div>
    </div>
  );
};

