import { Quota, PaymentInstallment, PaymentPlanType, MonthlyIndex, CorrectionIndex } from '../types';
import { addMonths } from '../utils/formatters';

// Helper to avoid timezone shifting (UTC vs Local) which causes "date - 1 day" errors
// Inputs "YYYY-MM-DD" and returns Date object at 00:00:00 LOCAL TIME
const createLocalDate = (dateStr: string): Date => {
  if(!dateStr) return new Date();
  // Handle cases where dateStr might be ISO with time
  const cleanDate = dateStr.split('T')[0];
  const [year, month, day] = cleanDate.split('-').map(Number);
  // Month in JS Date is 0-indexed (0 = Jan, 1 = Feb)
  return new Date(year, month - 1, day, 0, 0, 0, 0);
};

/**
 * Calculates the correction of the Bid Free value based on 92% of CDI.
 * Returns ONLY the correction amount (Interest earned), not the total.
 */
export const calculateCDICorrection = (value: number, startDateStr: string | undefined, indices: MonthlyIndex[]): number => {
    if (!value || value <= 0 || !startDateStr) return 0;

    // Use createLocalDate to ensure accurate start date (no timezone shift)
    const startDate = createLocalDate(startDateStr);
    // Normalize to first of month for comparison with monthly indices
    startDate.setDate(1); 
    startDate.setHours(0,0,0,0);

    const today = new Date();
    today.setHours(23,59,59,999);

    // Filter relevant CDI indices
    const relevantIndices = indices.filter(idx => {
        if (idx.type !== CorrectionIndex.CDI) return false;

        // Ensure index date is treated locally
        const idxDate = createLocalDate(idx.date);
        idxDate.setDate(1);
        idxDate.setHours(0,0,0,0);

        // Include indices FROM start month UNTIL today (inclusive of start month)
        return idxDate >= startDate && idxDate <= today;
    });

    // Calculate Compound Interest with 92% factor
    let accumulatedMultiplier = 1;

    relevantIndices.forEach(idx => {
        const effectiveRate = idx.rate * 0.92;
        accumulatedMultiplier *= (1 + (effectiveRate / 100));
    });

    const totalAmount = value * accumulatedMultiplier;

    return totalAmount - value;
};

export const calculateCurrentCreditValue = (quota: Quota, indices: MonthlyIndex[] = []): number => {
  if (!quota) return 0;

  let currentCreditValue = Number(quota.creditValue) || 0;

  const dateStr = quota.adhesionDate || quota.firstDueDate;
  if (!dateStr) return currentCreditValue;

  const startDate = createLocalDate(dateStr);
  startDate.setDate(1); 
  startDate.setHours(0,0,0,0);

  let cutoffDate = new Date();
  cutoffDate.setHours(23,59,59,999);

  if (quota.isContemplated && quota.contemplationDate) {
      cutoffDate = createLocalDate(quota.contemplationDate);
      cutoffDate.setHours(23,59,59,999);
  } else if (quota.isContemplated && !quota.contemplationDate) {
      return currentCreditValue;
  }

  let processingDate = new Date(startDate);
  processingDate = addMonths(processingDate, 12);

  let safetyCounter = 0;

  while (processingDate <= cutoffDate && safetyCounter < 100) {
      const endPeriod = new Date(processingDate);
      endPeriod.setDate(1); 
      endPeriod.setHours(0,0,0,0);
      const endPeriodStr = endPeriod.toISOString().split('T')[0];

      // PRIORIDADE: Verificar se existe um índice acumulado de 12 meses lançado
      const annualType = quota.correctionIndex === CorrectionIndex.INCC ? CorrectionIndex.INCC_12 : CorrectionIndex.IPCA_12;
      const directAnnualIndex = indices.find(idx => idx.type === annualType && idx.date === endPeriodStr);

      let finalRate = 0;

      if (directAnnualIndex) {
          finalRate = directAnnualIndex.rate / 100;
      } else {
          // COMPORTAMENTO PADRÃO: Calcular acúmulo mensal
          const startPeriod = addMonths(processingDate, -12);
          startPeriod.setDate(1); 
          startPeriod.setHours(0,0,0,0);

          const relevantIndices = indices.filter(idx => {
            if (idx.type !== quota.correctionIndex) return false;
            const d = createLocalDate(idx.date);
            d.setHours(0,0,0,0);
            return d >= startPeriod && d < endPeriod;
          });

          let accumulatedMultiplier = 1;
          relevantIndices.forEach(idx => {
              accumulatedMultiplier *= (1 + (idx.rate / 100));
          });
          finalRate = accumulatedMultiplier - 1;
      }

      if (finalRate > 0) {
          const ratePercent2 = parseFloat((finalRate * 100).toFixed(2));
          const effectiveRateCredit = ratePercent2 / 100;
          currentCreditValue = currentCreditValue * (1 + effectiveRateCredit);
      }

      processingDate = addMonths(processingDate, 12);
      safetyCounter++;
  }

  return currentCreditValue;
};

export const generateSchedule = (quota: Quota, indices: MonthlyIndex[] = []): PaymentInstallment[] => {
  const schedule: PaymentInstallment[] = [];

  if (!quota || !quota.firstDueDate) return [];

  const startDate = createLocalDate(quota.firstDueDate);
  const adhesionDateAnchor = createLocalDate(quota.adhesionDate || quota.firstDueDate);
  adhesionDateAnchor.setDate(1);
  adhesionDateAnchor.setHours(0,0,0,0);

  const termMonths = Number(quota.termMonths) || 1;
  const adminFeeRate = Number(quota.adminFeeRate) || 0;
  const reserveFundRate = Number(quota.reserveFundRate) || 0;

  let currentCreditValue = Number(quota.creditValue) || 0;
  let currentBalanceFC = currentCreditValue; 
  let currentBalanceTA = currentCreditValue * (adminFeeRate / 100);
  let currentBalanceFR = currentCreditValue * (reserveFundRate / 100);

  let bidProcessed = false;
  const today = new Date();
  today.setHours(23, 59, 59, 999);

  const initialTotalBalance = currentBalanceFC + currentBalanceTA + currentBalanceFR;
  const fixedRatioFC = initialTotalBalance > 0 ? currentBalanceFC / initialTotalBalance : 0;
  const fixedRatioTA = initialTotalBalance > 0 ? currentBalanceTA / initialTotalBalance : 0;
  const fixedRatioFR = initialTotalBalance > 0 ? currentBalanceFR / initialTotalBalance : 0;

  for (let i = 1; i <= termMonths; i++) {
    const currentDate = addMonths(startDate, i - 1);
    const dueDate = currentDate.toISOString();
    const amortizationDivisor = Math.max(0, termMonths - i + 1);

    let bidAmountApplied = 0; 
    let bidDateApplied: string | undefined = undefined;
    let bidAbatementFC = 0, bidAbatementTA = 0, bidAbatementFR = 0;
    let bidEmbeddedApplied = 0, bidEmbeddedPercent = 0, bidEmbeddedAbatementFC = 0, bidEmbeddedPercentFC = 0, bidEmbeddedAbatementFR = 0, bidEmbeddedPercentFR = 0, bidEmbeddedAbatementTA = 0, bidEmbeddedPercentTA = 0;
    let bidFreeApplied = 0, bidFreePercent = 0, bidFreeAbatementFC = 0, bidFreePercentFC = 0, bidFreeAbatementFR = 0, bidFreePercentFR = 0, bidFreeAbatementTA = 0, bidFreePercentTA = 0;

    if (quota.isContemplated && quota.contemplationDate && !bidProcessed && quota.bidTotal && quota.bidTotal > 0) {
        const bidDate = createLocalDate(quota.contemplationDate);
        if (bidDate <= currentDate) {
             const totalOutstanding = currentBalanceFC + currentBalanceTA + currentBalanceFR;
             if (totalOutstanding > 0) {
                 bidDateApplied = quota.contemplationDate;
                 bidProcessed = true;
                 bidAmountApplied = quota.bidTotal;
                 const distributeBid = (amount: number) => {
                     let mFC = parseFloat((amount * fixedRatioFC).toFixed(2));
                     let mTA = parseFloat((amount * fixedRatioTA).toFixed(2));
                     let mFR = parseFloat((amount * fixedRatioFR).toFixed(2));
                     const sum = mFC + mTA + mFR;
                     const diff = amount - sum;
                     if (Math.abs(diff) > 0.001) mFC += diff; 
                     const pFC = (mFC / currentCreditValue) * 100;
                     const pTA = (mTA / currentCreditValue) * 100;
                     const pFR = (mFR / currentCreditValue) * 100;
                     const pTotal = (amount / currentCreditValue) * 100;
                     return { mFC, mTA, mFR, pFC, pTA, pFR, pTotal };
                 };
                 if (quota.bidEmbedded && quota.bidEmbedded > 0) {
                     bidEmbeddedApplied = quota.bidEmbedded;
                     const res = distributeBid(bidEmbeddedApplied);
                     bidEmbeddedAbatementFC = res.mFC; bidEmbeddedAbatementTA = res.mTA; bidEmbeddedAbatementFR = res.mFR;
                     bidEmbeddedPercent = res.pTotal; bidEmbeddedPercentFC = res.pFC; bidEmbeddedPercentTA = res.pTA; bidEmbeddedPercentFR = res.pFR;
                     currentBalanceFC -= bidEmbeddedAbatementFC; currentBalanceTA -= bidEmbeddedAbatementTA; currentBalanceFR -= bidEmbeddedAbatementFR;
                 }
                 if (quota.bidFree && quota.bidFree > 0) {
                     bidFreeApplied = quota.bidFree;
                     const res = distributeBid(bidFreeApplied);
                     bidFreeAbatementFC = res.mFC; bidFreeAbatementTA = res.mTA; bidFreeAbatementFR = res.mFR;
                     bidFreePercent = res.pTotal; bidFreePercentFC = res.pFC; bidFreePercentTA = res.pTA; bidFreePercentFR = res.pFR;
                     currentBalanceFC -= bidFreeAbatementFC; currentBalanceTA -= bidFreeAbatementTA; currentBalanceFR -= bidFreeAbatementFR;
                 }
                 bidAbatementFC = bidEmbeddedAbatementFC + bidFreeAbatementFC;
                 bidAbatementFR = bidEmbeddedAbatementFR + bidFreeAbatementFR;
                 bidAbatementTA = bidEmbeddedAbatementTA + bidFreeAbatementTA;
             }
        }
    }

    let correctionApplied = false;
    let correctionFactor = 0;
    let correctionIndexName: string | undefined = undefined;
    let correctionStartDate: string | undefined = undefined;
    let correctionEndDate: string | undefined = undefined;
    let stopCreditCorrection = false;
    if (quota.isContemplated && quota.contemplationDate) {
         const contDate = createLocalDate(quota.contemplationDate);
         if (currentDate > contDate) stopCreditCorrection = true;
    }

    if (i > 1 && (i - 1) % 12 === 0) {
        const anniversaryCount = (i - 1) / 12;
        const endOfPeriod = addMonths(adhesionDateAnchor, anniversaryCount * 12);
        endOfPeriod.setDate(1);
        endOfPeriod.setHours(0,0,0,0);
        const endOfPeriodStr = endOfPeriod.toISOString().split('T')[0];

        if (endOfPeriod <= today) {
            // PRIORIDADE: Índice Anual Acumulado
            const annualType = quota.correctionIndex === CorrectionIndex.INCC ? CorrectionIndex.INCC_12 : CorrectionIndex.IPCA_12;
            const directAnnualIndex = indices.find(idx => idx.type === annualType && idx.date === endOfPeriodStr);

            let finalRate = 0;
            let startOfPeriod = addMonths(endOfPeriod, -12);
            startOfPeriod.setDate(1); startOfPeriod.setHours(0,0,0,0);

            if (directAnnualIndex) {
                finalRate = directAnnualIndex.rate / 100;
                correctionIndexName = quota.correctionIndex + " (Acum. 12m)";
            } else {
                const relevantIndices = indices.filter(idx => {
                  if (idx.type !== quota.correctionIndex) return false;
                  const idxDate = createLocalDate(idx.date);
                  idxDate.setHours(0,0,0,0);
                  return idxDate >= startOfPeriod && idxDate < endOfPeriod;
                });
                let accumulatedMultiplier = 1;
                relevantIndices.forEach(idx => { accumulatedMultiplier *= (1 + (idx.rate / 100)); });
                finalRate = accumulatedMultiplier - 1; 
                correctionIndexName = quota.correctionIndex;
            }

            if (finalRate > 0) {
                correctionApplied = true;
                const ratePercent2 = parseFloat((finalRate * 100).toFixed(2));
                const effectiveRateCredit = ratePercent2 / 100;
                const ratePercent4 = parseFloat((finalRate * 100).toFixed(4));
                const effectiveRateDebt = ratePercent4 / 100;

                correctionFactor = effectiveRateDebt; 
                correctionStartDate = startOfPeriod.toISOString();
                const displayEndDate = new Date(endOfPeriod);
                displayEndDate.setMonth(displayEndDate.getMonth() - 1);
                correctionEndDate = displayEndDate.toISOString();

                if (!stopCreditCorrection) currentCreditValue = currentCreditValue * (1 + effectiveRateCredit);
                currentBalanceFC = currentBalanceFC * (1 + effectiveRateDebt);
                currentBalanceTA = currentBalanceTA * (1 + effectiveRateDebt);
                currentBalanceFR = currentBalanceFR * (1 + effectiveRateDebt);
            }
        }
    }

    let installmentFC = 0, installmentTA = 0, installmentFR = 0;
    let monthlyRateFC = 0, monthlyRateFR = 0, monthlyRateTA = 0; 
    let isBeforeContemplation = true;
    if (quota.isContemplated && quota.contemplationDate) {
        const contDate = createLocalDate(quota.contemplationDate);
        const currentYearMonth = currentDate.getFullYear() * 12 + currentDate.getMonth();
        const contYearMonth = contDate.getFullYear() * 12 + contDate.getMonth();
        if (currentYearMonth > contYearMonth) isBeforeContemplation = false;
        if (bidProcessed) isBeforeContemplation = false;
    } else if (quota.isContemplated && !quota.contemplationDate) {
         isBeforeContemplation = false; 
    }

    const rawRateTA = adminFeeRate / termMonths;
    monthlyRateTA = parseFloat(rawRateTA.toFixed(4));
    const rawRateFR = reserveFundRate / termMonths;
    monthlyRateFR = parseFloat(rawRateFR.toFixed(4));

    if (quota.paymentPlan === PaymentPlanType.REDUCED || quota.paymentPlan === PaymentPlanType.NORMAL) {
      let useReducedLogic = false;
      if (quota.paymentPlan === PaymentPlanType.REDUCED) {
          const halfTermIndex = Math.ceil(termMonths / 2);
          useReducedLogic = (i <= halfTermIndex) && isBeforeContemplation;
      }
      if (useReducedLogic) {
          const basePercentageFC = 100 / termMonths;
          const reducedRateFC = basePercentageFC * 0.5;
          monthlyRateFC = parseFloat(reducedRateFC.toFixed(4));
          installmentFC = currentCreditValue * (monthlyRateFC / 100);
      } else {
          const div = amortizationDivisor > 0 ? amortizationDivisor : 1;
          installmentFC = currentBalanceFC / div;
          if (currentCreditValue > 0) monthlyRateFC = (installmentFC / currentCreditValue) * 100;
      }
      installmentFC = Math.min(installmentFC, currentBalanceFC);
      if (!isBeforeContemplation && bidProcessed) {
          const div = amortizationDivisor > 0 ? amortizationDivisor : 1;
          installmentTA = currentBalanceTA / div;
          installmentFR = currentBalanceFR / div;
          if (currentCreditValue > 0) {
              monthlyRateTA = (installmentTA / currentCreditValue) * 100;
              monthlyRateFR = (installmentFR / currentCreditValue) * 100;
          }
      } else {
          const calculatedTA = currentCreditValue * (monthlyRateTA / 100);
          const calculatedFR = currentCreditValue * (monthlyRateFR / 100);
          installmentTA = Math.min(calculatedTA, currentBalanceTA);
          installmentFR = Math.min(calculatedFR, currentBalanceFR);
      }
    } 
    else if (quota.paymentPlan === PaymentPlanType.SEMESTRAL) {
       const cycleMonth = i % 6; 
       const isBalloonMonth = cycleMonth === 0; 
       let baseFC = 0, baseTA = 0, baseFR = 0;
       if (isBeforeContemplation) {
           baseFC = currentCreditValue / termMonths;
           baseTA = currentCreditValue * (monthlyRateTA / 100);
           baseFR = currentCreditValue * (monthlyRateFR / 100);
       } else {
           const div = amortizationDivisor > 0 ? amortizationDivisor : 1;
           baseFC = currentBalanceFC / div;
           baseTA = currentBalanceTA / div;
           baseFR = currentBalanceFR / div;
       }
       if (!isBalloonMonth) {
          installmentFC = baseFC * 0.5; installmentTA = baseTA * 0.5; installmentFR = baseFR * 0.5;
       } else {
          installmentFC = baseFC * 3.5; installmentTA = baseTA * 3.5; installmentFR = baseFR * 3.5;
       }
       if (currentCreditValue > 0) {
           monthlyRateFC = (installmentFC / currentCreditValue) * 100;
           monthlyRateTA = (installmentTA / currentCreditValue) * 100;
           monthlyRateFR = (installmentFR / currentCreditValue) * 100;
       }
    }

    installmentFC = parseFloat(installmentFC.toFixed(2));
    installmentFR = parseFloat(installmentFR.toFixed(2));
    installmentTA = parseFloat(installmentTA.toFixed(2));
    const totalInstallment = installmentFC + installmentTA + installmentFR;
    currentBalanceFC -= installmentFC; currentBalanceTA -= installmentTA; currentBalanceFR -= installmentFR;
    const currentBalanceTotal = currentBalanceFC + currentBalanceTA + currentBalanceFR;
    if (i === termMonths || currentBalanceTotal < 1) {
        if (i === termMonths) { currentBalanceFC = 0; currentBalanceTA = 0; currentBalanceFR = 0; }
    }
    const percentBalanceFC = currentCreditValue > 0 ? (currentBalanceFC / currentCreditValue) * 100 : 0;
    const percentBalanceFR = currentCreditValue > 0 ? (currentBalanceFR / currentCreditValue) * 100 : 0;
    const percentBalanceTA = currentCreditValue > 0 ? (currentBalanceTA / currentCreditValue) * 100 : 0;
    const percentBalanceTotal = currentCreditValue > 0 ? ((currentBalanceFC + currentBalanceFR + currentBalanceTA) / currentCreditValue) * 100 : 0;

    schedule.push({
      installmentNumber: i, dueDate, commonFund: installmentFC, monthlyRateFC, reserveFund: installmentFR, monthlyRateFR, adminFee: installmentTA, monthlyRateTA, totalInstallment,
      balanceFC: Math.max(0, currentBalanceFC), balanceFR: Math.max(0, currentBalanceFR), balanceTA: Math.max(0, currentBalanceTA), balanceTotal: Math.max(0, currentBalanceFC + currentBalanceTA + currentBalanceFR),
      percentBalanceFC, percentBalanceFR, percentBalanceTA, percentBalanceTotal, bidAmountApplied, bidDate: bidDateApplied,
      bidEmbeddedApplied, bidEmbeddedPercent, bidEmbeddedAbatementFC, bidEmbeddedPercentFC, bidEmbeddedAbatementFR, bidEmbeddedPercentFR, bidEmbeddedAbatementTA, bidEmbeddedPercentTA,
      bidFreeApplied, bidFreePercent, bidFreeAbatementFC, bidFreePercentFC, bidFreeAbatementFR, bidFreePercentFR, bidFreeAbatementTA, bidFreePercentTA,
      bidAbatementFC, bidAbatementFR, bidAbatementTA, correctionApplied, correctionFactor, correctedCreditValue: currentCreditValue, correctionIndexName, correctionStartDate, correctionEndDate,
      realAmountPaid: null, isPaid: false
    });
  }
  return schedule;
};

import React, { useState } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { CorrectionIndex, MonthlyIndex } from '../types';
import { Trash2, Plus, TrendingUp, Pencil, X, Filter, Calculator, Calendar, Info, Star } from 'lucide-react';

const CorrectionIndices = () => {
  const { indices, addIndex, updateIndex, deleteIndex } = useConsortium();

  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    month: new Date().toISOString().slice(0, 7), // YYYY-MM
    type: CorrectionIndex.INCC,
    rate: 0.5 // Default 0.5%
  });

  // Filter State
  const [filterStart, setFilterStart] = useState('');
  const [filterEnd, setFilterEnd] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Normalize date
    const dateStr = `${form.month}-01`;

    // 1. DUPLICATE CHECK
    const isDuplicate = indices.some(idx => 
      idx.type === form.type && 
      idx.date === dateStr && 
      idx.id !== editingId
    );

    if (isDuplicate) {
      alert(`Já existe um índice ${form.type} cadastrado para o mês ${form.month}. Não é permitido duplicidade.`);
      return;
    }

    const indexData: MonthlyIndex = {
      id: editingId || crypto.randomUUID(),
      type: form.type,
      date: dateStr, 
      rate: Number(form.rate)
    };

    if (editingId) {
      updateIndex(indexData);
      setEditingId(null); 
    } else {
      addIndex(indexData);
    }

    // Reset values for next entry
    setForm({
        month: new Date().toISOString().slice(0, 7),
        type: form.type, 
        rate: 0.5
    });
  };

  const handleEdit = (idx: MonthlyIndex) => {
    setEditingId(idx.id);
    setForm({
      month: idx.date.slice(0, 7), 
      type: idx.type,
      rate: idx.rate
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setForm({
      month: new Date().toISOString().slice(0, 7),
      type: CorrectionIndex.INCC,
      rate: 0.5
    });
  };

  // --- FILTER & SORT LOGIC ---
  const sortedIndices = [...indices].sort((a, b) => 
    b.date.localeCompare(a.date)
  );

  const filteredIndices = sortedIndices.filter(idx => {
    const idxMonth = idx.date.slice(0, 7); // YYYY-MM
    if (filterStart && idxMonth < filterStart) return false;
    if (filterEnd && idxMonth > filterEnd) return false;
    return true;
  });

  // Comprehensive Calculation: Simple vs Compound
  const getIndexStats = (type: CorrectionIndex) => {
    const relevant = filteredIndices.filter(i => i.type === type);
    const simpleSum = relevant.reduce((acc, curr) => acc + curr.rate, 0);
    const totalFactor = relevant.reduce((acc, curr) => {
        return acc * (1 + (curr.rate / 100));
    }, 1.0);

    return {
        compound: (totalFactor - 1) * 100,
        simple: simpleSum,
        count: relevant.length
    };
  };

  const statsINCC = getIndexStats(CorrectionIndex.INCC);
  const statsIPCA = getIndexStats(CorrectionIndex.IPCA);
  const statsCDI = getIndexStats(CorrectionIndex.CDI);

  const SummaryCard = ({ title, stats, colorClass }: { title: string, stats: any, colorClass: string }) => (
