import React, { useState, useMemo } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { formatCurrency, formatPercent, formatDate } from '../utils/formatters';
import { Pencil, Search, DollarSign, Gavel, TrendingUp, Calculator, PieChart, FileText, Info, ArrowUpRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { generateSchedule } from '../services/calculationService';

const Simulation = () => {
  const { quotas, currentQuota, setCurrentQuota, installments, updateInstallmentPayment, companies, administrators, indices } = useConsortium();
  const navigate = useNavigate();

  const [searchText, setSearchText] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterAdmin, setFilterAdmin] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [editingCell, setEditingCell] = useState<{ id: number, field: 'payment' | 'fc' | 'fr' | 'ta' | 'fine' | 'interest' } | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  const filteredOptions = useMemo(() => {
    return quotas.filter(q => {
      const textMatch = (q.group || '').toLowerCase().includes(searchText.toLowerCase()) || (q.quotaNumber || '').toLowerCase().includes(searchText.toLowerCase());
      const companyMatch = filterCompany ? q.companyId === filterCompany : true;
      const adminMatch = filterAdmin ? q.administratorId === filterAdmin : true;
      let statusMatch = true;
      if (filterStatus === 'ACTIVE') statusMatch = !q.isContemplated;
      if (filterStatus === 'CONTEMPLATED') statusMatch = q.isContemplated;
      return textMatch && companyMatch && adminMatch && statusMatch;
    });
  }, [quotas, searchText, filterCompany, filterAdmin, filterStatus]);

  const summaryStats = useMemo(() => {
      const todayStr = new Date().toISOString().split('T')[0];
      let paidFC = 0, paidFR = 0, paidTA = 0, paidFine = 0, paidInterest = 0;
      let dueFC = 0, dueFR = 0, dueTA = 0, dueFine = 0, dueInterest = 0;
      let qtdeToPay = 0;
      const processInstallment = (inst: any) => {
          const isMatured = inst.dueDate.split('T')[0] <= todayStr;
          if (isMatured) {
              paidFC += inst.commonFund; paidFR += inst.reserveFund; paidTA += inst.adminFee; paidFine += (inst.manualFine || 0); paidInterest += (inst.manualInterest || 0);
          } else {
              dueFC += inst.commonFund; dueFR += inst.reserveFund; dueTA += inst.adminFee; dueFine += (inst.manualFine || 0); dueInterest += (inst.manualInterest || 0);
              qtdeToPay++;
          }
          if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
              paidFC += (inst.bidAbatementFC || 0); paidFR += (inst.bidAbatementFR || 0); paidTA += (inst.bidAbatementTA || 0);
          }
      };
      if (currentQuota) installments.forEach(processInstallment);
      else filteredOptions.forEach(q => generateSchedule(q, indices).forEach(processInstallment));
      const totalPaidReal = paidFC + paidFR + paidTA + paidFine + paidInterest;
      const totalDue = dueFC + dueFR + dueTA + dueFine + dueInterest;
      const safeTotal = (totalPaidReal + totalDue) || 1;
      return { paidFC, paidFR, paidTA, paidFine, paidInterest, totalPaidReal, dueFC, dueFR, dueTA, dueFine, dueInterest, totalDue, qtdeToPay, safeTotal };
  }, [currentQuota, installments, filteredOptions, indices]);

  const handleEditClick = (id: number, field: any, currentValue: any, defaultValue: any) => {
    setEditingCell({ id, field });
    setEditValue(currentValue !== undefined && currentValue !== null ? currentValue.toString() : defaultValue.toFixed(2));
  };

  const handleSaveEdit = (installmentNum: number) => {
    if (!editingCell) return;
    const val = parseFloat(editValue);
    if (isNaN(val)) { setEditingCell(null); return; }
    if (editingCell.field === 'payment') updateInstallmentPayment(installmentNum, { amount: val });
    else if (editingCell.field === 'fc') updateInstallmentPayment(installmentNum, { fc: val });
    else if (editingCell.field === 'fr') updateInstallmentPayment(installmentNum, { fr: val });
    else if (editingCell.field === 'ta') updateInstallmentPayment(installmentNum, { ta: val });
    else if (editingCell.field === 'fine') updateInstallmentPayment(installmentNum, { fine: val });
    else if (editingCell.field === 'interest') updateInstallmentPayment(installmentNum, { interest: val });
    setEditingCell(null);
  };

  const renderEditableCell = (inst: any, field: any, value: number, isManual: boolean, align: 'left' | 'right' | 'center' = 'right', secondaryValue?: string) => {
    const isEditing = editingCell?.id === inst.installmentNumber && editingCell?.field === field;
    if (isEditing) return (<td className={`p-2 ${align === 'right' ? 'text-right' : ''}`}><input autoFocus type="text" className="w-full p-1 border border-blue-400 rounded text-right text-xs" value={editValue} onChange={(e) => setEditValue(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') handleSaveEdit(inst.installmentNumber); if (e.key === 'Escape') setEditingCell(null); }} onBlur={() => handleSaveEdit(inst.installmentNumber)} /></td>);
    let cellClass = "cursor-pointer transition-colors hover:bg-slate-100 ";
    let contentClass = "";
    if (field === 'payment') { if (inst.realAmountPaid !== null) cellClass += "bg-indigo-50 hover:bg-indigo-100 text-indigo-700 font-bold"; else contentClass = "text-slate-300"; }
    else if (isManual) cellClass += "bg-blue-50 hover:bg-blue-100 text-blue-700 font-medium"; else contentClass = "text-slate-500";
    return (<td className={`p-3 ${align === 'right' ? 'text-right' : ''} ${cellClass}`} onClick={() => handleEditClick(inst.installmentNumber, field, (isManual || (field === 'payment' && inst.realAmountPaid !== null)) ? value : undefined, value)} title="Clique para editar"><div className="flex flex-col items-end"><span className={contentClass}>{(field === 'payment' && inst.realAmountPaid === null) ? '-' : formatCurrency(value)}</span>{secondaryValue && (<span className="text-[10px] text-slate-400 font-normal">{secondaryValue}</span>)}</div></td>);
  };

  const formatMonthYear = (dateStr?: string) => dateStr ? new Date(dateStr).toLocaleDateString('pt-BR', { month: '2-digit', year: 'numeric' }) : '';
  const formatSummaryPercent = (val: number) => isNaN(val) ? '0,0000' : val.toLocaleString('pt-BR', { minimumFractionDigits: 4, maximumFractionDigits: 4 });
  const formatBalancePercent = (val: number) => isNaN(val) ? '0,00%' : val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + '%';

  const todayStr = new Date().toISOString().split('T')[0];
  let currentDisplayCredit = 0;
  if (currentQuota && installments.length > 0) {
      const pastOrPresent = installments.filter(i => i.dueDate.split('T')[0] <= todayStr);
      currentDisplayCredit = pastOrPresent.length > 0 ? pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || currentQuota.creditValue : installments[0].correctedCreditValue || currentQuota.creditValue;
  } else if (currentQuota) currentDisplayCredit = currentQuota.creditValue;

  const totalDueToDate = installments.reduce((acc, inst) => inst.dueDate.split('T')[0] <= todayStr ? acc + inst.totalInstallment : acc, 0);
  const totalFC = installments.reduce((acc, inst) => acc + inst.commonFund, 0);
  const totalFR = installments.reduce((acc, inst) => acc + inst.reserveFund, 0);

  const footerTotals = useMemo(() => installments.reduce((acc, inst) => ({ fc: acc.fc + inst.commonFund, fr: acc.fr + inst.reserveFund, ta: acc.ta + inst.adminFee, fine: acc.fine + (inst.manualFine || 0), interest: acc.interest + (inst.manualInterest || 0), total: acc.total + inst.totalInstallment }), { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, total: 0 }), [installments]);
  const footerPercents = { fc: (footerTotals.fc / (currentDisplayCredit || 1)) * 100, fr: (footerTotals.fr / (currentDisplayCredit || 1)) * 100, ta: (footerTotals.ta / (currentDisplayCredit || 1)) * 100 };

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col gap-4">
        <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2"><Calculator className="text-emerald-600" /> Simulação & Pagamentos</h2>
             {currentQuota && <button onClick={() => navigate(`/edit/${currentQuota.id}`)} className="px-3 py-1.5 text-blue-600 hover:bg-blue-50 rounded-lg border border-blue-200 text-sm font-medium flex items-center gap-2"><Pencil size={16} /> Editar Cota Atual</button>}
        </div>
        <div className="grid grid-cols-1 md:grid-cols-12 gap-3 bg-white p-3 rounded-lg border border-slate-200 shadow-sm">
             <div className="md:col-span-3 relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} /><input type="text" placeholder="Pesquisar cota..." value={searchText} onChange={(e) => setSearchText(e.target.value)} className="w-full pl-9 pr-2 py-2 text-sm border border-slate-300 rounded-md focus:ring-1 focus:ring-emerald-500 outline-none" /></div>
             <div className="md:col-span-2"><select value={filterCompany} onChange={(e) => setFilterCompany(e.target.value)} className="w-full py-2 px-2 text-sm border border-slate-300 rounded-md focus:ring-1 focus:ring-emerald-500 outline-none text-slate-600"><option value="">Empresas</option>{companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></div>
             <div className="md:col-span-2"><select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="w-full py-2 px-2 text-sm border border-slate-300 rounded-md focus:ring-1 focus:ring-emerald-500 outline-none text-slate-600"><option value="">Status</option><option value="ACTIVE">Em Andamento</option><option value="CONTEMPLATED">Contempladas</option></select></div>
             <div className="md:col-span-5"><select className="w-full py-2 px-2 text-sm font-semibold text-emerald-800 bg-emerald-50 border border-emerald-200 rounded-md outline-none focus:ring-2 focus:ring-emerald-500" value={currentQuota?.id || ''} onChange={(e) => { const found = quotas.find(q => q.id === e.target.value); setCurrentQuota(found || null); }}><option value="">Selecionar Cota ({filteredOptions.length})</option>{filteredOptions.map(q => (<option key={q.id} value={q.id}>{q.group} - {q.quotaNumber} {q.companyId ? `(${companies.find(c => c.id === q.companyId)?.name})` : ''}</option>))}</select></div>
        </div>
      </div>

      {currentQuota && (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
           <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm"><p className="text-xs text-slate-500 uppercase font-semibold flex items-center gap-1"><DollarSign size={14}/> Crédito Base (Contemplação)</p><p className="text-xl font-bold text-emerald-600">{formatCurrency(currentDisplayCredit || 0)}</p></div>
           <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm"><p className="text-xs text-slate-500 uppercase font-semibold flex items-center gap-1"><Calculator size={14}/> Total Pago</p><p className="text-xl font-bold text-slate-700">{formatCurrency(totalDueToDate)}</p></div>
           <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm"><p className="text-xs text-slate-500 uppercase font-semibold flex items-center gap-1"><PieChart size={14}/> Total FC Plano</p><p className="text-lg font-medium text-blue-600">{formatCurrency(totalFC)}</p></div>
           <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm"><p className="text-xs text-slate-500 uppercase font-semibold flex items-center gap-1"><PieChart size={14}/> Total FR Plano</p><p className="text-lg font-medium text-amber-600">{formatCurrency(totalFR)}</p></div>
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200 text-xs">
                <tr>
                  <th className="p-2 text-center bg-slate-100 sticky left-0 z-10 w-10">P</th>
                  <th className="p-2 min-w-[80px]">Venc</th>
                  <th className="p-2 text-right min-w-[90px]">FC Mensal ✏️</th>
                  <th className="p-2 text-right min-w-[90px]">FR Mensal ✏️</th>
                  <th className="p-2 text-right min-w-[90px]">TA Mensal ✏️</th>
                  <th className="p-2 text-right min-w-[70px]">Multa ✏️</th>
                  <th className="p-2 text-right min-w-[70px]">Juros ✏️</th>
                  <th className="p-2 text-right font-bold bg-emerald-50 text-emerald-800 min-w-[100px]">Total Pago</th>
                  <th className="p-2 text-right bg-slate-50 min-w-[100px]">Saldo Dev Total</th>
                  <th className="p-2 text-right bg-slate-50 w-[60px] text-[10px]">%</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {installments.map((inst) => (
                  <React.Fragment key={inst.installmentNumber}>
                  {inst.correctionApplied && (
                      <tr className="bg-blue-50 border-y border-blue-100">
                         <td className="p-2 text-center text-blue-600 sticky left-0 bg-blue-50 z-10"><TrendingUp size={14} className="mx-auto"/></td>
                         <td colSpan={15} className="p-2 text-blue-800 text-xs font-bold uppercase tracking-wide">{inst.correctionIndexName} Acumulado: {formatPercent((inst.correctionFactor || 0) * 100)} <span className="ml-2 font-normal opacity-75">(Crédito: {formatCurrency(inst.correctedCreditValue || 0)})</span></td>
                      </tr>
                  )}
                  {(inst.bidAmountApplied ?? 0) > 0 && (
                    <tr className="bg-amber-50 border-y border-amber-100">
                        <td className="p-3 text-center font-bold text-amber-700 sticky left-0 bg-amber-50 z-10"><Gavel size={16} className="mx-auto" /></td>
                        <td className="p-3 text-left">
                            <div className="flex flex-col">
                                <span className="font-bold text-amber-800 text-xs uppercase">LANCE APLICADO</span>
                                <span className="text-[9px] text-amber-600 flex items-center gap-1 mt-1">
                                    <Info size={10}/> Base: {formatCurrency(inst.bidCalcBaseUsed || 0)}
                                </span>
                            </div>
                        </td>
                        <td className="p-3 text-right text-amber-700 font-semibold text-xs">-{formatCurrency(inst.bidAbatementFC || 0)}<span className="block text-[9px] font-normal opacity-70">{formatSummaryPercent((inst.bidFreePercentFC||0) + (inst.bidEmbeddedPercentFC||0))}%</span></td>
                        <td className="p-3 text-right text-amber-700 font-semibold text-xs">-{formatCurrency(inst.bidAbatementFR || 0)}<span className="block text-[9px] font-normal opacity-70">{formatSummaryPercent((inst.bidFreePercentFR||0) + (inst.bidEmbeddedPercentFR||0))}%</span></td>
                        <td className="p-3 text-right text-amber-700 font-semibold text-xs">-{formatCurrency(inst.bidAbatementTA || 0)}<span className="block text-[9px] font-normal opacity-70">{formatSummaryPercent((inst.bidFreePercentTA||0) + (inst.bidEmbeddedPercentTA||0))}%</span></td>
                        <td colSpan={2}></td>
                        <td className="p-3 text-right font-bold text-amber-800">
                            <div className="flex flex-col items-end">
                                <span>-{formatCurrency(inst.bidAmountApplied || 0)}</span>
                                <span className="text-[10px] text-amber-600 bg-amber-100 px-1 rounded flex items-center gap-0.5">
                                   {formatSummaryPercent((inst.bidFreePercent||0) + (inst.bidEmbeddedPercent||0))}% <ArrowUpRight size={10}/>
                                </span>
                            </div>
                        </td>
                        <td className="p-3 text-right text-amber-800 font-bold text-xs">{formatCurrency(inst.balanceTotal + inst.totalInstallment)}</td>
                        <td className="p-3"></td>
                    </tr>
                  )}
                  <tr className="hover:bg-slate-50 transition-colors group">
                    <td className="p-3 text-center font-medium sticky left-0 bg-white group-hover:bg-slate-50 z-10 border-r border-slate-100">{inst.installmentNumber}</td>
                    <td className="p-3 text-slate-600">{formatDate(inst.dueDate)}</td>
                    {renderEditableCell(inst, 'fc', inst.commonFund, inst.manualFC !== undefined && inst.manualFC !== null, 'right', inst.monthlyRateFC ? `${formatSummaryPercent(inst.monthlyRateFC)}%` : undefined)}
                    {renderEditableCell(inst, 'fr', inst.reserveFund, inst.manualFR !== undefined && inst.manualFR !== null, 'right', inst.monthlyRateFR ? `${formatSummaryPercent(inst.monthlyRateFR)}%` : undefined)}
                    {renderEditableCell(inst, 'ta', inst.adminFee, inst.manualTA !== undefined && inst.manualTA !== null, 'right', inst.monthlyRateTA ? `${formatSummaryPercent(inst.monthlyRateTA)}%` : undefined)}
                    {renderEditableCell(inst, 'fine', inst.manualFine || 0, inst.manualFine !== undefined && inst.manualFine !== null)}
                    {renderEditableCell(inst, 'interest', inst.manualInterest || 0, inst.manualInterest !== undefined && inst.manualInterest !== null)}
                    <td className="p-3 text-right font-bold text-emerald-700 bg-emerald-50/30">{formatCurrency(inst.totalInstallment || 0)}</td>
                    <td className="p-3 text-right text-slate-500 font-medium">{formatCurrency(inst.balanceTotal || 0)}</td>
                    <td className="p-3 text-right text-slate-400 text-[10px]">{formatBalancePercent(inst.percentBalanceTotal)}</td>
                  </tr>
                  </React.Fragment>
                ))}
              </tbody>
              <tfoot className="bg-slate-200 font-bold text-slate-800 border-t-2 border-slate-300">
                  <tr>
                      <td className="p-3 text-center sticky left-0 bg-slate-200 z-10 border-r border-slate-300">Total</td>
                      <td className="p-3"></td>
                      <td className="p-3 text-right"><div className="flex flex-col items-end"><span>{formatCurrency(footerTotals.fc)}</span><span className="text-[10px] text-slate-600 font-normal">{formatSummaryPercent(footerPercents.fc)}%</span></div></td>
                      <td className="p-3 text-right"><div className="flex flex-col items-end"><span>{formatCurrency(footerTotals.fr)}</span><span className="text-[10px] text-slate-600 font-normal">{formatSummaryPercent(footerPercents.fr)}%</span></div></td>
                      <td className="p-3 text-right"><div className="flex flex-col items-end"><span>{formatCurrency(footerTotals.ta)}</span><span className="text-[10px] text-slate-600 font-normal">{formatSummaryPercent(footerPercents.ta)}%</span></div></td>
                      <td className="p-3 text-right text-red-600">{formatCurrency(footerTotals.fine)}</td>
                      <td className="p-3 text-right text-red-600">{formatCurrency(footerTotals.interest)}</td>
                      <td className="p-3 text-right font-black text-emerald-800">{formatCurrency(footerTotals.total)}</td>
                      <td colSpan={2} className="p-3 text-right text-slate-500 text-[10px] italic font-normal">* Conferência baseada nos lançamentos acima</td>
                  </tr>
              </tfoot>
            </table>
          </div>
        </div>
    </div>
  );
};

