}

const Reports = () => {
  const { quotas, indices, updateQuota, administrators, companies, allCreditUsages } = useConsortium();
  const [reportData, setReportData] = useState<ReportRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<{ id: string, field: 'credit' } | null>(null);
  const [editValue, setEditValue] = useState('');
  const [saveError, setSaveError] = useState<string | null>(null);

  const [filterAdmin, setFilterAdmin] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterStatus, setFilterStatus] = useState(''); 
  const [referenceDate, setReferenceDate] = useState(new Date().toISOString().split('T')[0]);
  const [sortConfig, setSortConfig] = useState<{ key: keyof ReportRow, direction: 'asc' | 'desc' } | null>(null);

  const formatNumber = (val: number) => val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  useEffect(() => {
    const buildReport = async () => {
      setLoading(true);
      const refDateStr = referenceDate;
      try {
        const allPayments = await db.getAllPaymentsDictionary();
        const rows = quotas.map(quota => {
          const schedule = generateSchedule(quota, indices);
          let currentCredit = quota.creditValue;
          if (schedule.length > 0) {
             const pastOrPresent = schedule.filter(i => i.dueDate.split('T')[0] <= refDateStr);
             currentCredit = pastOrPresent.length > 0 ? pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || quota.creditValue : quota.creditValue;
          }

          let sumVencido = 0;
          let sumAVencer = 0;
          const paymentMap = allPayments[quota.id] || {};

          schedule.forEach(inst => {
              const instDateStr = inst.dueDate.split('T')[0];
              const isMatured = instDateStr <= refDateStr;
              const paymentData = paymentMap[inst.installmentNumber];

              if (isMatured) {
                  const fine = paymentData?.manualFine || inst.manualFine || 0;
                  const interest = paymentData?.manualInterest || inst.manualInterest || 0;
                  sumVencido += inst.commonFund + inst.reserveFund + inst.adminFee + fine + interest;
              } else {
                  sumAVencer += inst.commonFund + inst.reserveFund + inst.adminFee;
              }

              if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
                  sumVencido += (inst.bidAbatementFC || 0) + (inst.bidAbatementFR || 0) + (inst.bidAbatementTA || 0);
              }
          });

          const totalContractValue = sumVencido + sumAVencer || 1;
          const correction92CDI = calculateCDICorrection(quota.bidFree || 0, quota.contemplationDate, indices);
          const valorLiquido = currentCredit - (quota.bidEmbedded || 0);
          const creditoTotal = valorLiquido + (quota.creditManualAdjustment || 0);
          const quotaUsages = allCreditUsages.filter(u => u.quotaId === quota.id && u.date <= refDateStr);
          const creditoUtilizado = quotaUsages.reduce((sum, u) => sum + u.amount, 0);

          return {
            id: quota.id,
            group: quota.group,
            quotaNumber: quota.quotaNumber,
            creditValue: currentCredit,
            isContemplated: quota.isContemplated,
            administratorId: quota.administratorId,
            companyId: quota.companyId,
            saldoAVencer: sumAVencer,
            percentAVencer: (sumAVencer / totalContractValue) * 100,
            saldoVencido: sumVencido,
            percentVencido: (sumVencido / totalContractValue) * 100,
            bidTotal: quota.bidTotal || 0,
            percentBidTotal: currentCredit > 0 ? ((quota.bidTotal || 0) / currentCredit) * 100 : 0,
            bidFree: quota.bidFree || 0,
            bidEmbedded: quota.bidEmbedded || 0,
            valorRealCarta: valorLiquido,
            creditManualAdjustment: quota.creditManualAdjustment || 0,
            creditoTotal: creditoTotal,
            bidFreeCorrection: correction92CDI,
            creditoUtilizado,
            saldoDisponivel: creditoTotal - creditoUtilizado
          };
        });
        setReportData(rows);
      } catch (err) { console.error(err); } finally { setLoading(false); }
    };
    buildReport();
  }, [quotas, indices, allCreditUsages, referenceDate]);

  const handleSaveEdit = async () => {
    if (!editingId) return;
    const normalizedValue = editValue.replace(/\./g, '').replace(',', '.');
    const newVal = parseFloat(normalizedValue);
    if (isNaN(newVal)) { setEditingId(null); return; }
    const quota = quotas.find(q => q.id === editingId.id);
    if (quota) {
      try {
        await updateQuota({ ...quota, creditManualAdjustment: newVal });
        setEditingId(null);
      } catch (error) { setSaveError("Erro ao salvar."); }
    }
  };

  const filteredData = reportData.filter(row => {
    const matchAdmin = !filterAdmin || row.administratorId === filterAdmin;
    const matchComp = !filterCompany || row.companyId === filterCompany;
    let matchStatus = true;
    if (filterStatus === 'CONTEMPLATED') matchStatus = row.isContemplated;
    else if (filterStatus === 'ACTIVE') matchStatus = !row.isContemplated;
    return matchAdmin && matchComp && matchStatus;
  });

  const sortedData = useMemo(() => {
    let items = [...filteredData];
    if (sortConfig) {
      items.sort((a, b) => {
        if (sortConfig.key === 'quotaNumber') {
          return sortConfig.direction === 'asc' ? (parseInt(a.quotaNumber) - parseInt(b.quotaNumber)) : (parseInt(b.quotaNumber) - parseInt(a.quotaNumber));
        }
        return sortConfig.direction === 'asc' ? (a[sortConfig.key] > b[sortConfig.key] ? 1 : -1) : (a[sortConfig.key] < b[sortConfig.key] ? 1 : -1);
      });
    }
    return items;
  }, [filteredData, sortConfig]);

  const totals = sortedData.reduce((acc, row) => ({
    saldoAVencer: acc.saldoAVencer + row.saldoAVencer,
    saldoVencido: acc.saldoVencido + row.saldoVencido,
    bidTotal: acc.bidTotal + row.bidTotal,
    valorRealCarta: acc.valorRealCarta + row.valorRealCarta,
    creditoTotal: acc.creditoTotal + row.creditoTotal,
    creditoUtilizado: acc.creditoUtilizado + row.creditoUtilizado,
    saldoDisponivel: acc.saldoDisponivel + row.saldoDisponivel
  }), { saldoAVencer: 0, saldoVencido: 0, bidTotal: 0, valorRealCarta: 0, creditoTotal: 0, creditoUtilizado: 0, saldoDisponivel: 0 });

  const SortHeader = ({ label, sortKey, align = 'right', className = '' }: { label: string, sortKey: keyof ReportRow, align?: 'left'|'right', className?: string }) => (
      <th className={`px-2 py-3 cursor-pointer hover:bg-slate-800 transition-colors group select-none ${className} ${align === 'right' ? 'text-right' : 'text-left'}`} onClick={() => setSortConfig({ key: sortKey, direction: sortConfig?.key === sortKey && sortConfig.direction === 'asc' ? 'desc' : 'asc' })}>
        <div className={`flex items-center gap-1 ${align === 'right' ? 'justify-end' : 'justify-start'}`}>{label} <ArrowUpDown size={10} className="opacity-30 group-hover:opacity-100" /></div>
      </th>
  );

  return (
    <div className="space-y-6 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Relatório por Cota</h1>
           <p className="text-slate-500">Acompanhamento de saldos, lances e créditos disponíveis.</p>
        </div>
        <button onClick={() => window.print()} className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 font-medium print:hidden">Imprimir Relatório</button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-4 print:hidden">
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Data Fechamento</label><input type="date" value={referenceDate} onChange={(e) => setReferenceDate(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none" /></div>
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Empresa</label><select value={filterCompany} onChange={(e) => setFilterCompany(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none">{companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}<option value="">Todas</option></select></div>
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Administradora</label><select value={filterAdmin} onChange={(e) => setFilterAdmin(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none">{administrators.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}<option value="">Todas</option></select></div>
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Status</label><select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none"><option value="">Todas</option><option value="CONTEMPLATED">Contempladas</option><option value="ACTIVE">Em Andamento</option></select></div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-3">
          {[
              { label: 'Saldo Vencido', value: totals.saldoVencido, color: 'text-emerald-700', bg: 'bg-emerald-50' },
              { label: 'Saldo A Vencer', value: totals.saldoAVencer, color: 'text-red-700', bg: 'bg-red-50' },
              { label: 'Total Lances', value: totals.bidTotal, color: 'text-amber-700', bg: 'bg-amber-50' },
              { label: 'Vlr Carta Líq.', value: totals.valorRealCarta, color: 'text-blue-700', bg: 'bg-blue-50' },
              { label: 'Crédito Total', value: totals.creditoTotal, color: 'text-slate-800', bg: 'bg-slate-100' },
              { label: 'Utilizado', value: totals.creditoUtilizado, color: 'text-orange-700', bg: 'bg-orange-50' },
              { label: 'Disponível', value: totals.saldoDisponivel, color: 'text-emerald-800', bg: 'bg-emerald-100 border-emerald-200' },
          ].map((t, i) => (
              <div key={i} className={`${t.bg} border border-slate-200/60 p-3 rounded-lg shadow-sm`}>
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">{t.label}</p>
                  <p className={`text-sm font-black ${t.color}`}>{formatNumber(t.value)}</p>
              </div>
          ))}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-[10px] text-left border-collapse">
              <thead className="bg-slate-800 text-white uppercase tracking-tighter">
                <tr>
                  <SortHeader label="Cota" sortKey="quotaNumber" align="left" className="sticky left-0 bg-slate-800 z-10 border-r border-slate-700" />
                  <SortHeader label="Vlr Carta" sortKey="creditValue" />
                  <SortHeader label="S. Vencido" sortKey="saldoVencido" className="bg-emerald-900/30" />
                  <SortHeader label="S. A Vencer" sortKey="saldoAVencer" className="bg-red-900/30" />
                  <SortHeader label="Lance Tot." sortKey="bidTotal" className="bg-amber-900/30" />
                  <SortHeader label="Vlr Líquido" sortKey="valorRealCarta" />
                  <SortHeader label="Ajuste" sortKey="creditManualAdjustment" />
                  <SortHeader label="92% CDI" sortKey="bidFreeCorrection" />
                  <SortHeader label="Créd. Total" sortKey="creditoTotal" className="bg-slate-700 font-bold" />
                  <SortHeader label="Utilizado" sortKey="creditoUtilizado" />
                  <SortHeader label="Saldo Disp." sortKey="saldoDisponivel" className="bg-emerald-900 border-l border-emerald-700 font-bold" />
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {loading ? (<tr><td colSpan={15} className="p-10 text-center"><Loader className="animate-spin mx-auto mb-2" /> Carregando dados...</td></tr>) : 
                 sortedData.map(row => (
                  <tr key={row.id} className="hover:bg-slate-50">
                    <td className="p-2 font-bold text-slate-700 sticky left-0 bg-white border-r border-slate-100 shadow-sm">{row.group}/{row.quotaNumber}</td>
                    <td className="p-2 text-right">{formatNumber(row.creditValue)}</td>
                    <td className="p-2 text-right font-medium text-emerald-700 bg-emerald-50/30">{formatNumber(row.saldoVencido)}</td>
                    <td className="p-2 text-right font-medium text-red-600 bg-red-50/30">{formatNumber(row.saldoAVencer)}</td>
                    <td className="p-2 text-right font-medium text-amber-600 bg-amber-50/30">{formatNumber(row.bidTotal)}</td>
                    <td className="p-2 text-right">{formatNumber(row.valorRealCarta)}</td>
                    <td className="p-2 text-right text-blue-600 cursor-pointer" onClick={() => { setEditingId({id: row.id, field: 'credit'}); setEditValue(row.creditManualAdjustment.toString().replace('.',',')); }}>{formatNumber(row.creditManualAdjustment)}</td>
                    <td className="p-2 text-right text-violet-600">{formatNumber(row.bidFreeCorrection)}</td>
                    <td className="p-2 text-right font-bold bg-slate-50">{formatNumber(row.creditoTotal)}</td>
                    <td className="p-2 text-right text-amber-700">{formatNumber(row.creditoUtilizado)}</td>
                    <td className="p-2 text-right font-bold text-emerald-800 bg-emerald-50 border-l border-emerald-100">{formatNumber(row.saldoDisponivel)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
      </div>
      {editingId && (
          <div className="fixed inset-0 bg-black/20 flex items-center justify-center z-50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Ajuste Manual de Crédito</h3>
                  <input autoFocus type="text" value={editValue} onChange={e => setEditValue(e.target.value)} className="w-full border p-2 rounded mb-4" placeholder="0,00" />
                  <div className="flex gap-2">
                      <button onClick={() => setEditingId(null)} className="flex-1 p-2 border rounded">Cancelar</button>
                      <button onClick={handleSaveEdit} className="flex-1 p-2 bg-emerald-600 text-white rounded">Salvar</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Reports;

import React, { useState } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { CorrectionIndex, MonthlyIndex } from '../types';
import { Trash2, Plus, TrendingUp, Pencil, X, Filter, Calculator, Calendar, Info, Star } from 'lucide-react';

const CorrectionIndices = () => {
  const { indices, addIndex, updateIndex, deleteIndex } = useConsortium();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({
    month: new Date().toISOString().slice(0, 7),
    type: CorrectionIndex.INCC,
    rate: 0.5
  });

  const [filterStart, setFilterStart] = useState('');
  const [filterEnd, setFilterEnd] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateStr = `${form.month}-01`;
    if (indices.some(idx => idx.type === form.type && idx.date === dateStr && idx.id !== editingId)) {
      alert("Índice já cadastrado para este mês."); return;
    }
    const indexData: MonthlyIndex = { id: editingId || crypto.randomUUID(), type: form.type, date: dateStr, rate: Number(form.rate) };
    editingId ? updateIndex(indexData) : addIndex(indexData);
    setEditingId(null);
    setForm({ month: new Date().toISOString().slice(0, 7), type: form.type, rate: 0.5 });
  };

  const filteredIndices = [...indices].sort((a, b) => b.date.localeCompare(a.date)).filter(idx => {
    const m = idx.date.slice(0, 7);
    if (filterStart && m < filterStart) return false;
    if (filterEnd && m > filterEnd) return false;
    return true;
  });

  const getStats = (type: CorrectionIndex) => {
    const items = filteredIndices.filter(i => i.type === type);
    const simple = items.reduce((a, b) => a + b.rate, 0);
    const compound = (items.reduce((a, b) => a * (1 + b.rate/100), 1) - 1) * 100;
    return { simple, compound, count: items.length };
  };

  const Summary = ({ title, type, color }: any) => {
      const s = getStats(type);
      return (
          <div className={`bg-white p-4 rounded-xl border-l-4 ${color} shadow-sm flex-1`}>
              <p className="text-[10px] font-bold text-slate-400 uppercase">{title}</p>
              <div className="flex items-baseline gap-2">
                  <span className="text-lg font-black text-slate-800">{s.compound.toFixed(4)}%</span>
                  <span className="text-xs text-slate-400">(Soma: {s.simple.toFixed(2)}%)</span>
              </div>
              <p className="text-[9px] text-slate-400 mt-1">{s.count} meses selecionados</p>
          </div>
      );
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      <div className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-slate-800">Índices de Correção</h1>
          <div className="flex gap-2 print:hidden">
              <input type="month" value={filterStart} onChange={e => setFilterStart(e.target.value)} className="border rounded p-1 text-xs" />
              <input type="month" value={filterEnd} onChange={e => setFilterEnd(e.target.value)} className="border rounded p-1 text-xs" />
              {(filterStart || filterEnd) && <button onClick={() => {setFilterStart(''); setFilterEnd('');}} className="text-red-500"><X size={16}/></button>}
          </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4">
          <Summary title="INCC Acumulado" type={CorrectionIndex.INCC} color="border-blue-500" />
          <Summary title="IPCA Acumulado" type={CorrectionIndex.IPCA} color="border-orange-500" />
          <Summary title="CDI Acumulado" type={CorrectionIndex.CDI} color="border-violet-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
              <h2 className="font-bold mb-4 flex items-center gap-2">{editingId ? <Pencil size={18}/> : <Plus size={18}/>} {editingId ? 'Editar' : 'Novo Lançamento'}</h2>
              <form onSubmit={handleSubmit} className="space-y-4">
                  <select value={form.type} onChange={e => setForm({...form, type: e.target.value as any})} className="w-full border rounded p-2 text-sm">
                      <optgroup label="Mensais"><option value={CorrectionIndex.INCC}>INCC (Mensal)</option><option value={CorrectionIndex.IPCA}>IPCA (Mensal)</option><option value={CorrectionIndex.CDI}>CDI</option></optgroup>
                      <optgroup label="Acumulados 12m"><option value={CorrectionIndex.INCC_12}>INCC (Anual)</option><option value={CorrectionIndex.IPCA_12}>IPCA (Anual)</option></optgroup>
                  </select>
                  <input type="month" value={form.month} onChange={e => setForm({...form, month: e.target.value})} className="w-full border rounded p-2 text-sm" />
                  <input type="number" step="0.0001" value={form.rate} onChange={e => setForm({...form, rate: parseFloat(e.target.value)})} className="w-full border rounded p-2 text-sm font-bold" />
                  <button type="submit" className="w-full bg-emerald-600 text-white p-2 rounded font-bold">{editingId ? 'Salvar' : 'Adicionar'}</button>
                  {editingId && <button onClick={() => setEditingId(null)} className="w-full text-slate-500 text-xs">Cancelar Edição</button>}
              </form>
          </div>

          <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
              <table className="w-full text-sm text-left">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                      <tr><th className="p-4">Mês</th><th className="p-4">Índice</th><th className="p-4 text-right">Taxa %</th><th className="p-4 text-right">Ações</th></tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                      {filteredIndices.map(idx => (
                          <tr key={idx.id} className="hover:bg-slate-50 transition-colors">
                              <td className="p-4 font-medium">{new Date(idx.date+'T12:00:00').toLocaleDateString('pt-BR', {month:'2-digit', year:'numeric'})}</td>
                              <td className="p-4">
                                  <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${idx.type.includes('12') ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600'}`}>
                                      {idx.type} {idx.type.includes('12') && ' (ANUAL)'}
                                  </span>
                              </td>
                              <td className="p-4 text-right font-bold text-slate-800">{idx.rate.toFixed(4)}%</td>
                              <td className="p-4 text-right">
                                  <button onClick={() => {setEditingId(idx.id); setForm({month: idx.date.slice(0,7), type: idx.type, rate: idx.rate});}} className="p-1 text-blue-500 mr-2"><Pencil size={14}/></button>
                                  <button onClick={() => deleteIndex(idx.id)} className="p-1 text-red-400"><Trash2 size={14}/></button>
                              </td>
                          </tr>
                      ))}
                  </tbody>
              </table>
          </div>
      </div>
    </div>
  );
};

export default CorrectionIndices;

import React, { useState, useMemo } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { formatCurrency, formatPercent, formatDate } from '../utils/formatters';
import { Pencil, Search, DollarSign, Gavel, TrendingUp, Calculator, PieChart, FileText, Info, ArrowUpRight, CheckCircle2, Clock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { generateSchedule } from '../services/calculationService';

const Simulation = () => {
  const { quotas, currentQuota, setCurrentQuota, installments, updateInstallmentPayment, companies, administrators, indices } = useConsortium();
  const navigate = useNavigate();

  const [searchText, setSearchText] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [editingCell, setEditingCell] = useState<{ id: number, field: 'payment' | 'fc' | 'fr' | 'ta' | 'fine' | 'interest' } | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  const filteredOptions = useMemo(() => {
    return quotas.filter(q => {
      const textMatch = (q.group || '').toLowerCase().includes(searchText.toLowerCase()) || (q.quotaNumber || '').toLowerCase().includes(searchText.toLowerCase());
      const companyMatch = filterCompany ? q.companyId === filterCompany : true;
      let statusMatch = true;
      if (filterStatus === 'ACTIVE') statusMatch = !q.isContemplated;
      if (filterStatus === 'CONTEMPLATED') statusMatch = q.isContemplated;
      return textMatch && companyMatch && statusMatch;
    });
  }, [quotas, searchText, filterCompany, filterStatus]);

  const todayStr = new Date().toISOString().split('T')[0];

  // Cálculo de Crédito Atual (Base para percentuais do resumo)
  const currentDisplayCredit = useMemo(() => {
    if (currentQuota && installments.length > 0) {
        const pastOrPresent = installments.filter(i => i.dueDate.split('T')[0] <= todayStr);
        return pastOrPresent.length > 0 ? pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || currentQuota.creditValue : installments[0].correctedCreditValue || currentQuota.creditValue;
    }
    return currentQuota?.creditValue || 0;
  }, [currentQuota, installments, todayStr]);

  // Estatísticas Detalhadas para o Quadro de Resumo (Fiel à imagem)
  const detailedSummary = useMemo(() => {
    const stats = {
        paid: { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, others: 0, total: 0 },
        toPay: { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, others: 0, total: 0, diff: 0 },
        counts: { total: 0, furo: 0 }
    };

    if (!currentQuota) return stats;

    installments.forEach(inst => {
        const isMatured = inst.dueDate.split('T')[0] <= todayStr;

        if (isMatured) {
            stats.paid.fc += inst.commonFund;
            stats.paid.fr += inst.reserveFund;
            stats.paid.ta += inst.adminFee;
            stats.paid.fine += (inst.manualFine || 0);
            stats.paid.interest += (inst.manualInterest || 0);
        } else {
            stats.toPay.fc += inst.commonFund;
            stats.toPay.fr += inst.reserveFund;
            stats.toPay.ta += inst.adminFee;
            stats.toPay.fine += (inst.manualFine || 0);
            stats.toPay.interest += (inst.manualInterest || 0);
            stats.counts.total++;
        }

        // Lances abatem o saldo (entram como pago)
        if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
            stats.paid.fc += (inst.bidAbatementFC || 0);
            stats.paid.fr += (inst.bidAbatementFR || 0);
            stats.paid.ta += (inst.bidAbatementTA || 0);
        }
    });

    stats.paid.total = stats.paid.fc + stats.paid.fr + stats.paid.ta + stats.paid.fine + stats.paid.interest;
    stats.toPay.total = stats.toPay.fc + stats.toPay.fr + stats.toPay.ta + stats.toPay.fine + stats.toPay.interest;

    return stats;
  }, [currentQuota, installments, todayStr]);

  const handleEditClick = (id: number, field: any, currentValue: any, defaultValue: any) => {
    setEditingCell({ id, field });
    setEditValue(currentValue !== undefined && currentValue !== null ? currentValue.toString() : defaultValue.toFixed(2));
  };

  const handleSaveEdit = (installmentNum: number) => {
    if (!editingCell) return;
    const val = parseFloat(editValue.replace(',', '.'));
    if (isNaN(val)) { setEditingCell(null); return; }
    if (editingCell.field === 'payment') updateInstallmentPayment(installmentNum, { amount: val });
    else if (editingCell.field === 'fc') updateInstallmentPayment(installmentNum, { fc: val });
    else if (editingCell.field === 'fr') updateInstallmentPayment(installmentNum, { fr: val });
    else if (editingCell.field === 'ta') updateInstallmentPayment(installmentNum, { ta: val });
    else if (editingCell.field === 'fine') updateInstallmentPayment(installmentNum, { fine: val });
    else if (editingCell.field === 'interest') updateInstallmentPayment(installmentNum, { interest: val });
    setEditingCell(null);
  };

  const renderEditableCell = (inst: any, field: any, value: number, isManual: boolean, align: 'left' | 'right' | 'center' = 'right', secondaryValue?: string) => {
    const isEditing = editingCell?.id === inst.installmentNumber && editingCell?.field === field;
    if (isEditing) return (<td className={`p-2 ${align === 'right' ? 'text-right' : ''}`}><input autoFocus type="text" className="w-full p-1 border border-blue-400 rounded text-right text-xs" value={editValue} onChange={(e) => setEditValue(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') handleSaveEdit(inst.installmentNumber); if (e.key === 'Escape') setEditingCell(null); }} onBlur={() => handleSaveEdit(inst.installmentNumber)} /></td>);
    let cellClass = "cursor-pointer transition-colors hover:bg-slate-50 ";
    if (isManual) cellClass += "bg-blue-50/50 text-blue-700 font-medium";
    return (<td className={`p-2.5 ${align === 'right' ? 'text-right' : ''} ${cellClass} text-xs`} onClick={() => handleEditClick(inst.installmentNumber, field, isManual ? value : undefined, value)} title="Clique para editar"><div className="flex flex-col items-end"><span>{formatCurrency(value)}</span>{secondaryValue && (<span className="text-[9px] text-slate-400 font-normal">{secondaryValue}</span>)}</div></td>);
  };

  const formatSummaryPercent = (val: number) => {
      const base = currentDisplayCredit || 1;
      const pct = (val / base) * 100;
      return pct.toLocaleString('pt-BR', { minimumFractionDigits: 4, maximumFractionDigits: 4 });
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col gap-4">
