                    {renderEditableCell(inst, 'ta', inst.adminFee, inst.manualTA !== undefined && inst.manualTA !== null)}
                    {renderEditableCell(inst, 'fine', inst.manualFine || 0, inst.manualFine !== undefined && inst.manualFine !== null)}
                    {renderEditableCell(inst, 'interest', inst.manualInterest || 0, inst.manualInterest !== undefined && inst.manualInterest !== null)}
                    <td className="p-2 text-right font-bold text-emerald-800 bg-emerald-50/20">{formatCurrency(inst.totalInstallment || 0)}</td>

                    {/* SALDOS RESTAURADOS */}
                    <td className="p-2 text-right border-l border-slate-100 text-slate-600">
                        <div className="flex flex-col items-end">
                            <span>{formatCurrency(inst.balanceFC)}</span>
