                          <div className="flex justify-between items-center"><span>Fundo de Reserva:</span> <div className="flex gap-12"><span>{detailedSummary.paid.fr.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right">{formatSummaryPercent(detailedSummary.paid.fr)}</span></div></div>
                          <div className="flex justify-between items-center"><span>Taxa de Administração:</span> <div className="flex gap-12"><span>{detailedSummary.paid.ta.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right">{formatSummaryPercent(detailedSummary.paid.ta)}</span></div></div>
                          <div className="flex justify-between items-center"><span>Adesão(-):</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>
                          <div className="flex justify-between items-center"><span>Seguros:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>
                          <div className="flex justify-between items-center"><span>Multas:</span> <div className="flex gap-12"><span>{detailedSummary.paid.fine.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right"></span></div></div>
                          <div className="flex justify-between items-center"><span>Juros:</span> <div className="flex gap-12"><span>{detailedSummary.paid.interest.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right"></span></div></div>
                          <div className="flex justify-between items-center"><span>Outros Valores:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right"></span></div></div>

                          <div className="pt-2 border-t border-dotted border-slate-400 flex justify-between items-center font-black text-sm">
                              <span>TOTAL</span>
                              <div className="flex gap-12">
                                  <span>{detailedSummary.paid.total.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span>
