                          <h3 className="text-sm font-medium text-slate-700 uppercase tracking-tight">Valores / Percentuais a Pagar</h3>
                          <div className="h-px bg-slate-300 flex-1"></div>
                      </div>
                      <div className="space-y-1.5 text-xs font-medium text-slate-800">
                          <div className="flex justify-between items-center"><span>Fundo Comum:</span> <div className="flex gap-12"><span>{detailedSummary.toPay.fc.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right">{formatSummaryPercent(detailedSummary.toPay.fc)}</span></div></div>
                          <div className="flex justify-between items-center"><span>Fundo de Reserva:</span> <div className="flex gap-12"><span>{detailedSummary.toPay.fr.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right">{formatSummaryPercent(detailedSummary.toPay.fr)}</span></div></div>
                          <div className="flex justify-between items-center"><span>Taxa de Administração:</span> <div className="flex gap-12"><span>{detailedSummary.toPay.ta.toLocaleString('pt-BR', {minimumFractionDigits:2})}</span> <span className="font-black w-16 text-right">{formatSummaryPercent(detailedSummary.toPay.ta)}</span></div></div>
                          <div className="flex justify-between items-center"><span>Adesão:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>
                          <div className="flex justify-between items-center"><span>Seguros:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,000000</span></div></div>
                          <div className="flex justify-between items-center"><span>Multas:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>
                          <div className="flex justify-between items-center"><span>Juros:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>
                          <div className="flex justify-between items-center"><span>Outros Valores:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>
                          <div className="flex justify-between items-center"><span>Diferença de Parcela:</span> <div className="flex gap-12"><span>0,00</span> <span className="font-black w-16 text-right">0,0000</span></div></div>

                          <div className="pt-2 border-t border-dotted border-slate-400 flex justify-between items-center font-black text-sm">
