export default Simulation;

import { Quota, PaymentInstallment, PaymentPlanType, MonthlyIndex, CorrectionIndex, BidBaseType } from '../types';
import { addMonths } from '../utils/formatters';

// Helper to avoid timezone shifting (UTC vs Local) which causes "date - 1 day" errors
const createLocalDate = (dateStr: string): Date => {
  if(!dateStr) return new Date();
  const cleanDate = dateStr.split('T')[0];
  const [year, month, day] = cleanDate.split('-').map(Number);
  return new Date(year, month - 1, day, 0, 0, 0, 0);
};

export const calculateCDICorrection = (value: number, startDateStr: string | undefined, indices: MonthlyIndex[]): number => {
    if (!value || value <= 0 || !startDateStr) return 0;
    const startDate = createLocalDate(startDateStr);
    startDate.setDate(1); 
    startDate.setHours(0,0,0,0);
    const today = new Date();
    today.setHours(23,59,59,999);
    const relevantIndices = indices.filter(idx => {
        if (idx.type !== CorrectionIndex.CDI) return false;
        const idxDate = createLocalDate(idx.date);
        idxDate.setDate(1);
        idxDate.setHours(0,0,0,0);
        return idxDate >= startDate && idxDate <= today;
    });
    let accumulatedMultiplier = 1;
    relevantIndices.forEach(idx => {
        const effectiveRate = idx.rate * 0.92;
        accumulatedMultiplier *= (1 + (effectiveRate / 100));
    });
    const totalAmount = value * accumulatedMultiplier;
    return totalAmount - value;
};

export const calculateCurrentCreditValue = (quota: Quota, indices: MonthlyIndex[] = []): number => {
  if (!quota) return 0;
  let currentCreditValue = Number(quota.creditValue) || 0;
  const dateStr = quota.adhesionDate || quota.firstDueDate;
  if (!dateStr) return currentCreditValue;
  const startDate = createLocalDate(dateStr);
  startDate.setDate(1); 
  startDate.setHours(0,0,0,0);
  let cutoffDate = new Date();
  cutoffDate.setHours(23,59,59,999);
  if (quota.isContemplated && quota.contemplationDate) {
      cutoffDate = createLocalDate(quota.contemplationDate);
      cutoffDate.setHours(23,59,59,999);
  } else if (quota.isContemplated && !quota.contemplationDate) {
      return currentCreditValue;
  }
  let processingDate = new Date(startDate);
  processingDate = addMonths(processingDate, 12);
  let safetyCounter = 0;
  while (processingDate <= cutoffDate && safetyCounter < 100) {
      const endPeriod = new Date(processingDate);
      endPeriod.setDate(1); 
      endPeriod.setHours(0,0,0,0);
      const endPeriodStr = endPeriod.toISOString().split('T')[0];
      const annualType = quota.correctionIndex === CorrectionIndex.INCC ? CorrectionIndex.INCC_12 : CorrectionIndex.IPCA_12;
      const directAnnualIndex = indices.find(idx => idx.type === annualType && idx.date === endPeriodStr);
      let finalRate = 0;
      if (directAnnualIndex) {
          finalRate = directAnnualIndex.rate / 100;
      } else {
          const startPeriod = addMonths(processingDate, -12);
          startPeriod.setDate(1); 
          startPeriod.setHours(0,0,0,0);
          const relevantIndices = indices.filter(idx => {
            if (idx.type !== quota.correctionIndex) return false;
            const d = createLocalDate(idx.date);
            d.setHours(0,0,0,0);
            return d >= startPeriod && d < endPeriod;
          });
          let accumulatedMultiplier = 1;
          relevantIndices.forEach(idx => { accumulatedMultiplier *= (1 + (idx.rate / 100)); });
          finalRate = accumulatedMultiplier - 1;
      }
      if (finalRate > 0) {
          const ratePercent2 = parseFloat((finalRate * 100).toFixed(2));
          const effectiveRateCredit = ratePercent2 / 100;
          currentCreditValue = currentCreditValue * (1 + effectiveRateCredit);
      }
      processingDate = addMonths(processingDate, 12);
      safetyCounter++;
  }
  return currentCreditValue;
};

export const generateSchedule = (quota: Quota, indices: MonthlyIndex[] = []): PaymentInstallment[] => {
  const schedule: PaymentInstallment[] = [];
  if (!quota || !quota.firstDueDate) return [];
  const startDate = createLocalDate(quota.firstDueDate);
  const adhesionDateAnchor = createLocalDate(quota.adhesionDate || quota.firstDueDate);
  adhesionDateAnchor.setDate(1); adhesionDateAnchor.setHours(0,0,0,0);
  const termMonths = Number(quota.termMonths) || 1;
  const adminFeeRate = Number(quota.adminFeeRate) || 0;
  const reserveFundRate = Number(quota.reserveFundRate) || 0;
  let currentCreditValue = Number(quota.creditValue) || 0;

  // Saldos iniciais (Dívida Total)
  let currentBalanceFC = currentCreditValue; 
  let currentBalanceTA = currentCreditValue * (adminFeeRate / 100);
  let currentBalanceFR = currentCreditValue * (reserveFundRate / 100);

  // Proporções Contratuais CRÍTICAS para distribuição de Lances
  // Base 100 + TA% + FR%. Ex: 100 + 9,8072 + 2 = 111,8072
  const contractTotalRate = 100 + adminFeeRate + reserveFundRate;
  const contractRatioFC = 100 / contractTotalRate;
  const contractRatioTA = adminFeeRate / contractTotalRate;
  const contractRatioFR = reserveFundRate / contractTotalRate;

  let bidProcessed = false;
  const today = new Date(); today.setHours(23, 59, 59, 999);

  for (let i = 1; i <= termMonths; i++) {
    const currentDate = addMonths(startDate, i - 1);
    const dueDate = currentDate.toISOString();
    const amortizationDivisor = Math.max(0, termMonths - i + 1);

    let bidAmountApplied = 0; 
    let bidDateApplied: string | undefined = undefined;
    let bidCalcBaseUsed = 0;
    let bidAbatementFC = 0, bidAbatementTA = 0, bidAbatementFR = 0;

    let bidEmbeddedApplied = 0, bidEmbeddedPercent = 0, bidEmbeddedAbatementFC = 0, bidEmbeddedPercentFC = 0, bidEmbeddedAbatementFR = 0, bidEmbeddedPercentFR = 0, bidEmbeddedAbatementTA = 0, bidEmbeddedPercentTA = 0;
    let bidFreeApplied = 0, bidFreePercent = 0, bidFreeAbatementFC = 0, bidFreePercentFC = 0, bidFreeAbatementFR = 0, bidFreePercentFR = 0, bidFreeAbatementTA = 0, bidFreePercentTA = 0;

    if (quota.isContemplated && quota.contemplationDate && !bidProcessed && quota.bidTotal && quota.bidTotal > 0) {
        const bidDate = createLocalDate(quota.contemplationDate);
        if (bidDate <= currentDate) {
             bidDateApplied = quota.contemplationDate;
             bidProcessed = true;
             bidAmountApplied = quota.bidTotal;

             // Base para o cálculo dos % exibidos
             bidCalcBaseUsed = (quota.bidBase === BidBaseType.TOTAL_PROJECT) ? (currentBalanceFC + currentBalanceTA + currentBalanceFR) : currentCreditValue;

             const distributeBid = (amount: number) => {
                 // Usa as proporções fixas do contrato para garantir que a soma dos % atinja 100, TA e FR totais
                 let mFC = parseFloat((amount * contractRatioFC).toFixed(2));
                 let mTA = parseFloat((amount * contractRatioTA).toFixed(2));
                 let mFR = parseFloat((amount * contractRatioFR).toFixed(2));
                 const sum = mFC + mTA + mFR;
                 const diff = amount - sum;
                 // Ajuste fino no FC para bater o centavo do total do lance
                 if (Math.abs(diff) > 0.001) mFC = parseFloat((mFC + diff).toFixed(2)); 

                 // Percentuais relativos à carta de crédito atual
                 const pFC = (mFC / currentCreditValue) * 100;
                 const pTA = (mTA / currentCreditValue) * 100;
                 const pFR = (mFR / currentCreditValue) * 100;
                 const pTotal = (amount / currentCreditValue) * 100;
                 return { mFC, mTA, mFR, pFC, pTA, pFR, pTotal };
             };

             if (quota.bidEmbedded && quota.bidEmbedded > 0) {
                 bidEmbeddedApplied = quota.bidEmbedded;
                 const res = distributeBid(bidEmbeddedApplied);
                 bidEmbeddedAbatementFC = res.mFC; bidEmbeddedAbatementTA = res.mTA; bidEmbeddedAbatementFR = res.mFR;
                 bidEmbeddedPercent = res.pTotal; bidEmbeddedPercentFC = res.pFC; bidEmbeddedPercentTA = res.pTA; bidEmbeddedPercentFR = res.pFR;
                 currentBalanceFC -= bidEmbeddedAbatementFC; currentBalanceTA -= bidEmbeddedAbatementTA; currentBalanceFR -= bidEmbeddedAbatementFR;
             }
             if (quota.bidFree && quota.bidFree > 0) {
                 bidFreeApplied = quota.bidFree;
                 const res = distributeBid(bidFreeApplied);
                 bidFreeAbatementFC = res.mFC; bidFreeAbatementTA = res.mTA; bidFreeAbatementFR = res.mFR;
                 bidFreePercent = res.pTotal; bidFreePercentFC = res.pFC; bidFreePercentTA = res.pTA; bidFreePercentFR = res.pFR;
                 currentBalanceFC -= bidFreeAbatementFC; currentBalanceTA -= bidFreeAbatementTA; currentBalanceFR -= bidFreeAbatementFR;
             }
             bidAbatementFC = bidEmbeddedAbatementFC + bidFreeAbatementFC;
             bidAbatementFR = bidEmbeddedAbatementFR + bidFreeAbatementFR;
             bidAbatementTA = bidEmbeddedAbatementTA + bidFreeAbatementTA;
        }
    }

    let correctionApplied = false;
    let correctionFactor = 0;
    let correctionIndexName: string | undefined = undefined;
    let correctionStartDate: string | undefined = undefined;
    let correctionEndDate: string | undefined = undefined;
    let stopCreditCorrection = false;
    if (quota.isContemplated && quota.contemplationDate) {
         const contDate = createLocalDate(quota.contemplationDate);
         if (currentDate > contDate) stopCreditCorrection = true;
    }

    if (i > 1 && (i - 1) % 12 === 0) {
        const anniversaryCount = (i - 1) / 12;
        const endOfPeriod = addMonths(adhesionDateAnchor, anniversaryCount * 12);
        endOfPeriod.setDate(1); endOfPeriod.setHours(0,0,0,0);
        const endOfPeriodStr = endOfPeriod.toISOString().split('T')[0];
        if (endOfPeriod <= today) {
            const annualType = quota.correctionIndex === CorrectionIndex.INCC ? CorrectionIndex.INCC_12 : CorrectionIndex.IPCA_12;
            const directAnnualIndex = indices.find(idx => idx.type === annualType && idx.date === endOfPeriodStr);
            let finalRate = 0;
            let startOfPeriod = addMonths(endOfPeriod, -12);
            startOfPeriod.setDate(1); startOfPeriod.setHours(0,0,0,0);
            if (directAnnualIndex) {
                finalRate = directAnnualIndex.rate / 100;
                correctionIndexName = quota.correctionIndex + " (Acum. 12m)";
            } else {
                const relevantIndices = indices.filter(idx => {
                  if (idx.type !== quota.correctionIndex) return false;
                  const idxDate = createLocalDate(idx.date);
                  idxDate.setHours(0,0,0,0);
                  return idxDate >= startOfPeriod && idxDate < endOfPeriod;
                });
                let accumulatedMultiplier = 1;
                relevantIndices.forEach(idx => { accumulatedMultiplier *= (1 + (idx.rate / 100)); });
                finalRate = accumulatedMultiplier - 1; 
                correctionIndexName = quota.correctionIndex;
            }
            if (finalRate > 0) {
                correctionApplied = true;
                const ratePercent2 = parseFloat((finalRate * 100).toFixed(2));
                const effectiveRateCredit = ratePercent2 / 100;
                const ratePercent4 = parseFloat((finalRate * 100).toFixed(4));
                const effectiveRateDebt = ratePercent4 / 100;
                correctionFactor = effectiveRateDebt; 
                correctionStartDate = startOfPeriod.toISOString();
                const displayEndDate = new Date(endOfPeriod);
                displayEndDate.setMonth(displayEndDate.getMonth() - 1);
                correctionEndDate = displayEndDate.toISOString();
                if (!stopCreditCorrection) currentCreditValue = currentCreditValue * (1 + effectiveRateCredit);
                currentBalanceFC = currentBalanceFC * (1 + effectiveRateDebt);
                currentBalanceTA = currentBalanceTA * (1 + effectiveRateDebt);
                currentBalanceFR = currentBalanceFR * (1 + effectiveRateDebt);
            }
        }
    }

    let installmentFC = 0, installmentTA = 0, installmentFR = 0;
    let monthlyRateFC = 0, monthlyRateFR = 0, monthlyRateTA = 0; 
    let isBeforeContemplation = true;
    if (quota.isContemplated && quota.contemplationDate) {
        const contDate = createLocalDate(quota.contemplationDate);
        const currentYearMonth = currentDate.getFullYear() * 12 + currentDate.getMonth();
        const contYearMonth = contDate.getFullYear() * 12 + contDate.getMonth();
        if (currentYearMonth > contYearMonth) isBeforeContemplation = false;
        if (bidProcessed) isBeforeContemplation = false;
    } else if (quota.isContemplated && !quota.contemplationDate) {
         isBeforeContemplation = false; 
    }

    // Taxas mensais padrão baseadas no prazo original
    const standardRateTA = adminFeeRate / termMonths; 
    const standardRateFR = reserveFundRate / termMonths; 

    if (quota.paymentPlan === PaymentPlanType.REDUCED || quota.paymentPlan === PaymentPlanType.NORMAL) {
      let useReducedLogic = false;
      if (quota.paymentPlan === PaymentPlanType.REDUCED) {
          const halfTermIndex = Math.ceil(termMonths / 2);
          useReducedLogic = (i <= halfTermIndex) && isBeforeContemplation;
      }
      if (useReducedLogic) {
          const basePercentageFC = 100 / termMonths;
          const reducedRateFC = basePercentageFC * 0.5;
          monthlyRateFC = parseFloat(reducedRateFC.toFixed(4));
          installmentFC = currentCreditValue * (monthlyRateFC / 100);
      } else {
          const div = amortizationDivisor > 0 ? amortizationDivisor : 1;
          installmentFC = currentBalanceFC / div;
          if (currentCreditValue > 0) monthlyRateFC = (installmentFC / currentCreditValue) * 100;
      }
      installmentFC = Math.min(installmentFC, currentBalanceFC);

      if (!isBeforeContemplation && bidProcessed) {
          const div = amortizationDivisor > 0 ? amortizationDivisor : 1;
          installmentTA = currentBalanceTA / div;
          installmentFR = currentBalanceFR / div;
          if (currentCreditValue > 0) {
              monthlyRateTA = (installmentTA / currentCreditValue) * 100;
              monthlyRateFR = (installmentFR / currentCreditValue) * 100;
          }
      } else {
          monthlyRateTA = parseFloat(standardRateTA.toFixed(4));
          monthlyRateFR = parseFloat(standardRateFR.toFixed(4));
          installmentTA = Math.min(currentCreditValue * (monthlyRateTA / 100), currentBalanceTA);
          installmentFR = Math.min(currentCreditValue * (monthlyRateFR / 100), currentBalanceFR);
      }
    } 
    else if (quota.paymentPlan === PaymentPlanType.SEMESTRAL) {
       const cycleMonth = i % 6; 
       const isBalloonMonth = cycleMonth === 0; 
       let baseFC = 0, baseTA = 0, baseFR = 0;
       if (isBeforeContemplation) {
           baseFC = currentCreditValue / termMonths;
           baseTA = currentCreditValue * (standardRateTA / 100);
           baseFR = currentCreditValue * (standardRateFR / 100);
       } else {
           const div = amortizationDivisor > 0 ? amortizationDivisor : 1;
           baseFC = currentBalanceFC / div;
           baseTA = currentBalanceTA / div;
           baseFR = currentBalanceFR / div;
       }
       if (!isBalloonMonth) {
          installmentFC = baseFC * 0.5; installmentTA = baseTA * 0.5; installmentFR = baseFR * 0.5;
       } else {
          installmentFC = baseFC * 3.5; installmentTA = baseTA * 3.5; installmentFR = baseFR * 3.5;
       }
       if (currentCreditValue > 0) {
           monthlyRateFC = (installmentFC / currentCreditValue) * 100;
           monthlyRateTA = (installmentTA / currentCreditValue) * 100;
           monthlyRateFR = (installmentFR / currentCreditValue) * 100;
       }
    }

    installmentFC = parseFloat(installmentFC.toFixed(2));
    installmentFR = parseFloat(installmentFR.toFixed(2));
    installmentTA = parseFloat(installmentTA.toFixed(2));
    const totalInstallment = installmentFC + installmentTA + installmentFR;
    currentBalanceFC -= installmentFC; currentBalanceTA -= installmentTA; currentBalanceFR -= installmentFR;
    const currentBalanceTotal = currentBalanceFC + currentBalanceTA + currentBalanceFR;

    // Garantir que no último mês zere se for quase zero
    if (i === termMonths || currentBalanceTotal < 0.1) {
        if (i === termMonths) { currentBalanceFC = 0; currentBalanceTA = 0; currentBalanceFR = 0; }
    }

    const percentBalanceFC = currentCreditValue > 0 ? (currentBalanceFC / currentCreditValue) * 100 : 0;
    const percentBalanceFR = currentCreditValue > 0 ? (currentBalanceFR / currentCreditValue) * 100 : 0;
    const percentBalanceTA = currentCreditValue > 0 ? (currentBalanceTA / currentCreditValue) * 100 : 0;
    const percentBalanceTotal = currentCreditValue > 0 ? ((currentBalanceFC + currentBalanceFR + currentBalanceTA) / currentCreditValue) * 100 : 0;

    schedule.push({
      installmentNumber: i, dueDate, commonFund: installmentFC, monthlyRateFC, reserveFund: installmentFR, monthlyRateFR, adminFee: installmentTA, monthlyRateTA, totalInstallment,
      balanceFC: Math.max(0, currentBalanceFC), balanceFR: Math.max(0, currentBalanceFR), balanceTA: Math.max(0, currentBalanceTA), balanceTotal: Math.max(0, currentBalanceFC + currentBalanceTA + currentBalanceFR),
      percentBalanceFC, percentBalanceFR, percentBalanceTA, percentBalanceTotal, bidAmountApplied, bidDate: bidDateApplied, bidCalcBaseUsed,
      bidEmbeddedApplied, bidEmbeddedPercent, bidEmbeddedAbatementFC, bidEmbeddedPercentFC, bidEmbeddedAbatementFR, bidEmbeddedPercentFR, bidEmbeddedAbatementTA, bidEmbeddedPercentTA,
      bidFreeApplied, bidFreePercent, bidFreeAbatementFC, bidFreePercentFC, bidFreeAbatementFR, bidFreePercentFR, bidFreeAbatementTA, bidFreePercentTA,
      bidAbatementFC, bidAbatementFR, bidAbatementTA, correctionApplied, correctionFactor, correctedCreditValue: currentCreditValue, correctionIndexName, correctionStartDate, correctionEndDate,
      realAmountPaid: null, isPaid: false
    });
  }
  return schedule;
};

import React, { useState, useMemo } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { formatCurrency, formatPercent, formatDate } from '../utils/formatters';
import { Pencil, Search, DollarSign, Gavel, TrendingUp, Calculator, PieChart, Info, ArrowUpRight, ArrowRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { generateSchedule } from '../services/calculationService';

const Simulation = () => {
  const { quotas, currentQuota, setCurrentQuota, installments, updateInstallmentPayment, companies, administrators, indices } = useConsortium();
  const navigate = useNavigate();

  const [searchText, setSearchText] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [editingCell, setEditingCell] = useState<{ id: number, field: 'payment' | 'fc' | 'fr' | 'ta' | 'fine' | 'interest' } | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  const filteredOptions = useMemo(() => {
    return quotas.filter(q => {
      const textMatch = (q.group || '').toLowerCase().includes(searchText.toLowerCase()) || (q.quotaNumber || '').toLowerCase().includes(searchText.toLowerCase());
      const companyMatch = filterCompany ? q.companyId === filterCompany : true;
      let statusMatch = true;
      if (filterStatus === 'ACTIVE') statusMatch = !q.isContemplated;
      if (filterStatus === 'CONTEMPLATED') statusMatch = q.isContemplated;
      return textMatch && companyMatch && statusMatch;
    });
  }, [quotas, searchText, filterCompany, filterStatus]);

  const todayStr = new Date().toISOString().split('T')[0];

  const currentDisplayCredit = useMemo(() => {
    if (currentQuota && installments.length > 0) {
        const pastOrPresent = installments.filter(i => i.dueDate.split('T')[0] <= todayStr);
        return pastOrPresent.length > 0 ? pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || currentQuota.creditValue : installments[0].correctedCreditValue || currentQuota.creditValue;
    }
    return currentQuota?.creditValue || 0;
  }, [currentQuota, installments, todayStr]);

  const detailedSummary = useMemo(() => {
    const stats = {
        paid: { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, others: 0, total: 0 },
        toPay: { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, others: 0, total: 0, diff: 0 },
        counts: { total: 0, furo: 0 }
    };

    if (!currentQuota) return stats;

    installments.forEach(inst => {
        const isMatured = inst.dueDate.split('T')[0] <= todayStr;

        if (isMatured) {
            stats.paid.fc += inst.commonFund;
            stats.paid.fr += inst.reserveFund;
            stats.paid.ta += inst.adminFee;
            stats.paid.fine += (inst.manualFine || 0);
            stats.paid.interest += (inst.manualInterest || 0);
        } else {
            stats.toPay.fc += inst.commonFund;
            stats.toPay.fr += inst.reserveFund;
            stats.toPay.ta += inst.adminFee;
            stats.toPay.fine += (inst.manualFine || 0);
            stats.toPay.interest += (inst.manualInterest || 0);
            stats.counts.total++;
        }

        if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
            stats.paid.fc += (inst.bidAbatementFC || 0);
            stats.paid.fr += (inst.bidAbatementFR || 0);
            stats.paid.ta += (inst.bidAbatementTA || 0);
        }
    });

    stats.paid.total = stats.paid.fc + stats.paid.fr + stats.paid.ta + stats.paid.fine + stats.paid.interest;
    stats.toPay.total = stats.toPay.fc + stats.toPay.fr + stats.toPay.ta + stats.toPay.fine + stats.toPay.interest;

    return stats;
  }, [currentQuota, installments, todayStr]);

  // Cálculo dos Totais do Rodapé da Tabela
  const footerTotals = useMemo(() => {
    return installments.reduce((acc, inst) => {
        const currentCredit = inst.correctedCreditValue || 1;
        const paidPct = (inst.totalInstallment / currentCredit) * 100;

        // Valores de Lances
        const bidFC = (inst.bidEmbeddedAbatementFC || 0) + (inst.bidFreeAbatementFC || 0);
        const bidFR = (inst.bidEmbeddedAbatementFR || 0) + (inst.bidFreeAbatementFR || 0);
        const bidTA = (inst.bidEmbeddedAbatementTA || 0) + (inst.bidFreeAbatementTA || 0);
        const bidTotal = (inst.bidEmbeddedApplied || 0) + (inst.bidFreeApplied || 0);

        // Percentuais de Lances (Importante para o fechamento de 100%, 2%, 9.8%)
        const bidFCPct = (inst.bidEmbeddedPercentFC || 0) + (inst.bidFreePercentFC || 0);
        const bidFRPct = (inst.bidEmbeddedPercentFR || 0) + (inst.bidFreePercentFR || 0);
        const bidTAPct = (inst.bidEmbeddedPercentTA || 0) + (inst.bidFreePercentTA || 0);
        const bidTotalPct = (inst.bidEmbeddedPercent || 0) + (inst.bidFreePercent || 0);

        return {
            fc: acc.fc + inst.commonFund + bidFC,
            fcPct: acc.fcPct + (inst.monthlyRateFC || 0) + bidFCPct,
            fr: acc.fr + inst.reserveFund + bidFR,
            frPct: acc.frPct + (inst.monthlyRateFR || 0) + bidFRPct,
            ta: acc.ta + inst.adminFee + bidTA,
            taPct: acc.taPct + (inst.monthlyRateTA || 0) + bidTAPct,
            fine: acc.fine + (inst.manualFine || 0),
            interest: acc.interest + (inst.manualInterest || 0),
            total: acc.total + inst.totalInstallment + bidTotal,
            totalPct: acc.totalPct + paidPct + bidTotalPct
        };
    }, { fc: 0, fcPct: 0, fr: 0, frPct: 0, ta: 0, taPct: 0, fine: 0, interest: 0, total: 0, totalPct: 0 });
  }, [installments]);

  const handleEditClick = (id: number, field: any, currentValue: any, defaultValue: any) => {
    setEditingCell({ id, field });
    setEditValue(currentValue !== undefined && currentValue !== null ? currentValue.toString() : defaultValue.toFixed(2));
  };

  const handleSaveEdit = (installmentNum: number) => {
    if (!editingCell) return;
    const val = parseFloat(editValue.replace(',', '.'));
    if (isNaN(val)) { setEditingCell(null); return; }
    if (editingCell.field === 'payment') updateInstallmentPayment(installmentNum, { amount: val });
    else if (editingCell.field === 'fc') updateInstallmentPayment(installmentNum, { fc: val });
    else if (editingCell.field === 'fr') updateInstallmentPayment(installmentNum, { fr: val });
    else if (editingCell.field === 'ta') updateInstallmentPayment(installmentNum, { ta: val });
    else if (editingCell.field === 'fine') updateInstallmentPayment(installmentNum, { fine: val });
    else if (editingCell.field === 'interest') updateInstallmentPayment(installmentNum, { interest: val });
    setEditingCell(null);
  };

  const formatSummaryPercent = (val: number) => {
      const base = currentDisplayCredit || 1;
      const pct = (val / base) * 100;
      return pct.toLocaleString('pt-BR', { minimumFractionDigits: 4, maximumFractionDigits: 4 });
  };

  const renderEditableCell = (inst: any, field: any, value: number, isManual: boolean, rate?: number) => {
    const isEditing = editingCell?.id === inst.installmentNumber && editingCell?.field === field;
    if (isEditing) return (<td className="p-2 text-right"><input autoFocus type="text" className="w-full p-1 border border-blue-400 rounded text-right text-xs" value={editValue} onChange={(e) => setEditValue(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') handleSaveEdit(inst.installmentNumber); if (e.key === 'Escape') setEditingCell(null); }} onBlur={() => handleSaveEdit(inst.installmentNumber)} /></td>);
    let cellClass = "cursor-pointer transition-colors hover:bg-slate-50 ";
    if (isManual) cellClass += "bg-blue-50/50 text-blue-700 font-medium";
    return (<td className={`p-2.5 text-right ${cellClass} text-xs`} onClick={() => handleEditClick(inst.installmentNumber, field, isManual ? value : undefined, value)} title="Clique para editar"><div className="flex flex-col items-end"><span>{formatCurrency(value)}</span><span className="text-[9px] text-slate-400 font-normal">{rate ? `${rate.toLocaleString('pt-BR', { minimumFractionDigits: 4, maximumFractionDigits: 4 })}%` : ''}</span></div></td>);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col gap-4 print:hidden">
        <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2"><Calculator className="text-emerald-600" /> Simulador e Extrato</h2>
             {currentQuota && <button onClick={() => navigate(`/edit/${currentQuota.id}`)} className="px-3 py-1.5 text-blue-600 hover:bg-blue-50 rounded-lg border border-blue-200 text-sm font-medium flex items-center gap-2"><Pencil size={16} /> Editar Dados Cota</button>}
        </div>
        <div className="grid grid-cols-1 md:grid-cols-12 gap-3 bg-white p-3 rounded-lg border border-slate-200 shadow-sm">
             <div className="md:col-span-3 relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} /><input type="text" placeholder="Pesquisar cota..." value={searchText} onChange={(e) => setSearchText(e.target.value)} className="w-full pl-9 pr-2 py-2 text-sm border border-slate-300 rounded-md focus:ring-1 focus:ring-emerald-500 outline-none" /></div>
             <div className="md:col-span-2"><select value={filterCompany} onChange={(e) => setFilterCompany(e.target.value)} className="w-full py-2 px-2 text-sm border border-slate-300 rounded-md focus:ring-1 focus:ring-emerald-500 outline-none text-slate-600"><option value="">Todas Empresas</option>{companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></div>
             <div className="md:col-span-2"><select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="w-full py-2 px-2 text-sm border border-slate-300 rounded-md focus:ring-1 focus:ring-emerald-500 outline-none text-slate-600"><option value="">Todos Status</option><option value="ACTIVE">Em Andamento</option><option value="CONTEMPLATED">Contempladas</option></select></div>
             <div className="md:col-span-5"><select className="w-full py-2 px-2 text-sm font-semibold text-emerald-800 bg-emerald-50 border border-emerald-200 rounded-md outline-none focus:ring-2 focus:ring-emerald-500" value={currentQuota?.id || ''} onChange={(e) => { const found = quotas.find(q => q.id === e.target.value); setCurrentQuota(found || null); }}><option value="">Selecionar Cota ({filteredOptions.length})</option>{filteredOptions.map(q => (<option key={q.id} value={q.id}>{q.group} - {q.quotaNumber} {q.companyId ? `(${companies.find(c => c.id === q.companyId)?.name})` : ''}</option>))}</select></div>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-xs text-left border-collapse">
              <thead className="bg-slate-50 text-slate-600 font-bold border-b border-slate-200 text-[10px] uppercase sticky top-0 z-20">
                <tr>
                  <th className="p-2 text-center bg-slate-100 sticky left-0 z-30 w-10">P</th>
                  <th className="p-2 min-w-[70px]">Vencimento</th>
                  <th className="p-2 text-right">FC Mensal (%)</th>
                  <th className="p-2 text-right">FR Mensal (%)</th>
                  <th className="p-2 text-right">TA Mensal (%)</th>
                  <th className="p-2 text-right">Multa</th>
                  <th className="p-2 text-right">Juros</th>
                  <th className="p-2 text-right font-bold text-slate-800 bg-emerald-50/50">Vlr Pago (%)</th>
                  <th className="p-2 text-right border-l border-slate-200 bg-slate-50/80">Saldo FC (%)</th>
                  <th className="p-2 text-right bg-slate-50/80">Saldo FR (%)</th>
                  <th className="p-2 text-right bg-slate-50/80">Saldo TA (%)</th>
                  <th className="p-2 text-right font-bold bg-slate-100 border-l border-slate-200">Saldo Total (%)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {installments.map((inst) => (
                  <React.Fragment key={inst.installmentNumber}>
                  {inst.correctionApplied && (
                      <tr className="bg-blue-50 border-y border-blue-100">
