export default Simulation;

import { Quota, PaymentInstallment, PaymentPlanType, MonthlyIndex, CorrectionIndex, BidBaseType } from '../types';
import { addMonths } from '../utils/formatters';

const createLocalDate = (dateStr: string): Date => {
  if(!dateStr) return new Date();
  const cleanDate = dateStr.split('T')[0];
  const [year, month, day] = cleanDate.split('-').map(Number);
  return new Date(year, month - 1, day, 0, 0, 0, 0);
};

export const calculateCDICorrection = (value: number, startDateStr: string | undefined, indices: MonthlyIndex[]): number => {
    if (!value || value <= 0 || !startDateStr) return 0;
    const startDate = createLocalDate(startDateStr);
    startDate.setDate(1); 
    startDate.setHours(0,0,0,0);
    const today = new Date();
    today.setHours(23,59,59,999);
    const relevantIndices = indices.filter(idx => {
        if (idx.type !== CorrectionIndex.CDI) return false;
        const idxDate = createLocalDate(idx.date);
        idxDate.setDate(1);
        idxDate.setHours(0,0,0,0);
        return idxDate >= startDate && idxDate <= today;
    });
    let accumulatedMultiplier = 1;
    relevantIndices.forEach(idx => {
        const effectiveRate = idx.rate * 0.92;
        accumulatedMultiplier *= (1 + (effectiveRate / 100));
    });
    return (value * accumulatedMultiplier) - value;
};

export const calculateCurrentCreditValue = (quota: Quota, indices: MonthlyIndex[] = []): number => {
  if (!quota) return 0;
  let currentCreditValue = Number(quota.creditValue) || 0;
  const dateStr = quota.adhesionDate || quota.firstDueDate;
  if (!dateStr) return currentCreditValue;
  const startDate = createLocalDate(dateStr);
  startDate.setDate(1); 
  startDate.setHours(0,0,0,0);
  let cutoffDate = new Date();
  cutoffDate.setHours(23,59,59,999);
  if (quota.isContemplated && quota.contemplationDate) {
      cutoffDate = createLocalDate(quota.contemplationDate);
      cutoffDate.setHours(23,59,59,999);
  }
  let processingDate = new Date(startDate);
  processingDate = addMonths(processingDate, 12);
  let safetyCounter = 0;
  while (processingDate <= cutoffDate && safetyCounter < 100) {
      const endPeriodStr = processingDate.toISOString().split('T')[0];
      const annualType = quota.correctionIndex === CorrectionIndex.INCC ? CorrectionIndex.INCC_12 : CorrectionIndex.IPCA_12;
      const directAnnualIndex = indices.find(idx => idx.type === annualType && idx.date === endPeriodStr);
      let finalRate = 0;
      if (directAnnualIndex) {
          finalRate = directAnnualIndex.rate / 100;
      } else {
          const startPeriod = addMonths(processingDate, -12);
          const relevantIndices = indices.filter(idx => {
            if (idx.type !== quota.correctionIndex) return false;
            const d = createLocalDate(idx.date);
            return d >= startPeriod && d < processingDate;
          });
          let accumulatedMultiplier = 1;
          relevantIndices.forEach(idx => { accumulatedMultiplier *= (1 + (idx.rate / 100)); });
          finalRate = accumulatedMultiplier - 1;
      }
      if (finalRate > 0) {
          const ratePercent2 = parseFloat((finalRate * 100).toFixed(2));
          currentCreditValue = currentCreditValue * (1 + (ratePercent2 / 100));
      }
      processingDate = addMonths(processingDate, 12);
      safetyCounter++;
  }
  return currentCreditValue;
};

export const generateSchedule = (quota: Quota, indices: MonthlyIndex[] = []): PaymentInstallment[] => {
  const schedule: PaymentInstallment[] = [];
  if (!quota || !quota.firstDueDate) return [];

  const startDate = createLocalDate(quota.firstDueDate);
  const adhesionDateAnchor = createLocalDate(quota.adhesionDate || quota.firstDueDate);
  adhesionDateAnchor.setDate(1); adhesionDateAnchor.setHours(0,0,0,0);

  const termMonths = Number(quota.termMonths) || 1;
  const adminFeeRateTotal = Number(quota.adminFeeRate) || 0;
  const reserveFundRateTotal = Number(quota.reserveFundRate) || 0;

  let currentCreditValue = Number(quota.creditValue) || 0;

  // RASTREAMENTO POR PERCENTUAL (Garante que a soma seja 100%, TA% e FR%)
  let remainingPctFC = 100.0;
  let remainingPctTA = adminFeeRateTotal;
  let remainingPctFR = reserveFundRateTotal;

  // Proporções Contratuais para Rateio de Lances
  const totalContractRate = 100 + adminFeeRateTotal + reserveFundRateTotal;
  const ratioFC = 100 / totalContractRate;
  const ratioTA = adminFeeRateTotal / totalContractRate;
  const ratioFR = reserveFundRateTotal / totalContractRate;

  let bidProcessed = false;
  const today = new Date(); today.setHours(23, 59, 59, 999);

  for (let i = 1; i <= termMonths; i++) {
    const currentDate = addMonths(startDate, i - 1);
    const dueDate = currentDate.toISOString();
    const monthsLeft = termMonths - i + 1;

    let bidAmountApplied = 0; 
    let bidDateApplied: string | undefined = undefined;
    let bidEmbeddedApplied = 0, bidEmbeddedPercent = 0, bidEmbeddedAbatementFC = 0, bidEmbeddedPercentFC = 0, bidEmbeddedAbatementFR = 0, bidEmbeddedPercentFR = 0, bidEmbeddedAbatementTA = 0, bidEmbeddedPercentTA = 0;
    let bidFreeApplied = 0, bidFreePercent = 0, bidFreeAbatementFC = 0, bidFreePercentFC = 0, bidFreeAbatementFR = 0, bidFreePercentFR = 0, bidFreeAbatementTA = 0, bidFreePercentTA = 0;

    // PROCESSAMENTO DE LANCE (Se houver)
    if (quota.isContemplated && quota.contemplationDate && !bidProcessed) {
        const bidDate = createLocalDate(quota.contemplationDate);
        // Aplica o lance no mês da contemplação
        if (bidDate <= currentDate) {
             bidProcessed = true;
             bidDateApplied = quota.contemplationDate;
             bidAmountApplied = quota.bidTotal || 0;

             const applyBid = (amount: number, type: 'embedded' | 'free') => {
                 const pctOfTotal = (amount / currentCreditValue) * 100;
                 // Distribuição baseada nos pesos do contrato
                 const pFC = pctOfTotal * ratioFC;
                 const pTA = pctOfTotal * ratioTA;
                 const pFR = pctOfTotal * ratioFR;

                 const mFC = (pFC / 100) * currentCreditValue;
                 const mTA = (pTA / 100) * currentCreditValue;
                 const mFR = (pFR / 100) * currentCreditValue;

                 remainingPctFC -= pFC;
                 remainingPctTA -= pTA;
                 remainingPctFR -= pFR;

                 return { mFC, mTA, mFR, pFC, pTA, pFR, pTotal: pctOfTotal };
             };

             if (quota.bidEmbedded && quota.bidEmbedded > 0) {
                 bidEmbeddedApplied = quota.bidEmbedded;
                 const r = applyBid(bidEmbeddedApplied, 'embedded');
                 bidEmbeddedAbatementFC = r.mFC; bidEmbeddedAbatementTA = r.mTA; bidEmbeddedAbatementFR = r.mFR;
                 bidEmbeddedPercent = r.pTotal; bidEmbeddedPercentFC = r.pFC; bidEmbeddedPercentTA = r.pTA; bidEmbeddedPercentFR = r.pFR;
             }
             if (quota.bidFree && quota.bidFree > 0) {
                 bidFreeApplied = quota.bidFree;
                 const r = applyBid(bidFreeApplied, 'free');
                 bidFreeAbatementFC = r.mFC; bidFreeAbatementTA = r.mTA; bidFreeAbatementFR = r.mFR;
                 bidFreePercent = r.pTotal; bidFreePercentFC = r.pFC; bidFreePercentTA = r.pTA; bidFreePercentFR = r.pFR;
             }
        }
    }

    // CORREÇÃO ANUAL (Crédito e Saldos)
    let correctionApplied = false;
    let correctionFactor = 0;
    let correctionIndexName: string | undefined = undefined;
    if (i > 1 && (i - 1) % 12 === 0) {
        const anniversaryDate = addMonths(adhesionDateAnchor, ((i - 1) / 12) * 12);
        if (anniversaryDate <= today) {
            const annualType = quota.correctionIndex === CorrectionIndex.INCC ? CorrectionIndex.INCC_12 : CorrectionIndex.IPCA_12;
            const directAnnualIndex = indices.find(idx => idx.type === annualType && idx.date === anniversaryDate.toISOString().split('T')[0]);
            let rate = 0;
            if (directAnnualIndex) rate = directAnnualIndex.rate / 100;
            if (rate > 0) {
                correctionApplied = true;
                const r2 = parseFloat((rate * 100).toFixed(2)) / 100;
                const r4 = parseFloat((rate * 100).toFixed(4)) / 100;
                correctionFactor = r4;
                correctionIndexName = quota.correctionIndex;
                // Atualiza crédito se não estiver contemplado (ou conforme regra da ADM)
                const shouldUpdateCredit = !quota.isContemplated || (quota.contemplationDate && createLocalDate(quota.contemplationDate) >= currentDate);
                if (shouldUpdateCredit) currentCreditValue *= (1 + r2);
            }
        }
    }

    // CÁLCULO DA PARCELA MENSAL (Baseada no que resta de percentual)
    let monthlyRateFC = 0, monthlyRateTA = 0, monthlyRateFR = 0;

    // Lógica de Plano (Reduzido vs Normal)
    let isReducedPeriod = false;
    if (quota.paymentPlan === PaymentPlanType.REDUCED) {
        const halfTerm = Math.ceil(termMonths / 2);
        const isNotContemplatedYet = !quota.isContemplated || (quota.contemplationDate && createLocalDate(quota.contemplationDate) > currentDate);
        isReducedPeriod = i <= halfTerm && isNotContemplatedYet;
    }

    if (isReducedPeriod) {
        // No reduzido, paga-se metade da cota-parte normal do FC
        monthlyRateFC = (100 / termMonths) * 0.5;
        // Taxas são integrais
        monthlyRateTA = adminFeeRateTotal / termMonths;
        monthlyRateFR = reserveFundRateTotal / termMonths;
    } else {
        // Reparcelamento automático: divide o percentual restante pelos meses que faltam
        monthlyRateFC = remainingPctFC / monthsLeft;
        monthlyRateTA = remainingPctTA / monthsLeft;
        monthlyRateFR = remainingPctFR / monthsLeft;
    }

    // Converter % em Valor Monetário
    const installmentFC = parseFloat(((monthlyRateFC / 100) * currentCreditValue).toFixed(2));
    const installmentTA = parseFloat(((monthlyRateTA / 100) * currentCreditValue).toFixed(2));
    const installmentFR = parseFloat(((monthlyRateFR / 100) * currentCreditValue).toFixed(2));

    // Deduzir do saldo percentual (Usamos os valores exatos calculados para evitar desvios)
    remainingPctFC -= monthlyRateFC;
    remainingPctTA -= monthlyRateTA;
    remainingPctFR -= monthlyRateFR;

    const totalInstallment = installmentFC + installmentTA + installmentFR;
    const balanceFC = (remainingPctFC / 100) * currentCreditValue;
    const balanceTA = (remainingPctTA / 100) * currentCreditValue;
    const balanceFR = (remainingPctFR / 100) * currentCreditValue;

    schedule.push({
      installmentNumber: i, dueDate, commonFund: installmentFC, monthlyRateFC, reserveFund: installmentFR, monthlyRateFR, adminFee: installmentTA, monthlyRateTA, totalInstallment,
      balanceFC, balanceFR, balanceTA, balanceTotal: balanceFC + balanceTA + balanceFR,
      percentBalanceFC: remainingPctFC, percentBalanceFR: remainingPctFR, percentBalanceTA: remainingPctTA, percentBalanceTotal: remainingPctFC + remainingPctTA + remainingPctFR,
      bidAmountApplied, bidDate: bidDateApplied,
      bidEmbeddedApplied, bidEmbeddedPercent, bidEmbeddedAbatementFC, bidEmbeddedPercentFC, bidEmbeddedAbatementFR, bidEmbeddedPercentFR, bidEmbeddedAbatementTA, bidEmbeddedPercentTA,
      bidFreeApplied, bidFreePercent, bidFreeAbatementFC, bidFreePercentFC, bidFreeAbatementFR, bidFreePercentFR, bidFreeAbatementTA, bidFreePercentTA,
      bidAbatementFC: bidEmbeddedAbatementFC + bidFreeAbatementFC, bidAbatementFR: bidEmbeddedAbatementFR + bidFreeAbatementFR, bidAbatementTA: bidEmbeddedAbatementTA + bidFreeAbatementTA,
      correctionApplied, correctionFactor, correctedCreditValue: currentCreditValue, correctionIndexName,
      realAmountPaid: null, isPaid: false
    });
  }
  return schedule;
};

import React, { useState, useMemo } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { formatCurrency, formatPercent, formatDate } from '../utils/formatters';
import { Pencil, Search, Gavel, TrendingUp, Calculator, X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Simulation = () => {
  const { quotas, currentQuota, setCurrentQuota, installments, updateInstallmentPayment, companies, administrators, indices } = useConsortium();
  const navigate = useNavigate();

  const [searchText, setSearchText] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [editingCell, setEditingCell] = useState<{ id: number, field: string } | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  const filteredOptions = useMemo(() => {
    return quotas.filter(q => {
      const textMatch = (q.group || '').toLowerCase().includes(searchText.toLowerCase()) || (q.quotaNumber || '').toLowerCase().includes(searchText.toLowerCase());
      const companyMatch = filterCompany ? q.companyId === filterCompany : true;
      let statusMatch = true;
      if (filterStatus === 'ACTIVE') statusMatch = !q.isContemplated;
      if (filterStatus === 'CONTEMPLATED') statusMatch = q.isContemplated;
      return textMatch && companyMatch && statusMatch;
    });
  }, [quotas, searchText, filterCompany, filterStatus]);

  const todayStr = new Date().toISOString().split('T')[0];

  const currentDisplayCredit = useMemo(() => {
    if (currentQuota && installments.length > 0) {
        const pastOrPresent = installments.filter(i => i.dueDate.split('T')[0] <= todayStr);
        return pastOrPresent.length > 0 ? pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || currentQuota.creditValue : installments[0].correctedCreditValue || currentQuota.creditValue;
    }
    return currentQuota?.creditValue || 0;
  }, [currentQuota, installments, todayStr]);

  const detailedSummary = useMemo(() => {
    const stats = {
        paid: { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, total: 0 },
        toPay: { fc: 0, fr: 0, ta: 0, fine: 0, interest: 0, total: 0 },
        counts: { total: 0 }
    };
    if (!currentQuota) return stats;

    installments.forEach(inst => {
        const isMatured = inst.dueDate.split('T')[0] <= todayStr;
        if (isMatured) {
            stats.paid.fc += inst.commonFund; stats.paid.fr += inst.reserveFund; stats.paid.ta += inst.adminFee;
            stats.paid.fine += (inst.manualFine || 0); stats.paid.interest += (inst.manualInterest || 0);
        } else {
            stats.toPay.fc += inst.commonFund; stats.toPay.fr += inst.reserveFund; stats.toPay.ta += inst.adminFee;
            stats.counts.total++;
        }
        if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
            stats.paid.fc += (inst.bidAbatementFC || 0); stats.paid.fr += (inst.bidAbatementFR || 0); stats.paid.ta += (inst.bidAbatementTA || 0);
        }
    });
    stats.paid.total = stats.paid.fc + stats.paid.fr + stats.paid.ta + stats.paid.fine + stats.paid.interest;
    stats.toPay.total = stats.toPay.fc + stats.toPay.fr + stats.toPay.ta;
    return stats;
  }, [currentQuota, installments, todayStr]);

  const footerTotals = useMemo(() => {
    return installments.reduce((acc, inst) => {
        // Soma de lances aplicados (monetário e percentual)
        const bFC = (inst.bidEmbeddedAbatementFC || 0) + (inst.bidFreeAbatementFC || 0);
        const bTA = (inst.bidEmbeddedAbatementTA || 0) + (inst.bidFreeAbatementTA || 0);
        const bFR = (inst.bidEmbeddedAbatementFR || 0) + (inst.bidFreeAbatementFR || 0);

        const bFCP = (inst.bidEmbeddedPercentFC || 0) + (inst.bidFreePercentFC || 0);
        const bTAP = (inst.bidEmbeddedPercentTA || 0) + (inst.bidFreePercentTA || 0);
        const bFRP = (inst.bidEmbeddedPercentFR || 0) + (inst.bidFreePercentFR || 0);

        return {
            fc: acc.fc + inst.commonFund + bFC,
            fcPct: acc.fcPct + (inst.monthlyRateFC || 0) + bFCP,
            ta: acc.ta + inst.adminFee + bTA,
            taPct: acc.taPct + (inst.monthlyRateTA || 0) + bTAP,
            fr: acc.fr + inst.reserveFund + bFR,
            frPct: acc.frPct + (inst.monthlyRateFR || 0) + bFRP,
            fine: acc.fine + (inst.manualFine || 0),
            interest: acc.interest + (inst.manualInterest || 0),
            total: acc.total + inst.totalInstallment + bFC + bTA + bFR,
            totalPct: acc.totalPct + ( (inst.totalInstallment + bFC + bTA + bFR) / (inst.correctedCreditValue || 1) * 100 )
        };
    }, { fc: 0, fcPct: 0, ta: 0, taPct: 0, fr: 0, frPct: 0, fine: 0, interest: 0, total: 0, totalPct: 0 });
  }, [installments]);

  const handleEditClick = (id: number, field: string, value: number) => {
    setEditingCell({ id, field });
    setEditValue(value.toFixed(2).replace('.', ','));
