    installments.forEach(inst => {
        const isMatured = inst.dueDate.split('T')[0] <= todayStr;
        if (isMatured) {
            stats.paid.fc += inst.commonFund; stats.paid.fr += inst.reserveFund; stats.paid.ta += inst.adminFee;
