    else {
      const list = JSON.parse(localStorage.getItem(CREDIT_USAGES_KEY) || '[]');
      localStorage.setItem(CREDIT_USAGES_KEY, JSON.stringify(list.filter((u: any) => u.id !== id)));
    }
  }
};

