  companyId?: string;

  saldoAVencer: number; 
  percentAVencer: number;
  saldoVencido: number; 
  percentVencido: number;

  bidTotal: number;
  percentBidTotal: number;
  bidFree: number;
  bidEmbedded: number;

  creditAtContemplation: number; // Novo: Crédito na data da contemplação
  valorRealCarta: number; // Valor Líquido (Crédito - Lance Embutido)
  creditManualAdjustment: number;
  creditoTotal: number;
  bidFreeCorrection: number;
  creditoUtilizado: number;
  saldoDisponivel: number;
}

const Reports = () => {
  const { quotas, indices, updateQuota, administrators, companies, allCreditUsages } = useConsortium();
