          const valorLiquido = creditAtContemplation - bidEmbedded;
          const creditoTotal = valorLiquido + (quota.creditManualAdjustment || 0);

          const quotaUsages = allCreditUsages.filter(u => u.quotaId === quota.id && u.date <= refDateStr);
