import { Quota, PaymentInstallment, PaymentPlanType, MonthlyIndex, CorrectionIndex, BidBaseType } from '../types';
import { addMonths, getNextBusinessDay } from '../utils/formatters';

const createLocalDate = (dateStr: string): Date => {
  if(!dateStr) return new Date();
  const cleanDate = dateStr.split('T')[0];
  const [year, month, day] = cleanDate.split('-').map(Number);
  return new Date(year, month - 1, day, 0, 0, 0, 0);
};

export const calculateCDICorrection = (value: number, startDateStr: string | undefined, indices: MonthlyIndex[]): number => {
    if (!value || value <= 0 || !startDateStr) return 0;
    const startDate = createLocalDate(startDateStr);
    startDate.setDate(1); 
    startDate.setHours(0,0,0,0);
    const today = new Date();
    today.setHours(23,59,59,999);
    const relevantIndices = indices.filter(idx => {
        if (idx.type !== CorrectionIndex.CDI) return false;
        const idxDate = createLocalDate(idx.date);
        idxDate.setDate(1);
        idxDate.setHours(0,0,0,0);
        return idxDate >= startDate && idxDate <= today;
    });
    let accumulatedMultiplier = 1;
    relevantIndices.forEach(idx => {
        const effectiveRate = idx.rate * 0.92;
        accumulatedMultiplier *= (1 + (effectiveRate / 100));
    });
    return (value * accumulatedMultiplier) - value;
};

export const calculateCurrentCreditValue = (quota: Quota, indices: MonthlyIndex[] = [], customCutoff?: Date): number => {
  if (!quota) return 0;
  let currentCreditValue = Number(quota.creditValue) || 0;
  const dateStr = quota.adhesionDate || quota.firstDueDate;
  if (!dateStr) return currentCreditValue;

  const startDate = createLocalDate(dateStr);
  startDate.setDate(1); 
  startDate.setHours(0,0,0,0);

  // A data de corte padrão é hoje ou a informada
  let cutoffDate = customCutoff || new Date();
  cutoffDate.setHours(23,59,59,999);

  // Se a cota está contemplada, o valor do crédito "trava" nos reajustes até a data da contemplação
  if (quota.isContemplated && quota.contemplationDate) {
      const contDate = createLocalDate(quota.contemplationDate);
      contDate.setHours(23,59,59,999);
      // O crédito é o valor na data da contemplação, mas não pode exceder o filtro do relatório se este for anterior
      if (contDate < cutoffDate) {
          cutoffDate = contDate;
      }
  }

  // Reajuste ocorre a cada 12 meses (aniversário da adesão)
  let anniversaryCount = 1;
  let safetyCounter = 0;

  while (safetyCounter < 100) {
      const anniversaryInstallmentDate = addMonths(startDate, anniversaryCount * 12);
      // Se o próximo aniversário de reajuste é após a nossa data de corte (contemplação ou hoje), paramos
      if (anniversaryInstallmentDate > cutoffDate) break;

      // O índice a ser usado é o do 12º mês do ciclo (um mês antes do aniversário/reajuste)
      const indexDate = addMonths(startDate, (anniversaryCount * 12) - 1);
      const indexLookupStr = indexDate.toISOString().split('T')[0];

      const monthlyIndex = indices.find(idx => idx.type === quota.correctionIndex && idx.date === indexLookupStr);

      if (monthlyIndex && monthlyIndex.rate > 0) {
          currentCreditValue = currentCreditValue * (1 + (monthlyIndex.rate / 100));
      }

      anniversaryCount++;
      safetyCounter++;
  }
  return currentCreditValue;
};

export const generateSchedule = (quota: Quota, indices: MonthlyIndex[] = []): PaymentInstallment[] => {
  const schedule: PaymentInstallment[] = [];
  if (!quota || !quota.firstDueDate) return [];

  const firstDueDate = createLocalDate(quota.firstDueDate);
  const adhesionDateAnchor = createLocalDate(quota.adhesionDate || quota.firstDueDate);
  adhesionDateAnchor.setDate(1); 
  adhesionDateAnchor.setHours(0,0,0,0);

  const termMonths = Number(quota.termMonths) || 1;
  const originalCredit = Number(quota.creditValue) || 1;
  const adminFeeRateTotal = Number(quota.adminFeeRate) || 0;
  const reserveFundRateTotal = Number(quota.reserveFundRate) || 0;
  const dueDay = quota.dueDay || 25;

  let currentCreditValue = originalCredit;

  let remainingPctFC = 100.0;
  let remainingPctTA = adminFeeRateTotal;
  let remainingPctFR = reserveFundRateTotal;

  let bidProcessed = false;
  const today = new Date(); today.setHours(23, 59, 59, 999);

  for (let i = 1; i <= termMonths; i++) {
    let currentDate: Date;
    if (i === 1) {
      currentDate = new Date(firstDueDate);
    } else {
      const tempDate = addMonths(firstDueDate, i - 1);
      currentDate = new Date(tempDate.getFullYear(), tempDate.getMonth(), dueDay);
    }

    const finalDueDate = getNextBusinessDay(currentDate);
    const dueDateStr = finalDueDate.toISOString();
    const monthsLeft = termMonths - i + 1;

    let bidAmountApplied = 0; 
    let bidDateApplied: string | undefined = undefined;
    let bidEmbeddedApplied = 0, bidEmbeddedPercent = 0, bidEmbeddedAbatementFC = 0, bidEmbeddedPercentFC = 0, bidEmbeddedAbatementFR = 0, bidEmbeddedPercentFR = 0, bidEmbeddedAbatementTA = 0, bidEmbeddedPercentTA = 0;
    let bidFreeApplied = 0, bidFreePercent = 0, bidFreeAbatementFC = 0, bidFreePercentFC = 0, bidFreeAbatementFR = 0, bidFreePercentFR = 0, bidFreeAbatementTA = 0, bidFreePercentTA = 0;

    let correctionApplied = false;
    let correctionFactor = 0;
    let correctionIndexName: string | undefined = undefined;

    if (i > 1 && (i - 1) % 12 === 0) {
        const indexMonthDate = addMonths(adhesionDateAnchor, i - 2);
        const indexLookupStr = indexMonthDate.toISOString().split('T')[0];

        if (indexMonthDate <= today) {
            const monthlyIndex = indices.find(idx => idx.type === quota.correctionIndex && idx.date === indexLookupStr);

            if (monthlyIndex && monthlyIndex.rate > 0) {
                correctionApplied = true;
                correctionFactor = monthlyIndex.rate / 100;
                correctionIndexName = quota.correctionIndex;
                currentCreditValue *= (1 + correctionFactor);
            }
        }
    }

    if (quota.isContemplated && quota.contemplationDate && !bidProcessed) {
        const bidDate = createLocalDate(quota.contemplationDate);
        if (bidDate <= finalDueDate) {
             bidProcessed = true;
             bidDateApplied = quota.contemplationDate;
             bidAmountApplied = quota.bidTotal || 0;

             const distributeBid = (amount: number) => {
                 const totalRemainingPct = remainingPctFC + remainingPctTA + remainingPctFR;
                 const weightFC = remainingPctFC / totalRemainingPct;
                 const weightTA = remainingPctTA / totalRemainingPct;
                 const weightFR = remainingPctFR / totalRemainingPct;

                 const mFC = parseFloat((amount * weightFC).toFixed(2));
                 const mTA = parseFloat((amount * weightTA).toFixed(2));
                 const mFR = parseFloat((amount - mFC - mTA).toFixed(2));

                 const pFC = (mFC / originalCredit) * 100;
                 const pTA = (mTA / originalCredit) * 100;
                 const pFR = (mFR / originalCredit) * 100;
                 const pTotal = (amount / originalCredit) * 100;

                 remainingPctFC -= pFC;
                 remainingPctTA -= pTA;
                 remainingPctFR -= pFR;

                 return { mFC, mTA, mFR, pFC, pTA, pFR, pTotal };
             };

             if (quota.bidEmbedded && quota.bidEmbedded > 0) {
                 bidEmbeddedApplied = quota.bidEmbedded;
                 const res = distributeBid(bidEmbeddedApplied);
                 bidEmbeddedAbatementFC = res.mFC; bidEmbeddedAbatementTA = res.mTA; bidEmbeddedAbatementFR = res.mFR;
                 bidEmbeddedPercent = res.pTotal; bidEmbeddedPercentFC = res.pFC; bidEmbeddedPercentTA = res.pTA; bidEmbeddedPercentFR = res.pFR;
             }
             if (quota.bidFree && quota.bidFree > 0) {
                 bidFreeApplied = quota.bidFree;
                 const res = distributeBid(bidFreeApplied);
                 bidFreeAbatementFC = res.mFC; bidFreeAbatementTA = res.mTA; bidFreeAbatementFR = res.mFR;
                 bidFreePercent = res.pTotal; bidFreePercentFC = res.pFC; bidFreePercentTA = res.pTA; bidFreePercentFR = res.pFR;
             }
        }
    }

    let monthlyRateFC = 0, monthlyRateTA = 0, monthlyRateFR = 0;

    let isReducedPeriod = false;
    if (quota.paymentPlan === PaymentPlanType.REDUZIDA) {
        const halfTerm = Math.ceil(termMonths / 2);
        const isNotContemplatedYet = !quota.isContemplated || (quota.contemplationDate && createLocalDate(quota.contemplationDate) > finalDueDate);
        isReducedPeriod = i <= halfTerm && isNotContemplatedYet;
    }

    if (i === termMonths) {
        monthlyRateFC = remainingPctFC;
        monthlyRateTA = remainingPctTA;
        monthlyRateFR = remainingPctFR;
    } else if (isReducedPeriod) {
        monthlyRateFC = parseFloat(((100 / termMonths) * 0.5).toFixed(4));
        monthlyRateTA = parseFloat((adminFeeRateTotal / termMonths).toFixed(4));
        monthlyRateFR = parseFloat((reserveFundRateTotal / termMonths).toFixed(4));
    } else {
        monthlyRateFC = parseFloat((remainingPctFC / monthsLeft).toFixed(4));
        monthlyRateTA = parseFloat((remainingPctTA / monthsLeft).toFixed(4));
        monthlyRateFR = parseFloat((remainingPctFR / monthsLeft).toFixed(4));
    }

    const installmentFC = parseFloat(((monthlyRateFC / 100) * currentCreditValue).toFixed(2));
    const installmentTA = parseFloat(((monthlyRateTA / 100) * currentCreditValue).toFixed(2));
    const installmentFR = parseFloat(((monthlyRateFR / 100) * currentCreditValue).toFixed(2));

    remainingPctFC -= monthlyRateFC;
    remainingPctTA -= monthlyRateTA;
    remainingPctFR -= monthlyRateFR;

    const totalInstallment = installmentFC + installmentTA + installmentFR;

    schedule.push({
      installmentNumber: i, dueDate: dueDateStr, commonFund: installmentFC, monthlyRateFC, reserveFund: installmentFR, monthlyRateFR, adminFee: installmentTA, monthlyRateTA, totalInstallment,
      balanceFC: (remainingPctFC / 100) * currentCreditValue, 
      balanceFR: (remainingPctFR / 100) * currentCreditValue, 
      balanceTA: (remainingPctTA / 100) * currentCreditValue, 
      balanceTotal: ((remainingPctFC + remainingPctTA + remainingPctFR) / 100) * currentCreditValue,
      percentBalanceFC: Math.max(0, remainingPctFC), 
      percentBalanceFR: Math.max(0, remainingPctFR), 
      percentBalanceTA: Math.max(0, remainingPctTA), 
      percentBalanceTotal: Math.max(0, remainingPctFC + remainingPctTA + remainingPctFR),
      bidAmountApplied, bidDate: bidDateApplied,
      bidEmbeddedApplied, bidEmbeddedPercent, bidEmbeddedAbatementFC, bidEmbeddedPercentFC, bidEmbeddedAbatementFR, bidEmbeddedPercentFR, bidEmbeddedAbatementTA, bidEmbeddedPercentTA,
      bidFreeApplied, bidFreePercent, bidFreeAbatementFC, bidFreePercentFC, bidFreeAbatementFR, bidFreePercentFR, bidFreeAbatementTA, bidFreePercentTA,
      bidAbatementFC: bidEmbeddedAbatementFC + bidFreeAbatementFC, bidAbatementFR: bidEmbeddedAbatementFR + bidFreeAbatementFR, bidAbatementTA: bidEmbeddedAbatementTA + bidFreeAbatementTA,
      correctionApplied, correctionFactor, correctedCreditValue: currentCreditValue, correctionIndexName,
      realAmountPaid: null, isPaid: false
    });
  }
  return schedule;
};

import React, { useEffect, useState, useMemo } from 'react';
import { useConsortium } from '../store/ConsortiumContext';
import { generateSchedule, calculateCDICorrection, calculateCurrentCreditValue } from '../services/calculationService';
import { db } from '../services/database';
import { FileBarChart, Loader, AlertTriangle, Filter, CheckCircle2, Clock, Sheet, Calendar, ArrowUpDown, ArrowUp, ArrowDown, DollarSign } from 'lucide-react';

interface ReportRow {
  id: string;
  group: string;
  quotaNumber: string;
  creditValue: number;
  isContemplated: boolean;
  administratorId?: string;
  companyId?: string;

  saldoAVencer: number; 
  percentAVencer: number;
  saldoVencido: number; 
  percentVencido: number;

  bidTotal: number;
  percentBidTotal: number;
  bidFree: number;
  bidEmbedded: number;

  creditAtContemplation: number; 
  valorRealCarta: number; 
  creditManualAdjustment: number;
  creditoTotal: number;
  bidFreeCorrection: number;
  creditoUtilizado: number;
  saldoDisponivel: number;
}

const Reports = () => {
  const { quotas, indices, updateQuota, administrators, companies, allCreditUsages } = useConsortium();
  const [reportData, setReportData] = useState<ReportRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<{ id: string, field: 'credit' } | null>(null);
  const [editValue, setEditValue] = useState('');
  const [saveError, setSaveError] = useState<string | null>(null);

  const [filterAdmin, setFilterAdmin] = useState('');
  const [filterCompany, setFilterCompany] = useState('');
  const [filterStatus, setFilterStatus] = useState(''); 
  const [referenceDate, setReferenceDate] = useState(new Date().toISOString().split('T')[0]);
  const [sortConfig, setSortConfig] = useState<{ key: keyof ReportRow, direction: 'asc' | 'desc' } | null>(null);

  const formatNumber = (val: number) => val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  useEffect(() => {
    const buildReport = async () => {
      setLoading(true);
      const refDateStr = referenceDate;
      const refDate = new Date(refDateStr + 'T23:59:59');

      try {
        const allPayments = await db.getAllPaymentsDictionary();
        const rows = quotas.map(quota => {
          const schedule = generateSchedule(quota, indices);

          // Valor da Carta (Vlr Carta): Valor atualizado do grupo até a data de referência (pode mudar mensalmente)
          let vlrCartaAtual = quota.creditValue;
          if (schedule.length > 0) {
             const pastOrPresent = schedule.filter(i => i.dueDate.split('T')[0] <= refDateStr);
             vlrCartaAtual = pastOrPresent.length > 0 ? pastOrPresent[pastOrPresent.length - 1].correctedCreditValue || quota.creditValue : quota.creditValue;
          }

          let sumVencido = 0;
          let sumAVencer = 0;
          const paymentMap = allPayments[quota.id] || {};

          schedule.forEach(inst => {
              const instDateStr = inst.dueDate.split('T')[0];
              const isMatured = instDateStr <= refDateStr;
              const paymentData = paymentMap[inst.installmentNumber];

              if (isMatured) {
                  const fine = paymentData?.manualFine || inst.manualFine || 0;
                  const interest = paymentData?.manualInterest || inst.manualInterest || 0;
                  sumVencido += inst.commonFund + inst.reserveFund + inst.adminFee + fine + interest;
              } else {
                  sumAVencer += inst.commonFund + inst.reserveFund + inst.adminFee;
              }

              if (inst.bidAmountApplied && inst.bidAmountApplied > 0) {
                  sumVencido += (inst.bidAbatementFC || 0) + (inst.bidAbatementFR || 0) + (inst.bidAbatementTA || 0);
              }
          });

          const totalContractValue = sumVencido + sumAVencer || 1;
          const correction92CDI = calculateCDICorrection(quota.bidFree || 0, quota.contemplationDate, indices);

          // REGRA DE BALIZAMENTO DO CRÉDITO: 
          // Se contemplada, o valor do crédito trava nos reajustes acumulados até a data da contemplação.
          // Ex: Contemplada no 12º mês = 80.000 (sem reajuste). No 14º mês = 80.000 * (1 + índice).
          const creditAtContemplation = calculateCurrentCreditValue(quota, indices, refDate);

          const bidEmbedded = quota.bidEmbedded || 0;
          const valorLiquido = creditAtContemplation - bidEmbedded;
          const creditoTotal = valorLiquido + (quota.creditManualAdjustment || 0);

          const quotaUsages = allCreditUsages.filter(u => u.quotaId === quota.id && u.date <= refDateStr);
          const creditoUtilizado = quotaUsages.reduce((sum, u) => sum + u.amount, 0);

          return {
            id: quota.id,
            group: quota.group,
            quotaNumber: quota.quotaNumber,
            creditValue: vlrCartaAtual, // Coluna Vlr Carta mostra o valor "de prateleira" no mês
            isContemplated: quota.isContemplated,
            administratorId: quota.administratorId,
            companyId: quota.companyId,
            saldoAVencer: sumAVencer,
            percentAVencer: (sumAVencer / totalContractValue) * 100,
            saldoVencido: sumVencido,
            percentVencido: (sumVencido / totalContractValue) * 100,
            bidTotal: quota.bidTotal || 0,
            percentBidTotal: vlrCartaAtual > 0 ? ((quota.bidTotal || 0) / vlrCartaAtual) * 100 : 0,
            bidFree: quota.bidFree || 0,
            bidEmbedded: bidEmbedded,
            creditAtContemplation: creditAtContemplation, // Coluna Crédito mostra o valor balizado
            valorRealCarta: valorLiquido,
            creditManualAdjustment: quota.creditManualAdjustment || 0,
            creditoTotal: creditoTotal,
            bidFreeCorrection: correction92CDI,
            creditoUtilizado,
            saldoDisponivel: creditoTotal - creditoUtilizado
          };
        });
        setReportData(rows);
      } catch (err) { console.error(err); } finally { setLoading(false); }
    };
    buildReport();
  }, [quotas, indices, allCreditUsages, referenceDate]);

  const handleSaveEdit = async () => {
    if (!editingId) return;
    const normalizedValue = editValue.replace(/\./g, '').replace(',', '.');
    const newVal = parseFloat(normalizedValue);
    if (isNaN(newVal)) { setEditingId(null); return; }
    const quota = quotas.find(q => q.id === editingId.id);
    if (quota) {
      try {
        await updateQuota({ ...quota, creditManualAdjustment: newVal });
        setEditingId(null);
      } catch (error) { setSaveError("Erro ao salvar."); }
    }
  };

  const filteredData = reportData.filter(row => {
    const matchAdmin = !filterAdmin || row.administratorId === filterAdmin;
    const matchComp = !filterCompany || row.companyId === filterCompany;
    let matchStatus = true;
    if (filterStatus === 'CONTEMPLATED') matchStatus = row.isContemplated;
    else if (filterStatus === 'ACTIVE') matchStatus = !row.isContemplated;
    return matchAdmin && matchComp && matchStatus;
  });

  const sortedData = useMemo(() => {
    let items = [...filteredData];
    if (sortConfig) {
      items.sort((a, b) => {
        if (sortConfig.key === 'quotaNumber') {
          return sortConfig.direction === 'asc' ? (parseInt(a.quotaNumber) - parseInt(b.quotaNumber)) : (parseInt(b.quotaNumber) - parseInt(a.quotaNumber));
        }
        return sortConfig.direction === 'asc' ? (a[sortConfig.key] > b[sortConfig.key] ? 1 : -1) : (a[sortConfig.key] < b[sortConfig.key] ? 1 : -1);
      });
    }
    return items;
  }, [filteredData, sortConfig]);

  const totals = sortedData.reduce((acc, row) => ({
    saldoAVencer: acc.saldoAVencer + row.saldoAVencer,
    saldoVencido: acc.saldoVencido + row.saldoVencido,
    bidTotal: acc.bidTotal + row.bidTotal,
    bidEmbedded: acc.bidEmbedded + row.bidEmbedded,
    creditAtContemplation: acc.creditAtContemplation + row.creditAtContemplation,
    valorRealCarta: acc.valorRealCarta + row.valorRealCarta,
    creditoTotal: acc.creditoTotal + row.creditoTotal,
    creditoUtilizado: acc.creditoUtilizado + row.creditoUtilizado,
    saldoDisponivel: acc.saldoDisponivel + row.saldoDisponivel
  }), { saldoAVencer: 0, saldoVencido: 0, bidTotal: 0, bidEmbedded: 0, creditAtContemplation: 0, valorRealCarta: 0, creditoTotal: 0, creditoUtilizado: 0, saldoDisponivel: 0 });

  const SortHeader = ({ label, sortKey, align = 'right', className = '' }: { label: string, sortKey: keyof ReportRow, align?: 'left'|'right', className?: string }) => (
      <th className={`px-2 py-3 cursor-pointer hover:bg-slate-800 transition-colors group select-none ${className} ${align === 'right' ? 'text-right' : 'text-left'}`} onClick={() => setSortConfig({ key: sortKey, direction: sortConfig?.key === sortKey && sortConfig.direction === 'asc' ? 'desc' : 'asc' })}>
        <div className={`flex items-center gap-1 ${align === 'right' ? 'justify-end' : 'justify-start'}`}>{label} <ArrowUpDown size={10} className="opacity-30 group-hover:opacity-100" /></div>
      </th>
  );

  return (
    <div className="space-y-6 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Relatório por Cota</h1>
           <p className="text-slate-500">Acompanhamento de saldos, lances e créditos disponíveis.</p>
        </div>
        <button onClick={() => window.print()} className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 font-medium print:hidden">Imprimir Relatório</button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-4 print:hidden">
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Data Fechamento</label><input type="date" value={referenceDate} onChange={(e) => setReferenceDate(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none" /></div>
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Empresa</label><select value={filterCompany} onChange={(e) => setFilterCompany(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none">{companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}<option value="">Todas</option></select></div>
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Administradora</label><select value={filterAdmin} onChange={(e) => setFilterAdmin(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none">{administrators.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}<option value="">Todas</option></select></div>
          <div><label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Status</label><select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm outline-none"><option value="">Todas</option><option value="CONTEMPLATED">Contempladas</option><option value="ACTIVE">Em Andamento</option></select></div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-3">
          {[
              { label: 'Saldo Vencido', value: totals.saldoVencido, color: 'text-emerald-700', bg: 'bg-emerald-50' },
              { label: 'Saldo A Vencer', value: totals.saldoAVencer, color: 'text-red-700', bg: 'bg-red-50' },
              { label: 'Total Lances', value: totals.bidTotal, color: 'text-amber-700', bg: 'bg-amber-50' },
              { label: 'Crédito Contemp.', value: totals.creditAtContemplation, color: 'text-slate-600', bg: 'bg-slate-50' },
              { label: 'Vlr Carta Líq.', value: totals.valorRealCarta, color: 'text-blue-700', bg: 'bg-blue-50' },
              { label: 'Crédito Total', value: totals.creditoTotal, color: 'text-slate-800', bg: 'bg-slate-100' },
              { label: 'Utilizado', value: totals.creditoUtilizado, color: 'text-orange-700', bg: 'bg-orange-50' },
              { label: 'Disponível', value: totals.saldoDisponivel, color: 'text-emerald-800', bg: 'bg-emerald-100 border-emerald-200' },
          ].map((t, i) => (
              <div key={i} className={`${t.bg} border border-slate-200/60 p-3 rounded-lg shadow-sm`}>
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">{t.label}</p>
                  <p className={`text-sm font-black ${t.color}`}>{formatNumber(t.value)}</p>
              </div>
          ))}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-[10px] text-left border-collapse">
              <thead className="bg-slate-800 text-white uppercase tracking-tighter">
                <tr>
                  <SortHeader label="Cota" sortKey="quotaNumber" align="left" className="sticky left-0 bg-slate-800 z-10 border-r border-slate-700" />
                  <SortHeader label="Vlr Carta" sortKey="creditValue" />
                  <SortHeader label="S. Vencido" sortKey="saldoVencido" className="bg-emerald-900/30" />
                  <SortHeader label="S. A Vencer" sortKey="saldoAVencer" className="bg-red-900/30" />
                  <SortHeader label="Lance Tot." sortKey="bidTotal" className="bg-amber-900/30" />
                  <SortHeader label="Crédito" sortKey="creditAtContemplation" className="bg-slate-700" />
                  <SortHeader label="Lance Emb." sortKey="bidEmbedded" />
                  <SortHeader label="Vlr Líquido" sortKey="valorRealCarta" className="font-bold" />
                  <SortHeader label="Ajuste" sortKey="creditManualAdjustment" />
                  <SortHeader label="92% CDI" sortKey="bidFreeCorrection" />
                  <SortHeader label="Créd. Total" sortKey="creditoTotal" className="bg-slate-700 font-bold" />
                  <SortHeader label="Utilizado" sortKey="creditoUtilizado" />
                  <SortHeader label="Saldo Disp." sortKey="saldoDisponivel" className="bg-emerald-900 border-l border-emerald-700 font-bold" />
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {loading ? (<tr><td colSpan={13} className="p-10 text-center"><Loader className="animate-spin mx-auto mb-2" /> Carregando dados...</td></tr>) : 
                 sortedData.map(row => (
                  <tr key={row.id} className="hover:bg-slate-50">
                    <td className="p-2 font-bold text-slate-700 sticky left-0 bg-white border-r border-slate-100 shadow-sm">{row.group}/{row.quotaNumber}</td>
                    <td className="p-2 text-right">{formatNumber(row.creditValue)}</td>
                    <td className="p-2 text-right font-medium text-emerald-700 bg-emerald-50/30">{formatNumber(row.saldoVencido)}</td>
                    <td className="p-2 text-right font-medium text-red-600 bg-red-50/30">{formatNumber(row.saldoAVencer)}</td>
                    <td className="p-2 text-right font-medium text-amber-600 bg-amber-50/30">{formatNumber(row.bidTotal)}</td>
                    <td className="p-2 text-right font-bold bg-slate-50/80">{formatNumber(row.creditAtContemplation)}</td>
                    <td className="p-2 text-right text-orange-600">{formatNumber(row.bidEmbedded)}</td>
                    <td className="p-2 text-right font-bold text-blue-700 bg-blue-50/30">{formatNumber(row.valorRealCarta)}</td>
                    <td className="p-2 text-right text-blue-600 cursor-pointer" onClick={() => { setEditingId({id: row.id, field: 'credit'}); setEditValue(row.creditManualAdjustment.toString().replace('.',',')); }}>{formatNumber(row.creditManualAdjustment)}</td>
                    <td className="p-2 text-right text-violet-600">{formatNumber(row.bidFreeCorrection)}</td>
                    <td className="p-2 text-right font-bold bg-slate-50">{formatNumber(row.creditoTotal)}</td>
                    <td className="p-2 text-right text-amber-700">{formatNumber(row.creditoUtilizado)}</td>
                    <td className="p-2 text-right font-bold text-emerald-800 bg-emerald-50 border-l border-emerald-100">{formatNumber(row.saldoDisponivel)}</td>
                  </tr>
                ))}
              </tbody>
              <tfoot className="bg-slate-900 text-white font-bold text-[9px] uppercase">
                  <tr>
