      alert(error.message || "Erro ao salvar. Verifique a conexão.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleGoToSimulation = () => {
      if (id && formData.group) {
          handleSaveAndContinue();
      }
  };

  const handleSaveAndContinue = async () => {
      const quotaData: Quota = {
